-- ════════════════════════════════════════════════════════════════════
-- Book of Complete Prayer — one-shot import.
-- Adds a `section` column for in-list grouping headers, inserts the
-- new 'book_of_prayer' category, then bulk-loads 263 duas.
-- ════════════════════════════════════════════════════════════════════

-- 1) Schema: add the section column (idempotent).
ALTER TABLE azkar_items
  ADD COLUMN IF NOT EXISTS section TEXT;

-- 2) New category row. icon stays a generic book emoji until you pick one.
INSERT INTO azkar_categories (id, label, icon_name, sort_order, is_visible)
VALUES ('book_of_prayer', 'The Book of Complete Prayer', 'book', 99, true)
ON CONFLICT (id) DO UPDATE SET label = EXCLUDED.label;

-- 3) Wipe any prior import of this category so re-runs are clean.
DELETE FROM azkar_items WHERE category_id = 'book_of_prayer';

-- 4) Bulk insert all 263 duas.
INSERT INTO azkar_items
  (id, category_id, title, arabic, transliteration, translation,
   recommended_count, reward, reference, section, sort_order)
VALUES
  ('bocp_001', 'book_of_prayer', '', 'رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ', 'Rabbanā ātinā fi''d-dunyā ḥasanatan wa fi''l-ākhirati ḥasanatan wa qinā ʿadhāba''n-nār', '“Our Lord! Grant us the good of this world and the Hereafter, and protect us from the torment of the Fire”', 1, '', '', 'Supplications from al-Baqarah', 1),
  ('bocp_002', 'book_of_prayer', '', 'رَبَّنَا أَفْرِغْ عَلَيْنَا صَبْرًا وَثَبِّتْ أَقْدَامَنَا وَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِينَ', 'Rabbanā afrigh ʿalaynā ṣabran wa thabbit aqdāmanā wa''nṣurnā ʿala''l-qawmi''l-kāfirīn', '“Our Lord! Shower us with perseverance, make our steps firm, and give us victory over the disbelieving people”', 1, '', '', 'Supplications from al-Baqarah', 2),
  ('bocp_003', 'book_of_prayer', '', 'رَبَّنَا لَا تُؤَاخِذْنَا إِنْ نَسِينَا أَوْ أَخْطَأْنَا، رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَا إِصْرًا كَمَا حَمَلْتَهُ عَلَى الَّذِينَ مِنْ قَبْلِنَا، رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِ، وَاعْفُ عَنَّا وَاغْفِرْ لَنَا وَارْحَمْنَا، أَنْتَ مَوْلَانَا فَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِينَ', 'Rabbanā lā tuʾākhidhnā in nasīnā aw akhṭaʾnā, rabbanā wa lā taḥmil ʿalaynā iṣran kamā ḥamaltahu ʿala''l-ladhīna min qablinā, rabbanā wa lā tuḥammilnā mā lā ṭāqata lanā bih, wa''fu ʿannā wa''ghfir lanā wa''rḥamnā, anta mawlānā fa''nṣurnā ʿala''l-qawmi''l-kāfirīn', '“Our Lord! Do not punish us if we forget or make a mistake. Our Lord! Do not place a burden on us like the one you placed on those before us. Our Lord! Do not burden us with what we cannot bear. Pardon us, forgive us, and have mercy on us. You are our ˹only˺ Guardian. So grant us victory over the disbelieving people”', 1, '', '', 'Supplications from al-Baqarah', 3),
  ('bocp_004', 'book_of_prayer', '', 'رَبَّنَا لَا تُزِغْ قُلُوبَنَا بَعْدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِنْ لَدُنْكَ رَحْمَةً إِنَّكَ أَنْتَ الْوَهَّابُ', 'Rabbanā lā tuzigh qulūbanā baʿda idh hadaytanā wa hab lanā min ladunka raḥmah, innaka anta''l-wahhāb', '“Our Lord! Do not let our hearts deviate after you have guided us. Grant us Your mercy. You are indeed the Giver ˹of all bounties˺”', 1, '', '', 'Supplications from Aal ''Imran', 4),
  ('bocp_005', 'book_of_prayer', '', 'رَبَّنَا إِنَّنَا آمَنَّا فَاغْفِرْ لَنَا ذُنُوبَنَا وَقِنَا عَذَابَ النَّارِ', 'Rabbanā innanā āmannā fa''ghfir lanā dhunūbanā wa qinā ʿadhāba''n-nār', '“Our Lord! We have believed, so forgive our sins and protect us from the torment of the Fire”', 1, '', '', 'Supplications from Aal ''Imran', 5),
  ('bocp_006', 'book_of_prayer', '', 'اللَّهُمَّ مَالِكَ الْمُلْكِ تُؤْتِي الْمُلْكَ مَنْ تَشَاءُ وَتَنْزِعُ الْمُلْكَ مِمَّنْ تَشَاءُ وَتُعِزُّ مَنْ تَشَاءُ وَتُذِلُّ مَنْ تَشَاءُ بِيَدِكَ الْخَيْرُ إِنَّكَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ', 'Allāhumma mālika''l-mulki tu''ti''l-mulka man tashāʾu wa tanziʿu''l-mulka mimman tashāʾu wa tuʿizzu man tashāʾu wa tudhillu man tashāʾu, bi-yadika''l-khayr, innaka ʿalā kulli shayʾin qadīr', '“O Allah! Lord over all authorities! You give authority to whoever You please and remove it from who You please; You honour whoever You please and disgrace who You please—all good is in Your Hands. Surely You ˹alone˺ are Most Capable of everything”', 1, '', '', 'Supplications from Aal ''Imran', 6),
  ('bocp_007', 'book_of_prayer', '', 'رَبِّ هَبْ لِي مِنْ لَدُنْكَ ذُرِّيَّةً طَيِّبَةً إِنَّكَ سَمِيعُ الدُّعَاءِ', 'Rabbi hab lī min ladunka dhurriyyatan ṭayyibah, innaka samīʿu''d-duʿāʾ', '“My Lord! Grant me—by your grace—righteous offspring. You are certainly the Hearer of ˹all˺ prayers”', 1, '', '', 'Supplications from Aal ''Imran', 7),
  ('bocp_008', 'book_of_prayer', '', 'رَبَّنَا آمَنَّا بِمَا أَنْزَلْتَ وَاتَّبَعْنَا الرَّسُولَ فَاكْتُبْنَا مَعَ الشَّاهِدِينَ', 'Rabbanā āmannā bimā anzalta wa''ttabaʿna''r-rasūla fa''ktubnā maʿa''sh-shāhidīn', '“Our Lord! We believe in Your revelations and follow the messenger, so count us among those who bear witness”', 1, '', '', 'Supplications from Aal ''Imran', 8),
  ('bocp_009', 'book_of_prayer', '', 'رَبَّنَا اغْفِرْ لَنَا ذُنُوبَنَا وَإِسْرَافَنَا فِي أَمْرِنَا وَثَبِّتْ أَقْدَامَنَا وَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِينَ', 'Rabbana''ghfir lanā dhunūbanā wa isrāfanā fī amrinā wa thabbit aqdāmanā wa''nṣurnā ʿala''l-qawmi''l-kāfirīn', '“Our Lord! Forgive our sins and excesses, make our steps firm, and grant us victory over the disbelieving people”', 1, '', '', 'Supplications from Aal ''Imran', 9),
  ('bocp_010', 'book_of_prayer', '', 'رَبَّنَا مَا خَلَقْتَ هَٰذَا بَاطِلًا سُبْحَانَكَ فَقِنَا عَذَابَ النَّارِ، رَبَّنَا إِنَّكَ مَنْ تُدْخِلِ النَّارَ فَقَدْ أَخْزَيْتَهُ وَمَا لِلظَّالِمِينَ مِنْ أَنْصَارٍ، رَبَّنَا إِنَّنَا سَمِعْنَا مُنَادِيًا يُنَادِي لِلْإِيمَانِ أَنْ آمِنُوا بِرَبِّكُمْ فَآمَنَّا، رَبَّنَا فَاغْفِرْ لَنَا ذُنُوبَنَا وَكَفِّرْ عَنَّا سَيِّئَاتِنَا وَتَوَفَّنَا مَعَ الْأَبْرَارِ، رَبَّنَا وَآتِنَا مَا وَعَدْتَنَا عَلَى رُسُلِكَ وَلَا تُخْزِنَا يَوْمَ الْقِيَامَةِ إِنَّكَ لَا تُخْلِفُ الْمِيعَادَ', 'Rabbanā mā khalaqta hādhā bāṭilan subḥānaka faqinā ʿadhāba''n-nār. Rabbanā innaka man tudkhili''n-nāra faqad akhzaytah, wa mā li''ẓ-ẓālimīna min anṣār. Rabbanā innanā samiʿnā munādiyan yunādī li''l-īmāni an āminū bi-rabbikum fa-āmannā, rabbanā fa''ghfir lanā dhunūbanā wa kaffir ʿannā sayyiʾātinā wa tawaffanā maʿa''l-abrār. Rabbanā wa ātinā mā waʿadtanā ʿalā rusulika wa lā tukhzinā yawma''l-qiyāmah, innaka lā tukhlifu''l-mīʿād', '“Our Lord! You have not created ˹all of˺ this without purpose. Glory be to You! Protect us from the torment of the Fire.Our Lord! Indeed, those You commit to the Fire will be ˹completely˺ disgraced! And the wrongdoers will have no helpers.Our Lord! We have heard the caller to ˹true˺ belief, ˹proclaiming,˺ ‘Believe in your Lord ˹alone˺,’ so we believed. Our Lord! Forgive our sins, absolve us of our misdeeds, and join us with the virtuous when we die‎.Our Lord! Grant us what You have promised us through Your messengers and do not put us to shame on Judgment Day—for certainly You never fail in Your promise”', 1, '', '', 'Supplications from Aal ''Imran', 10),
  ('bocp_011', 'book_of_prayer', '', 'رَبَّنَا آمَنَّا فَاكْتُبْنَا مَعَ الشَّاهِدِينَ', 'Rabbanā āmannā fa''ktubnā maʿa''sh-shāhidīn', '“Our Lord! We believe, so count us among the witnesses”', 1, '', '', 'Supplications from al-Ma''idah', 11),
  ('bocp_012', 'book_of_prayer', '', 'رَبَّنَا ظَلَمْنَا أَنْفُسَنَا وَإِنْ لَمْ تَغْفِرْ لَنَا وَتَرْحَمْنَا لَنَكُونَنَّ مِنَ الْخَاسِرِينَ', 'Rabbanā ẓalamnā anfusanā wa in lam taghfir lanā wa tarḥamnā lanakūnanna mina''l-khāsirīn', '“Our Lord! We have wronged ourselves. If You do not forgive us and have mercy on us, we will certainly be losers”', 1, '', '', 'Supplications from al-A''raf', 12),
  ('bocp_013', 'book_of_prayer', '', 'رَبَّنَا لَا تَجْعَلْنَا مَعَ الْقَوْمِ الظَّالِمِينَ', 'Rabbanā lā tajʿalnā maʿa''l-qawmi''ẓ-ẓālimīn', '“Our Lord! Do not join us with the wrongdoing people”', 1, '', '', 'Supplications from al-A''raf', 13),
  ('bocp_014', 'book_of_prayer', '', 'رَبَّنَا لَا تَجْعَلْنَا فِتْنَةً لِلْقَوْمِ الظَّالِمِينَ', 'Rabbanā lā tajʿalnā fitnatan li''l-qawmi''ẓ-ẓālimīn', '“Our Lord! Do not subject us to the persecution of the oppressive people”', 1, '', '', 'Supplications from Yunus', 14),
  ('bocp_015', 'book_of_prayer', '', 'رَبِّ إِنِّي أَعُوذُ بِكَ أَنْ أَسْأَلَكَ مَا لَيْسَ لِي بِهِ عِلْمٌ وَإِلَّا تَغْفِرْ لِي وَتَرْحَمْنِي أَكُنْ مِنَ الْخَاسِرِينَ', 'Rabbi innī aʿūdhu bika an asʾalaka mā laysa lī bihi ʿilm, wa illā taghfir lī wa tarḥamnī akun mina''l-khāsirīn', '“My Lord, I seek refuge in You from asking You about what I have no knowledge of, and unless You forgive me and have mercy on me, I will be one of the losers”', 1, '', '', 'Supplications from Hud', 15),
  ('bocp_016', 'book_of_prayer', '', 'رَبِّ اجْعَلْ هَٰذَا الْبَلَدَ آمِنًا وَاجْنُبْنِي وَبَنِيَّ أَنْ نَعْبُدَ الْأَصْنَامَ', 'Rabbi''jʿal hādha''l-balada āminan wa''jnubnī wa baniyya an naʿbuda''l-aṣnām', '“My Lord! Make this city ˹of Mecca˺ secure, and keep me and my children away from the worship of idols”', 1, '', '', 'Supplications from Ibrahim', 16),
  ('bocp_017', 'book_of_prayer', '', 'رَبِّ اجْعَلْنِي مُقِيمَ الصَّلَاةِ وَمِنْ ذُرِّيَّتِي رَبَّنَا وَتَقَبَّلْ دُعَاءِ', 'Rabbi''jʿalnī muqīma''ṣ-ṣalāti wa min dhurriyyatī, rabbanā wa taqabbal duʿāʾ', '“My Lord! Make me and those ˹believers˺ of my descendants keep up prayer. Our Lord! Accept my prayers”', 1, '', '', 'Supplications from Ibrahim', 17),
  ('bocp_018', 'book_of_prayer', '', 'رَبَّنَا اغْفِرْ لِي وَلِوَالِدَيَّ وَلِلْمُؤْمِنِينَ يَوْمَ يَقُومُ الْحِسَابُ', 'Rabbana''ghfir lī wa li-wālidayya wa li''l-muʾminīna yawma yaqūmu''l-ḥisāb', '“Our Lord! Forgive me, my parents, and the believers on the Day when the judgment will come to pass”', 1, '', '', 'Supplications from Ibrahim', 18),
  ('bocp_019', 'book_of_prayer', '', 'رَبِّ ارْحَمْهُمَا كَمَا رَبَّيَانِي صَغِيرًا', 'Rabbi''rḥamhumā kamā rabbayānī ṣaghīrā', '“My Lord! Be merciful to them as they raised me when I was young”', 1, '', '', 'Supplications from al-Isra', 19),
  ('bocp_020', 'book_of_prayer', '', 'رَبِّ أَدْخِلْنِي مُدْخَلَ صِدْقٍ وَأَخْرِجْنِي مُخْرَجَ صِدْقٍ وَاجْعَلْ لِي مِنْ لَدُنْكَ سُلْطَانًا نَصِيرًا', 'Rabbi adkhilnī mudkhala ṣidqin wa akhrijnī mukhraja ṣidqin wa''jʿal lī min ladunka sulṭānan naṣīrā', '“My Lord! Grant me an honourable entrance and an honourable exit and give me a supporting authority from Yourself”', 1, '', '', 'Supplications from al-Isra', 20),
  ('bocp_021', 'book_of_prayer', '', 'رَبَّنَا آتِنَا مِنْ لَدُنْكَ رَحْمَةً وَهَيِّئْ لَنَا مِنْ أَمْرِنَا رَشَدًا', 'Rabbanā ātinā min ladunka raḥmatan wa hayyiʾ lanā min amrinā rashadā', '“Our Lord! Grant us mercy from Yourself and guide us rightly through our ordeal”', 1, '', '', 'Supplications from al-Kahf', 21),
  ('bocp_022', 'book_of_prayer', '', 'رَبِّ زِدْنِي عِلْمًا', 'Rabbi zidnī ʿilmā', '“My Lord! Increase me in knowledge”', 1, '', '', 'Supplications from Ta-Ha', 22),
  ('bocp_023', 'book_of_prayer', '', 'لَا إِلَٰهَ إِلَّا أَنْتَ سُبْحَانَكَ إِنِّي كُنْتُ مِنَ الظَّالِمِينَ', 'Lā ilāha illā anta subḥānaka innī kuntu mina''ẓ-ẓālimīn', '“There is no god ˹worthy of worship˺ except You. Glory be to You! I have certainly done wrong”', 1, '', '', 'Supplications from al-Anbiya', 23),
  ('bocp_024', 'book_of_prayer', '', 'رَبِّ لَا تَذَرْنِي فَرْدًا وَأَنْتَ خَيْرُ الْوَارِثِينَ', 'Rabbi lā tadharnī fardan wa anta khayru''l-wārithīn', '“My Lord! Do not leave me childless, though You are the Best of Successors”', 1, '', '', 'Supplications from al-Anbiya', 24),
  ('bocp_025', 'book_of_prayer', '', 'رَبِّ أَنْزِلْنِي مُنْزَلًا مُبَارَكًا وَأَنْتَ خَيْرُ الْمُنْزِلِينَ', 'Rabbi anzilnī munzalan mubārakan wa anta khayru''l-munzilīn', '“My Lord! Allow me a blessed landing, for You are the best accommodator”', 1, '', '', 'Supplications from al-Mu''minun', 25),
  ('bocp_026', 'book_of_prayer', '', 'رَبِّ أَعُوذُ بِكَ مِنْ هَمَزَاتِ الشَّيَاطِينِ وَأَعُوذُ بِكَ رَبِّ أَنْ يَحْضُرُونِ', 'Rabbi aʿūdhu bika min hamazāti''sh-shayāṭīn, wa aʿūdhu bika rabbi an yaḥḍurūn', '“My Lord! I seek refuge in You from the temptations of the devils And I seek refuge in You, my Lord, that they ˹even˺ come near me”', 1, '', '', 'Supplications from al-Mu''minun', 26),
  ('bocp_027', 'book_of_prayer', '', 'رَبَّنَا آمَنَّا فَاغْفِرْ لَنَا وَارْحَمْنَا وَأَنْتَ خَيْرُ الرَّاحِمِينَ', 'Rabbanā āmannā fa''ghfir lanā wa''rḥamnā wa anta khayru''r-rāḥimīn', '“Our Lord! We have believed, so forgive us and have mercy on us, for You are the best of those who show mercy”', 1, '', '', 'Supplications from al-Mu''minun', 27),
  ('bocp_028', 'book_of_prayer', '', 'رَبِّ اغْفِرْ وَارْحَمْ وَأَنْتَ خَيْرُ الرَّاحِمِينَ', 'Rabbi''ghfir wa''rḥam wa anta khayru''r-rāḥimīn', '“My Lord! Forgive and have mercy, for You are the best of those who show mercy”', 1, '', '', 'Supplications from al-Mu''minun', 28),
  ('bocp_029', 'book_of_prayer', '', 'رَبِّ أَوْزِعْنِي أَنْ أَشْكُرَ نِعْمَتَكَ الَّتِي أَنْعَمْتَ عَلَيَّ وَعَلَى وَالِدَيَّ وَأَنْ أَعْمَلَ صَالِحًا تَرْضَاهُ وَأَدْخِلْنِي بِرَحْمَتِكَ فِي عِبَادِكَ الصَّالِحِينَ', 'Rabbi awziʿnī an ashkura niʿmataka''llatī anʿamta ʿalayya wa ʿalā wālidayya wa an aʿmala ṣāliḥan tarḍāhu wa adkhilnī bi-raḥmatika fī ʿibādika''ṣ-ṣāliḥīn', '“My Lord! Inspire me to ˹always˺ be thankful for Your favours which You have blessed me and my parents with, and to do good deeds that please you. Admit me, by Your mercy, into ˹the company of˺ Your righteous servants”', 1, '', '', 'Supplications from al-Naml', 29),
  ('bocp_030', 'book_of_prayer', '', 'رَبِّ إِنِّي ظَلَمْتُ نَفْسِي فَاغْفِرْ لِي', 'Rabbi innī ẓalamtu nafsī fa''ghfir lī', '“My Lord! I have definitely wronged my soul, so forgive me.”', 1, '', '', 'Supplications from al-Qasas', 30),
  ('bocp_031', 'book_of_prayer', '', 'رَبِّ بِمَا أَنْعَمْتَ عَلَيَّ فَلَنْ أَكُونَ ظَهِيرًا لِلْمُجْرِمِينَ', 'Rabbi bimā anʿamta ʿalayya falan akūna ẓahīran li''l-mujrimīn', '“My Lord! For all Your favours upon me, I will never side with the wicked”', 1, '', '', 'Supplications from al-Qasas', 31),
  ('bocp_032', 'book_of_prayer', '', 'رَبِّ نَجِّنِي مِنَ الْقَوْمِ الظَّالِمِينَ', 'Rabbi najjinī mina''l-qawmi''ẓ-ẓālimīn', '“My Lord! Deliver me from the wrongdoing people”', 1, '', '', 'Supplications from al-Qasas', 32),
  ('bocp_033', 'book_of_prayer', '', 'رَبِّ إِنِّي لِمَا أَنْزَلْتَ إِلَيَّ مِنْ خَيْرٍ فَقِيرٌ', 'Rabbi innī limā anzalta ilayya min khayrin faqīr', '“My Lord! I am truly in ˹desperate˺ need of whatever provision You may have in store for me”', 1, '', '', 'Supplications from al-Qasas', 33),
  ('bocp_034', 'book_of_prayer', '', 'رَبِّ انْصُرْنِي عَلَى الْقَوْمِ الْمُفْسِدِينَ', 'Rabbi''nṣurnī ʿala''l-qawmi''l-mufsidīn', '“My Lord! Help me against the people of corruption”', 1, '', '', 'Supplications from al-''Ankabut', 34),
  ('bocp_035', 'book_of_prayer', '', 'رَبَّنَا اصْرِفْ عَنَّا عَذَابَ جَهَنَّمَ إِنَّ عَذَابَهَا كَانَ غَرَامًا', 'Rabbana''ṣrif ʿannā ʿadhāba jahannama inna ʿadhābahā kāna gharāmā', '“Our Lord! Keep the punishment of Hell away from us, for its punishment is indeed unrelenting”', 1, '', '', 'Supplications from al-Furqan', 35),
  ('bocp_036', 'book_of_prayer', '', 'رَبَّنَا هَبْ لَنَا مِنْ أَزْوَاجِنَا وَذُرِّيَّاتِنَا قُرَّةَ أَعْيُنٍ وَاجْعَلْنَا لِلْمُتَّقِينَ إِمَامًا', 'Rabbanā hab lanā min azwājinā wa dhurriyyātinā qurrata aʿyunin wa''jʿalnā li''l-muttaqīna imāmā', '“Our Lord! Bless us with ˹pious˺ spouses and offspring who will be the joy of our hearts, and make us models for the righteous”', 1, '', '', 'Supplications from al-Furqan', 36),
  ('bocp_037', 'book_of_prayer', '', 'رَبَّنَا وَسِعْتَ كُلَّ شَيْءٍ رَحْمَةً وَعِلْمًا فَاغْفِرْ لِلَّذِينَ تَابُوا وَاتَّبَعُوا سَبِيلَكَ وَقِهِمْ عَذَابَ الْجَحِيمِ، رَبَّنَا وَأَدْخِلْهُمْ جَنَّاتِ عَدْنٍ الَّتِي وَعَدْتَهُمْ وَمَنْ صَلَحَ مِنْ آبَائِهِمْ وَأَزْوَاجِهِمْ وَذُرِّيَّاتِهِمْ إِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ', 'Rabbanā wasiʿta kulla shayʾin raḥmatan wa ʿilman fa''ghfir li''lladhīna tābū wa''ttabaʿū sabīlaka wa qihim ʿadhāba''l-jaḥīm. Rabbanā wa adkhilhum jannāti ʿadnin allatī waʿadtahum wa man ṣalaḥa min ābāʾihim wa azwājihim wa dhurriyyātihim, innaka anta''l-ʿazīzu''l-ḥakīm', '“Our Lord! You encompass everything in ˹Your˺ mercy and knowledge. So forgive those who repent and follow Your Way, and protect them from the torment of the Hellfire”', 1, '', '', 'Supplications from Ghafir', 37),
  ('bocp_038', 'book_of_prayer', '', 'رَبِّ أَوْزِعْنِي أَنْ أَشْكُرَ نِعْمَتَكَ الَّتِي أَنْعَمْتَ عَلَيَّ وَعَلَى وَالِدَيَّ وَأَنْ أَعْمَلَ صَالِحًا تَرْضَاهُ وَأَصْلِحْ لِي فِي ذُرِّيَّتِي إِنِّي تُبْتُ إِلَيْكَ وَإِنِّي مِنَ الْمُسْلِمِينَ', 'Rabbi awziʿnī an ashkura niʿmataka''llatī anʿamta ʿalayya wa ʿalā wālidayya wa an aʿmala ṣāliḥan tarḍāhu wa aṣliḥ lī fī dhurriyyatī, innī tubtu ilayka wa innī mina''l-muslimīn', '“My Lord! Inspire me to ˹always˺ be thankful for Your favours which You blessed me and my parents with, and to do good deeds that please You. And instil righteousness in my offspring. I truly repent to You, and I truly submit ˹to Your Will˺”', 1, '', '', 'Supplications from al-Ahqaf', 38),
  ('bocp_039', 'book_of_prayer', '', 'رَبِّ هَبْ لِي مِنَ الصَّالِحِينَ', 'Rabbi hab lī mina''ṣ-ṣāliḥīn', '“My Lord! Bless me with righteous offspring”', 1, '', '', 'Supplications from as-Saffat', 39),
  ('bocp_040', 'book_of_prayer', '', 'رَبَّنَا اغْفِرْ لَنَا وَلِإِخْوَانِنَا الَّذِينَ سَبَقُونَا بِالْإِيمَانِ وَلَا تَجْعَلْ فِي قُلُوبِنَا غِلًّا لِلَّذِينَ آمَنُوا رَبَّنَا إِنَّكَ رَؤُوفٌ رَحِيمٌ', 'Rabbana''ghfir lanā wa li-ikhwānina''lladhīna sabaqūnā bi''l-īmāni wa lā tajʿal fī qulūbinā ghillan li''lladhīna āmanū rabbanā innaka raʾūfun raḥīm', '“Our Lord! Forgive us and our fellow believers who preceded us in faith, and do not allow bitterness into our hearts towards those who believe. Our Lord! Indeed, You are Ever Gracious, Most Merciful”', 1, '', '', 'Supplications from al-Hashr', 40),
  ('bocp_041', 'book_of_prayer', '', 'رَبَّنَا عَلَيْكَ تَوَكَّلْنَا وَإِلَيْكَ أَنَبْنَا وَإِلَيْكَ الْمَصِيرُ، رَبَّنَا لَا تَجْعَلْنَا فِتْنَةً لِلَّذِينَ كَفَرُوا وَاغْفِرْ لَنَا رَبَّنَا إِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ', 'Rabbanā ʿalayka tawakkalnā wa ilayka anabnā wa ilayka''l-maṣīr. Rabbanā lā tajʿalnā fitnatan li''lladhīna kafarū wa''ghfir lanā rabbanā, innaka anta''l-ʿazīzu''l-ḥakīm', '“Our Lord! In You we trust. And to You we ˹always˺ turn. And to You is the final return”', 1, '', '', 'Supplications from al-Mumtahanah', 41),
  ('bocp_042', 'book_of_prayer', '', 'رَبِّ اغْفِرْ لِي وَلِوَالِدَيَّ وَلِمَنْ دَخَلَ بَيْتِيَ مُؤْمِنًا وَلِلْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ وَلَا تَزِدِ الظَّالِمِينَ إِلَّا تَبَارًا', 'Rabbi''ghfir lī wa li-wālidayya wa li-man dakhala baytiya muʾminan wa li''l-muʾminīna wa''l-muʾmināti wa lā tazidi''ẓ-ẓālimīna illā tabārā', '“My Lord! Forgive me, my parents, and whoever enters my house in faith, and ˹all˺ believing men and women. And increase the wrongdoers only in destruction”', 1, '', '', 'Supplications from Nuh', 42),
  ('bocp_043', 'book_of_prayer', '', 'اللَّهُمَّ آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ', 'Allāhumma ātinā fi''d-dunyā ḥasanatan wa fi''l-ākhirati ḥasanatan wa qinā ʿadhāba''n-nār', '“O Allah! Give us in this world that which is good and in the Hereafter that which is good, and save us from the torment of the Fire.”', 1, '', '', 'Prophetic Supplications', 43),
  ('bocp_044', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ فِتْنَةِ النَّارِ، وَفِتْنَةِ الْقَبْرِ، وَعَذَابِ الْقَبْرِ، وَشَرِّ فِتْنَةِ الْغِنَى، وَشَرِّ فِتْنَةِ الْفَقْرِ، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ، اللَّهُمَّ اغْسِلْ قَلْبِي بِمَاءِ الثَّلْجِ وَالْبَرَدِ، وَنَقِّ قَلْبِي مِنَ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنَ الدَّنَسِ، وَبَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْكَسَلِ وَالْمَأْثَمِ وَالْمَغْرَمِ', 'Allāhumma innī aʿūdhu bika min fitnati''n-nār, wa fitnati''l-qabr, wa ʿadhābi''l-qabr, wa sharri fitnati''l-ghinā, wa sharri fitnati''l-faqr. Allāhumma innī aʿūdhu bika min sharri fitnati''l-masīḥi''d-dajjāl. Allāhumma''ghsil qalbī bi-māʾi''th-thalji wa''l-barad, wa naqqi qalbī mina''l-khaṭāyā kamā naqqayta''th-thawba''l-abyaḍa mina''d-danas, wa bāʿid baynī wa bayna khaṭāyāya kamā bāʿadta bayna''l-mashriqi wa''l-maghrib. Allāhumma innī aʿūdhu bika mina''l-kasali wa''l-maʾthami wa''l-maghram', '“O Allah! I ask refuge with You from the torment of the Fire, and ordeal in the grave, and the punishment of the grave, and the evil (brought by) affluence and poverty. O Allah! I ask refuge with You from the trials of the Masihud Dajjal (False Messiah). O Allah, cleanse my heart with snow and cool water, and purify my heart from misdeeds as You purify the white cloth from dirt, and keep me away from sinful acts as You keep the East far away from the West. O Allah! I ask refuge with You from being lazy, sinful and having liabilities (due to debts).”', 1, '', '', 'Prophetic Supplications', 44),
  ('bocp_045', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْعَجْزِ وَالْكَسَلِ، وَالْجُبْنِ وَالْهَرَمِ وَالْبُخْلِ، وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ، وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ', 'Allāhumma innī aʿūdhu bika mina''l-ʿajzi wa''l-kasal, wa''l-jubni wa''l-harami wa''l-bukhl, wa aʿūdhu bika min ʿadhābi''l-qabr, wa min fitnati''l-maḥyā wa''l-mamāt', '“O Allah! I ask refuge with You from weakness, indolence, cowardliness, senility and miserliness. I (also) ask refuge with You from punishment of the grave, and from the trials of life and the ordeals of death.”', 1, '', '', 'Prophetic Supplications', 45),
  ('bocp_046', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ جَهْدِ الْبَلَاءِ، وَدَرَكِ الشَّقَاءِ، وَسُوءِ الْقَضَاءِ، وَشَمَاتَةِ الْأَعْدَاءِ', 'Allāhumma innī aʿūdhu bika min jahdi''l-balāʾ, wa daraki''sh-shaqāʾ, wa sūʾi''l-qaḍāʾ, wa shamātati''l-aʿdāʾ', '“O Allah! I ask refuge with You against any severe trial and bad misfortune, and adverse judgment and satire of the enemies.”', 1, '', '', 'Prophetic Supplications', 46),
  ('bocp_047', 'book_of_prayer', '', 'اللَّهُمَّ أَصْلِحْ لِي دِينِي الَّذِي هُوَ عِصْمَةُ أَمْرِي، وَأَصْلِحْ لِي دُنْيَايَ الَّتِي فِيهَا مَعَاشِي، وَأَصْلِحْ لِي آخِرَتِي الَّتِي فِيهَا مَعَادِي، وَاجْعَلِ الْحَيَاةَ زِيَادَةً لِي فِي كُلِّ خَيْرٍ، وَاجْعَلِ الْمَوْتَ رَاحَةً لِي مِنْ كُلِّ شَرٍّ', 'Allāhumma aṣliḥ lī dīniya''lladhī huwa ʿiṣmatu amrī, wa aṣliḥ lī dunyāya''llatī fīhā maʿāshī, wa aṣliḥ lī ākhiratiya''llatī fīhā maʿādī, wa''jʿali''l-ḥayāta ziyādatan lī fī kulli khayr, wa''jʿali''l-mawta rāḥatan lī min kulli sharr', '“O Allah! Make upright my religion which is the basis of my activity, make my world suited for my best subsistence, and the Hereafter my best Final Destination, and make life easy for me (to earn) all good and make death for me as relief from all evils.”', 1, '', '', 'Prophetic Supplications', 47),
  ('bocp_048', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ الْهُدَى وَالتُّقَى وَالْعَفَافَ وَالْغِنَى', 'Allāhumma innī asʾaluka''l-hudā wa''t-tuqā wa''l-ʿafāfa wa''l-ghinā', '“O Allah! I am asking You Guidance, Piety, Virtue and Wealth.”', 1, '', '', 'Prophetic Supplications', 48),
  ('bocp_049', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْعَجْزِ وَالْكَسَلِ، وَالْجُبْنِ وَالْبُخْلِ وَالْهَرَمِ، وَعَذَابِ الْقَبْرِ، اللَّهُمَّ آتِ نَفْسِي تَقْوَاهَا، وَزَكِّهَا أَنْتَ خَيْرُ مَنْ زَكَّاهَا، أَنْتَ وَلِيُّهَا وَمَوْلَاهَا، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عِلْمٍ لَا يَنْفَعُ، وَمِنْ قَلْبٍ لَا يَخْشَعُ، وَمِنْ نَفْسٍ لَا تَشْبَعُ، وَمِنْ دَعْوَةٍ لَا يُسْتَجَابُ لَهَا', 'Allāhumma innī aʿūdhu bika mina''l-ʿajzi wa''l-kasal, wa''l-jubni wa''l-bukhli wa''l-haram, wa ʿadhābi''l-qabr. Allāhumma āti nafsī taqwāhā, wa zakkihā anta khayru man zakkāhā, anta waliyyuhā wa mawlāhā. Allāhumma innī aʿūdhu bika min ʿilmin lā yanfaʿ, wa min qalbin lā yakhshaʿ, wa min nafsin lā tashbaʿ, wa min daʿwatin lā yustajābu lahā', '“O Allah! I ask refuge with You from weakness, indolence, cowardliness, senility and miserliness. I (also) ask refuge with You from punishment of the grave. O Allah! Give myself its piety (fear to You), and purify it as You are the Best of those who purify, You are its Protector and Master. O Allah! I ask refuge with You from knowledge that which is worthless, from heart that which is not subservient (to You), from self that which is unsatisfied, and from invocation that which is not accepted.”', 1, '', '', 'Prophetic Supplications', 49),
  ('bocp_050', 'book_of_prayer', '', 'اللَّهُمَّ اهْدِنِي وَسَدِّدْنِي، اللَّهُمَّ إِنِّي أَسْأَلُكَ الْهُدَى وَالسَّدَادَ', 'Allāhumma''hdinī wa saddidnī, Allāhumma innī asʾaluka''l-hudā wa''s-sadād', '“O Allah! Guide me and direct me. O Allah! I ask You Guidance and Direction.”', 1, '', '', 'Prophetic Supplications', 50),
  ('bocp_051', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ زَوَالِ نِعْمَتِكَ، وَتَحَوُّلِ عَافِيَتِكَ، وَفُجَاءَةِ نِقْمَتِكَ، وَجَمِيعِ سَخَطِكَ', 'Allāhumma innī aʿūdhu bika min zawāli niʿmatik, wa taḥawwuli ʿāfiyatik, wa fujāʾati niqmatik, wa jamīʿi sakhaṭik', '“O Allah! I ask refuge with You from the cessation of Your Blessing, and Your Protection (of me from harm), and Your sudden Wrath and all that displeased You.”', 1, '', '', 'Prophetic Supplications', 51),
  ('bocp_052', 'book_of_prayer', '', 'اللَّهُمَّ أَكْثِرْ مَالِي وَوَلَدِي، وَبَارِكْ لِي فِيمَا أَعْطَيْتَنِي، وَأَطِلْ حَيَاتِي عَلَى طَاعَتِكَ، وَأَحْسِنْ عَمَلِي وَاغْفِرْ لِي', 'Allāhumma akthir mālī wa waladī, wa bārik lī fīmā aʿṭaytanī, wa aṭil ḥayātī ʿalā ṭāʿatik, wa aḥsin ʿamalī wa''ghfir lī', '“O Allah! Increase my wealth and (provide me) more children, bless for me all that You give me (wealth, children, knowledge, etc.), prolong my life in obeying You, (help me) excel in my (Islamic) activities, and forgive me.”', 1, '', '', 'Prophetic Supplications', 52),
  ('bocp_053', 'book_of_prayer', '', 'لَا إِلَٰهَ إِلَّا اللَّهُ الْعَظِيمُ الْحَلِيمُ، لَا إِلَٰهَ إِلَّا اللَّهُ رَبُّ الْعَرْشِ الْعَظِيمِ، لَا إِلَٰهَ إِلَّا اللَّهُ رَبُّ السَّمَوَاتِ وَرَبُّ الْأَرْضِ وَرَبُّ الْعَرْشِ الْكَرِيمِ', 'Lā ilāha illa''llāhu''l-ʿaẓīmu''l-ḥalīm, lā ilāha illa''llāhu rabbu''l-ʿarshi''l-ʿaẓīm, lā ilāha illa''llāhu rabbu''s-samāwāti wa rabbu''l-arḍi wa rabbu''l-ʿarshi''l-karīm', '“None has the right to be worshipped but Allah, the Great Forbearer. None has the right to be worshipped but Allah, Lord of the Great Throne. None has the right to be worshipped but Allah, Lord of the Heavens and the Earth and Lord of the Noble Throne.”', 1, '', '', 'Prophetic Supplications', 53),
  ('bocp_054', 'book_of_prayer', '', 'اللَّهُمَّ رَحْمَتَكَ أَرْجُو، فَلَا تَكِلْنِي إِلَى نَفْسِي طَرْفَةَ عَيْنٍ، وَأَصْلِحْ لِي شَأْنِي كُلَّهُ، لَا إِلَٰهَ إِلَّا أَنْتَ', 'Allāhumma raḥmataka arjū, falā takilnī ilā nafsī ṭarfata ʿayn, wa aṣliḥ lī shaʾnī kullah, lā ilāha illā ant', '“O Allah! Your Mercy is what I am yearning for, so (please) don''t stop guiding myself even in a blink of an eye, set right for me all of my actions, none has the right to be worshipped except You (O Allah).”', 1, '', '', 'Prophetic Supplications', 54),
  ('bocp_055', 'book_of_prayer', '', 'لَا إِلَٰهَ إِلَّا أَنْتَ سُبْحَانَكَ إِنِّي كُنْتُ مِنَ الظَّالِمِينَ', 'Lā ilāha illā anta subḥānaka innī kuntu mina''ẓ-ẓālimīn', '“La ilaha illa anta [none has the right to be worshipped but You (O Allah)], Glorified (and Exalted) be You [above all that (evil) they associate with You]! Truly, I have been of the wrong-doers.”', 1, '', '', 'Prophetic Supplications', 55),
  ('bocp_056', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي عَبْدُكَ ابْنُ عَبْدِكَ ابْنُ أَمَتِكَ، نَاصِيَتِي بِيَدِكَ، مَاضٍ فِيَّ حُكْمُكَ، عَدْلٌ فِيَّ قَضَاؤُكَ، أَسْأَلُكَ بِكُلِّ اسْمٍ هُوَ لَكَ، سَمَّيْتَ بِهِ نَفْسَكَ، أَوْ أَنْزَلْتَهُ فِي كِتَابِكَ، أَوْ عَلَّمْتَهُ أَحَدًا مِنْ خَلْقِكَ، أَوِ اسْتَأْثَرْتَ بِهِ فِي عِلْمِ الْغَيْبِ عِنْدَكَ، أَنْ تَجْعَلَ الْقُرْآنَ رَبِيعَ قَلْبِي، وَنُورَ صَدْرِي، وَجَلَاءَ حُزْنِي، وَذَهَابَ هَمِّي', 'Allāhumma innī ʿabduka''bnu ʿabdika''bnu amatik, nāṣiyatī bi-yadik, māḍin fiyya ḥukmuk, ʿadlun fiyya qaḍāʾuk, asʾaluka bi-kulli''smin huwa lak, sammayta bihi nafsak, aw anzaltahu fī kitābik, aw ʿallamtahu aḥadan min khalqik, awi''staʾtharta bihi fī ʿilmi''l-ghaybi ʿindak, an tajʿala''l-qurʾāna rabīʿa qalbī, wa nūra ṣadrī, wa jalāʾa ḥuznī, wa dhahāba hammī', '“O Allah! I am Your slave, son of Your male and female slaves, my thoughts are in Your Hand, Your Command I must endeavor to (fully and) continuously fulfill, You are Just in Your Commands (to me). I am asking You with all Your Names that which You named for Yourself, or revealed in Your Book, or You taught to one of Your creatures, or that which You keep in the unseen knowledge with You; to make the Qur''an the life of my heart, the light of my chest, reliever of my grief, and remover of my worries.”', 1, '', '', 'Prophetic Supplications', 56),
  ('bocp_057', 'book_of_prayer', '', 'اللَّهُمَّ مُصَرِّفَ الْقُلُوبِ، صَرِّفْ قُلُوبَنَا عَلَى طَاعَتِكَ', 'Allāhumma muṣarrifa''l-qulūb, ṣarrif qulūbanā ʿalā ṭāʿatik', '“O Allah! (He Who) guides the hearts, (please) guide our hearts to obey You.”', 1, '', '', 'Prophetic Supplications', 57),
  ('bocp_058', 'book_of_prayer', '', 'يَا مُقَلِّبَ الْقُلُوبِ، ثَبِّتْ قَلْبِي عَلَى دِينِكَ', 'Yā muqalliba''l-qulūb, thabbit qalbī ʿalā dīnik', '“O (He Who) alters the hearts; make firm my heart upon Your religion.”', 1, '', '', 'Prophetic Supplications', 58),
  ('bocp_059', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ', 'Allāhumma innī asʾaluka''l-ʿāfiyata fi''d-dunyā wa''l-ākhirah', '“O Allah! Grant me good well-being here on Earth and in the Hereafter.”', 1, '', '', 'Prophetic Supplications', 59),
  ('bocp_060', 'book_of_prayer', '', 'اللَّهُمَّ أَحْسِنْ عَاقِبَتَنَا فِي الْأُمُورِ كُلِّهَا، وَأَجِرْنَا مِنْ خِزْيِ الدُّنْيَا وَعَذَابِ الْقَبْرِ', 'Allāhumma aḥsin ʿāqibatanā fi''l-umūri kullihā, wa ajirnā min khizyi''d-dunyā wa ʿadhābi''l-qabr', '“O Allah! Give us good rewards for all our deeds; save us from the disgrace of this life and from the punishment of the grave.”', 1, '', '', 'Prophetic Supplications', 60),
  ('bocp_061', 'book_of_prayer', '', 'رَبِّ أَعِنِّي وَلَا تُعِنْ عَلَيَّ، وَانْصُرْنِي وَلَا تَنْصُرْ عَلَيَّ، وَامْكُرْ لِي وَلَا تَمْكُرْ عَلَيَّ، اجْعَلْنِي لَكَ شَكَّارًا، لَكَ ذَكَّارًا، لَكَ رَهَّابًا، لَكَ مِطْوَاعًا، إِلَيْكَ مُخْبِتًا أَوَّاهًا مُنِيبًا، رَبِّ تَقَبَّلْ تَوْبَتِي، وَاغْسِلْ حَوْبَتِي، وَأَجِبْ دَعْوَتِي، وَثَبِّتْ حُجَّتِي، وَاهْدِ قَلْبِي، وَسَدِّدْ لِسَانِي، وَاسْلُلْ سَخِيمَةَ قَلْبِي', 'Rabbi aʿinnī wa lā tuʿin ʿalayy, wa''nṣurnī wa lā tanṣur ʿalayy, wa''mkur lī wa lā tamkur ʿalayy, ijʿalnī laka shakkāran, laka dhakkāran, laka rahhāban, laka miṭwāʿan, ilayka mukhbitan awwāhan munīban, rabbi taqabbal tawbatī, wa''ghsil ḥawbatī, wa ajib daʿwatī, wa thabbit ḥujjatī, wa''hdi qalbī, wa saddid lisānī, wa''slul sakhīmata qalbī', '“Lord! Help me to be mindful of good deeds and not of bad ones, provide me victory for good and not for bad, give me intellect for good not for bad, make me thankful to You (O Allah), praying to You (Alone), fearing You (Alone), obeying You (Alone), submissive to You (O Allah), and penitent to You (O Allah). Accept my repentance, purify me, answer my prayer, establish me firmly (in Your religion), guide my heart, direct my tongue (to say Right), and eliminate the black spots from my heart.”', 1, '', '', 'Prophetic Supplications', 61),
  ('bocp_062', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ سَمْعِي، وَمِنْ شَرِّ بَصَرِي، وَمِنْ شَرِّ لِسَانِي، وَمِنْ شَرِّ قَلْبِي، وَمِنْ شَرِّ مَنِيِّي', 'Allāhumma innī aʿūdhu bika min sharri samʿī, wa min sharri baṣarī, wa min sharri lisānī, wa min sharri qalbī, wa min sharri maniyyī', '“O Allah! I ask refuge with You from the badness of my hearing, from the immorality of my vision, from the ruthlessness of my word, from the wickedness of my heart and from impiety of my semen.”', 1, '', '', 'Prophetic Supplications', 62),
  ('bocp_063', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّكَ عَفُوٌّ كَرِيمٌ تُحِبُّ الْعَفْوَ فَاعْفُ عَنِّي', 'Allāhumma innaka ʿafuwwun karīmun tuḥibbu''l-ʿafwa fa''fu ʿannī', '“O Allah! You are the Forgiver, the Generous; You love those who repent, so (please) forgive me.”', 1, '', '', 'Prophetic Supplications', 63),
  ('bocp_064', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ فِعْلَ الْخَيْرَاتِ، وَتَرْكَ الْمُنْكَرَاتِ، وَحُبَّ الْمَسَاكِينِ، وَأَنْ تَغْفِرَ لِي وَتَرْحَمَنِي، وَإِذَا أَرَدْتَ فِتْنَةَ قَوْمٍ فَتَوَفَّنِي غَيْرَ مَفْتُونٍ، وَأَسْأَلُكَ حُبَّكَ، وَحُبَّ مَنْ يُحِبُّكَ، وَحُبَّ عَمَلٍ يُقَرِّبُنِي إِلَى حُبِّكَ', 'Allāhumma innī asʾaluka fiʿla''l-khayrāt, wa tarka''l-munkarāt, wa ḥubba''l-masākīn, wa an taghfira lī wa tarḥamanī, wa idhā aradta fitnata qawmin fatawaffanī ghayra maftūn, wa asʾaluka ḥubbak, wa ḥubba man yuḥibbuk, wa ḥubba ʿamalin yuqarribunī ilā ḥubbik', '“O Allah! I ask You to let me do the good deeds and leave the forbidden ones, and love the poor, and forgive me and have mercy on me; if You want to destroy the people, (please) take my life (in order) not to be included with them. I ask Your Love (O Allah) and the love of those whom You loved, and to love the deeds that will bring me near to Your Love.”', 1, '', '', 'Prophetic Supplications', 64),
  ('bocp_065', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنَ الْخَيْرِ كُلِّهِ عَاجِلِهِ وَآجِلِهِ، مَا عَلِمْتُ مِنْهُ وَمَا لَمْ أَعْلَمْ، وَأَعُوذُ بِكَ مِنَ الشَّرِّ كُلِّهِ عَاجِلِهِ وَآجِلِهِ، مَا عَلِمْتُ مِنْهُ وَمَا لَمْ أَعْلَمْ، اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ خَيْرِ مَا سَأَلَكَ عَبْدُكَ وَنَبِيُّكَ، وَأَعُوذُ بِكَ مِنْ شَرِّ مَا اسْتَعَاذَ مِنْهُ عَبْدُكَ وَنَبِيُّكَ، اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ وَمَا قَرَّبَ إِلَيْهَا مِنْ قَوْلٍ أَوْ عَمَلٍ، وَأَعُوذُ بِكَ مِنَ النَّارِ وَمَا قَرَّبَ إِلَيْهَا مِنْ قَوْلٍ أَوْ عَمَلٍ، وَأَسْأَلُكَ أَنْ تَجْعَلَ كُلَّ قَضَاءٍ قَضَيْتَهُ لِي خَيْرًا', 'Allāhumma innī asʾaluka mina''l-khayri kullihi ʿājilihi wa ājilih, mā ʿalimtu minhu wa mā lam aʿlam, wa aʿūdhu bika mina''sh-sharri kullihi ʿājilihi wa ājilih, mā ʿalimtu minhu wa mā lam aʿlam, Allāhumma innī asʾaluka min khayri mā saʾalaka ʿabduka wa nabiyyuk, wa aʿūdhu bika min sharri ma''staʿādha minhu ʿabduka wa nabiyyuk, Allāhumma innī asʾaluka''l-jannata wa mā qarraba ilayhā min qawlin aw ʿamal, wa aʿūdhu bika mina''n-nāri wa mā qarraba ilayhā min qawlin aw ʿamal, wa asʾaluka an tajʿala kulla qaḍāʾin qaḍaytahu lī khayrā', '“O Allah! I seek from You every goodness; both the immediate and the latter and which I would know or would not know. I ask refuge with You against every evil, both the immediate and the latter and which I would know or would not know. I ask from You the best which had been sought by Your slave and Prophet (pbuh), and I ask refuge with You against the evil of all such things from which protection had been sought by Your slave and Prophet (pbuh). O Allah! I ask You the Garden (Paradise) and any such deed or word which may bring me closer to it. I ask refuge with You against the Hell-Fire and from any such deed or word which may bring me closer to it, and I ask You (O Allah) to make good every fate You have destined for me.”', 1, '', '', 'Prophetic Supplications', 65),
  ('bocp_066', 'book_of_prayer', '', 'اللَّهُمَّ احْفَظْنِي بِالْإِسْلَامِ قَائِمًا، وَاحْفَظْنِي بِالْإِسْلَامِ قَاعِدًا، وَاحْفَظْنِي بِالْإِسْلَامِ رَاقِدًا، وَلَا تُشْمِتْ بِي عَدُوًّا وَلَا حَاسِدًا، اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ كُلِّ خَيْرٍ خَزَائِنُهُ بِيَدِكَ، وَأَعُوذُ بِكَ مِنْ كُلِّ شَرٍّ خَزَائِنُهُ بِيَدِكَ', 'Allāhumma''ḥfaẓnī bi''l-islāmi qāʾiman, wa''ḥfaẓnī bi''l-islāmi qāʿidan, wa''ḥfaẓnī bi''l-islāmi rāqidan, wa lā tushmit bī ʿaduwwan wa lā ḥāsidan, Allāhumma innī asʾaluka min kulli khayrin khazāʾinuhu bi-yadik, wa aʿūdhu bika min kulli sharrin khazāʾinuhu bi-yadik', '“O Allah! Protect me standing in Islam, protect me sitting in Islam, and protect me lying down in Islam; and don''t allow enemy and envier to rejoice over my grief. O Allah! I ask You all that which is good that lay by Your Hand, and I ask refuge with You from all that which is bad that lay by Your Hand.”', 1, '', '', 'Prophetic Supplications', 66),
  ('bocp_067', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْجُبْنِ، وَأَعُوذُ بِكَ مِنَ الْبُخْلِ، وَأَعُوذُ بِكَ مِنْ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ، وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا وَعَذَابِ الْقَبْرِ', 'Allāhumma innī aʿūdhu bika mina''l-jubn, wa aʿūdhu bika mina''l-bukhl, wa aʿūdhu bika min an uradda ilā ardhali''l-ʿumur, wa aʿūdhu bika min fitnati''d-dunyā wa ʿadhābi''l-qabr', '“O Allah! I ask refuge with You from cowardice; and I ask refuge with You from miserliness; and I ask refuge with You from being sent back to geriatric old age; and I ask refuge with You from the Fitnah (trials and affliction etc) of this world and the punishment in the grave.”', 1, '', '', 'Prophetic Supplications', 67),
  ('bocp_068', 'book_of_prayer', '', 'اللَّهُمَّ اغْفِرْ لِي خَطِيئَتِي، وَجَهْلِي، وَإِسْرَافِي فِي أَمْرِي، وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي، اللَّهُمَّ اغْفِرْ لِي هَزْلِي وَجِدِّي، وَخَطَئِي وَعَمْدِي، وَكُلُّ ذَلِكَ عِنْدِي', 'Allāhumma''ghfir lī khaṭīʾatī, wa jahlī, wa isrāfī fī amrī, wa mā anta aʿlamu bihi minnī, Allāhumma''ghfir lī hazlī wa jiddī, wa khaṭaʾī wa ʿamdī, wa kullu dhālika ʿindī', '“O Allah! Forgive my mistakes, my ignorance, and my exceeding the limit (i.e. my great sins) and forgive whatever, You know better than I; O Allah! Forgive the wrong I have done jokingly or seriously, and forgive my accidental and intentional errors, all that is present in me.”', 1, '', '', 'Prophetic Supplications', 68),
  ('bocp_069', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَثِيرًا، وَلَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ، فَاغْفِرْ لِي مَغْفِرَةً مِنْ عِنْدِكَ، وَارْحَمْنِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ', 'Allāhumma innī ẓalamtu nafsī ẓulman kathīran, wa lā yaghfiru''dh-dhunūba illā ant, fa''ghfir lī maghfiratan min ʿindik, wa''rḥamnī innaka anta''l-ghafūru''r-raḥīm', '“O Allah! I corrupted myself a lot; You (Alone) forgive (all) sins, so (please) forgive me with forgiveness from You, and have Mercy on me, You are indeed the Most Forgiving the Most Merciful.”', 1, '', '', 'Prophetic Supplications', 69),
  ('bocp_070', 'book_of_prayer', '', 'اللَّهُمَّ لَكَ أَسْلَمْتُ، وَبِكَ آمَنْتُ، وَعَلَيْكَ تَوَكَّلْتُ، وَإِلَيْكَ أَنَبْتُ، وَبِكَ خَاصَمْتُ، اللَّهُمَّ إِنِّي أَعُوذُ بِعِزَّتِكَ، لَا إِلَٰهَ إِلَّا أَنْتَ أَنْ تُضِلَّنِي، أَنْتَ الْحَيُّ الَّذِي لَا يَمُوتُ، وَالْجِنُّ وَالْإِنْسُ يَمُوتُونَ', 'Allāhumma laka aslamtu, wa bika āmantu, wa ʿalayka tawakkaltu, wa ilayka anabtu, wa bika khāṣamtu, Allāhumma innī aʿūdhu bi-ʿizzatik, lā ilāha illā anta an tuḍillanī, anta''l-ḥayyu''lladhī lā yamūt, wa''l-jinnu wa''l-insu yamūtūn', '“O Allah! I submit myself to You, and I believe in You, and I depend on You, and I repent to You, and return to You, and to You I leave the judgment. I seek refuge (with You) by Your Might, no one has the right to be worshipped but You, against Your misguidance; You are the Ever Living One Who dies not, while the jinn and the human beings die.”', 1, '', '', 'Prophetic Supplications', 70),
  ('bocp_071', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّا نَسْأَلُكَ مُوجِبَاتِ رَحْمَتِكَ، وَعَزَائِمَ مَغْفِرَتِكَ، وَالسَّلَامَةَ مِنْ كُلِّ إِثْمٍ، وَالْغَنِيمَةَ مِنْ كُلِّ بِرٍّ، وَالْفَوْزَ بِالْجَنَّةِ، وَالنَّجَاةَ مِنَ النَّارِ', 'Allāhumma innā nasʾaluka mūjibāti raḥmatik, wa ʿazāʾima maghfiratik, wa''s-salāmata min kulli ithm, wa''l-ghanīmata min kulli birr, wa''l-fawza bi''l-jannah, wa''n-najāta mina''n-nār', '“O Allah! We ask the exigencies of Your Mercy, the comforts of Your Forgiveness, and security from all sins, and prizes from all devotion, and reward of Paradise, and deliverance from the Fire.”', 1, '', '', 'Prophetic Supplications', 71),
  ('bocp_072', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَلِمْتُ، وَمِنْ شَرِّ مَا لَمْ أَعْلَمْ', 'Allāhumma innī aʿūdhu bika min sharri mā ʿalimtu, wa min sharri mā lam aʿlam', '“O Allah! I ask refuge with You from the evil of (all) that which I know and from the evil of (all) that which I know not.”', 1, '', '', 'Prophetic Supplications', 72),
  ('bocp_073', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْ أَوْسَعَ رِزْقِكَ عَلَيَّ عِنْدَ كِبَرِ سِنِّي، وَانْقِطَاعِ عُمُرِي', 'Allāhumma''jʿal awsaʿa rizqika ʿalayya ʿinda kibari sinnī, wa''nqiṭāʿi ʿumurī', '“O Allah! Increase me my sustenance at the time of my old age and at the end of life.”', 1, '', '', 'Prophetic Supplications', 73),
  ('bocp_074', 'book_of_prayer', '', 'اللَّهُمَّ اغْفِرْ لِي ذَنْبِي، وَوَسِّعْ لِي فِي دَارِي، وَبَارِكْ لِي فِي رِزْقِي', 'Allāhumma''ghfir lī dhanbī, wa wassiʿ lī fī dārī, wa bārik lī fī rizqī', '“O Allah! Forgive me for my sins, make my home spacious for me, bless for me my sustenance (which You provided).”', 1, '', '', 'Prophetic Supplications', 74),
  ('bocp_075', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ وَرَحْمَتِكَ، فَإِنَّهُ لَا يَمْلِكُهَا إِلَّا أَنْتَ', 'Allāhumma innī asʾaluka min faḍlika wa raḥmatik, fa-innahu lā yamlikuhā illā ant', '“O Allah! I ask You Your Favor and Mercy, no One possesses them but You.”', 1, '', '', 'Prophetic Supplications', 75),
  ('bocp_076', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ التَّرَدِّي، وَالْهَدْمِ، وَالْغَرَقِ، وَالْحَرَقِ، وَأَعُوذُ بِكَ أَنْ يَتَخَبَّطَنِيَ الشَّيْطَانُ عِنْدَ الْمَوْتِ، وَأَعُوذُ بِكَ أَنْ أَمُوتَ فِي سَبِيلِكَ مُدْبِرًا، وَأَعُوذُ بِكَ أَنْ أَمُوتَ لَدِيغًا', 'Allāhumma innī aʿūdhu bika mina''t-taraddī, wa''l-hadm, wa''l-gharaq, wa''l-ḥaraq, wa aʿūdhu bika an yatakhabbaṭaniya''sh-shayṭānu ʿinda''l-mawt, wa aʿūdhu bika an amūta fī sabīlika mudbiran, wa aʿūdhu bika an amūta ladīghan', '“O Allah! I ask refuge with You from deterioration, destruction, sinking, and burning; I ask refuge with You from being overcome by the Shaitan (Satan) during my death, I ask refuge with You from death while I turned away from Your Way, and I ask refuge with You from death by poison.”', 1, '', '', 'Prophetic Supplications', 76),
  ('bocp_077', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْعَجْزِ، وَالْكَسَلِ، وَالْجُبْنِ، وَالْبُخْلِ، وَالْهَرَمِ، وَالْكُفْرِ، وَالْفُسُوقِ، وَالشِّقَاقِ، وَالنِّفَاقِ، وَالسُّمْعَةِ، وَالرِّيَاءِ، وَأَعُوذُ بِكَ مِنَ الصَّمَمِ، وَالْبَكَمِ، وَالْجُنُونِ، وَالْجُذَامِ، وَالْبَرَصِ، وَسَيِّئِ الْأَسْقَامِ', 'Allāhumma innī aʿūdhu bika mina''l-ʿajz, wa''l-kasal, wa''l-jubn, wa''l-bukhl, wa''l-haram, wa''l-kufr, wa''l-fusūq, wa''sh-shiqāq, wa''n-nifāq, wa''s-sumʿah, wa''r-riyāʾ, wa aʿūdhu bika mina''ṣ-ṣamam, wa''l-bakam, wa''l-junūn, wa''l-judhām, wa''l-baraṣ, wa sayyiʾi''l-asqām', '“O Allah! I ask refuge with You against weakness, indolence, cowardliness, miserliness, senility, disbelieving, immorality, rebellion, hypocrisy, grandstanding, and showiness; I (also) ask refuge with You against deafness, dumbness, insanity, leprosy, paralysis and other foul diseases.”', 1, '', '', 'Prophetic Supplications', 77),
  ('bocp_078', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْفَقْرِ، وَالْقِلَّةِ، وَالذِّلَّةِ، وَأَعُوذُ بِكَ مِنْ أَنْ أَظْلِمَ أَوْ أُظْلَمَ', 'Allāhumma innī aʿūdhu bika mina''l-faqr, wa''l-qillah, wa''dh-dhillah, wa aʿūdhu bika min an aẓlima aw uẓlam', '“O Allah! I ask refuge with You from poverty, scarcity, and humiliation; I (also) ask refuge with You from oppression and being oppressed.”', 1, '', '', 'Prophetic Supplications', 78),
  ('bocp_079', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ قَلْبٍ لَا يَخْشَعُ، وَمِنْ دُعَاءٍ لَا يُسْمَعُ، وَمِنْ نَفْسٍ لَا تَشْبَعُ، وَمِنْ عِلْمٍ لَا يَنْفَعُ، أَعُوذُ بِكَ مِنْ هَؤُلَاءِ الْأَرْبَعِ', 'Allāhumma innī aʿūdhu bika min qalbin lā yakhshaʿ, wa min duʿāʾin lā yusmaʿ, wa min nafsin lā tashbaʿ, wa min ʿilmin lā yanfaʿ, aʿūdhu bika min hāʾulāʾi''l-arbaʿ', '“O Allah! I ask refuge with You from heart which is not subservient (to You), from invocation that does not accepted (by You), from self that which is unsatisfied, from knowledge that which is worthless; I ask refuge with You from all these four.”', 1, '', '', 'Prophetic Supplications', 79),
  ('bocp_080', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ يَوْمِ السُّوءِ، وَمِنْ لَيْلَةِ السُّوءِ، وَمِنْ سَاعَةِ السُّوءِ، وَمِنْ صَاحِبِ السُّوءِ، وَمِنْ جَارِ السُّوءِ فِي دَارِ الْمُقَامَةِ', 'Allāhumma innī aʿūdhu bika min yawmi''s-sūʾ, wa min laylati''s-sūʾ, wa min sāʿati''s-sūʾ, wa min ṣāḥibi''s-sūʾ, wa min jāri''s-sūʾi fī dāri''l-muqāmah', '“O Allah! I ask refuge with You from evil day, from evil night, from bad friend, from bad neighbor in the home at the last day.”', 1, '', '', 'Prophetic Supplications', 80),
  ('bocp_081', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ وَأَسْتَجِيرُ بِكَ مِنَ النَّارِ', 'Allāhumma innī asʾaluka''l-jannata wa astajīru bika mina''n-nār', '“O Allah! I ask You Paradise and I seek Your protection from the Fire.”', 1, '', '', 'Prophetic Supplications', 81),
  ('bocp_082', 'book_of_prayer', '', 'اللَّهُمَّ فَقِّهْنِي فِي الدِّينِ', 'Allāhumma faqqihnī fi''d-dīn', '“O Allah! Provide me a wider understanding of the tenets of Religion.”', 1, '', '', 'Prophetic Supplications', 82),
  ('bocp_083', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ أَنْ أُشْرِكَ بِكَ وَأَنَا أَعْلَمُ، وَأَسْتَغْفِرُكَ لِمَا لَا أَعْلَمُ', 'Allāhumma innī aʿūdhu bika an ushrika bika wa anā aʿlam, wa astaghfiruka limā lā aʿlam', '“O Allah! I ask refuge with You from associating partner with You which I have knowledge of; and forgive me for that which I have no knowledge of.”', 1, '', '', 'Prophetic Supplications', 83),
  ('bocp_084', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ عِلْمًا نَافِعًا، وَرِزْقًا طَيِّبًا، وَعَمَلًا مُتَقَبَّلًا', 'Allāhumma innī asʾaluka ʿilman nāfiʿan, wa rizqan ṭayyiban, wa ʿamalan mutaqabbalan', '“O Allah! I ask You knowledge that which is useful, livelihood that which is good and deed that which is accepted (by Allah).”', 1, '', '', 'Prophetic Supplications', 84),
  ('bocp_085', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ عِلْمًا نَافِعًا، وَأَعُوذُ بِكَ مِنْ عِلْمٍ لَا يَنْفَعُ', 'Allāhumma innī asʾaluka ʿilman nāfiʿan, wa aʿūdhu bika min ʿilmin lā yanfaʿ', '“O Allah! I ask You knowledge that which is useful, and I ask refuge with You from knowledge that which is worthless.”', 1, '', '', 'Prophetic Supplications', 85),
  ('bocp_086', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ يَا اللَّهُ بِأَنَّكَ الْوَاحِدُ الْأَحَدُ، الصَّمَدُ، الَّذِي لَمْ يَلِدْ وَلَمْ يُولَدْ، وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ، أَنْ تَغْفِرَ لِي ذُنُوبِي، إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ', 'Allāhumma innī asʾaluka yā Allāhu bi-annaka''l-wāḥidu''l-aḥad, aṣ-ṣamad, alladhī lam yalid wa lam yūlad, wa lam yakun lahu kufuwan aḥad, an taghfira lī dhunūbī, innaka anta''l-ghafūru''r-raḥīm', '“O Allah! I ask You O Allah for You are indeed One and Only (God), the Self-Sufficient Master, He Who begets not nor was He begotten, and there is none co-equal or comparable to Him, to forgive me my sins; You indeed is the Most Forgiving the Most Merciful.”', 1, '', '', 'Prophetic Supplications', 86),
  ('bocp_087', 'book_of_prayer', '', 'اللَّهُمَّ أَنْتَ اللَّهُ الْأَحَدُ الصَّمَدُ الَّذِي لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ، أَنْتَ الْأَوَّلُ فَلَيْسَ قَبْلَكَ شَيْءٌ، وَأَنْتَ الْآخِرُ فَلَيْسَ بَعْدَكَ شَيْءٌ، وَأَنْتَ الظَّاهِرُ فَلَيْسَ فَوْقَكَ شَيْءٌ، وَأَنْتَ الْبَاطِنُ فَلَيْسَ دُونَكَ شَيْءٌ، أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ وَأَنْتَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ', 'Allāhumma anta''llāhu''l-aḥadu''ṣ-ṣamadu''lladhī lam yalid wa lam yūlad wa lam yakun lahu kufuwan aḥad, anta''l-awwalu fa-laysa qablaka shayʾ, wa anta''l-ākhiru fa-laysa baʿdaka shayʾ, wa anta''ẓ-ẓāhiru fa-laysa fawqaka shayʾ, wa anta''l-bāṭinu fa-laysa dūnaka shayʾ, anta''l-muqaddimu wa anta''l-muʾakhkhiru wa anta ʿalā kulli shayʾin qadīr', '“O Allah! You are Allah, the One, the Self-Sufficient Master Who begets not nor was He begotten, and there is none co-equal or comparable to Him; You are the First and nothing precedes You. You are the Last and nothing succeeds You. You are the Most High and nothing is above You. You are the All-Aware of the secrets and whatever concealed, there is no one more aware than You. You are the Beforehand and the Remainder; and You are Able to do all things.”', 1, '', '', 'Prophetic Supplications', 87),
  ('bocp_088', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ بِأَنَّ لَكَ الْحَمْدُ، لَا إِلَٰهَ إِلَّا أَنْتَ وَحْدَكَ لَا شَرِيكَ لَكَ، يَا بَدِيعَ السَّمَاوَاتِ وَالْأَرْضِ، يَا ذَا الْجَلَالِ وَالْإِكْرَامِ، يَا حَيُّ يَا قَيُّومُ، إِنِّي أَسْأَلُكَ الْجَنَّةَ، وَأَعُوذُ بِكَ مِنَ النَّارِ', 'Allāhumma innī asʾaluka bi-anna laka''l-ḥamd, lā ilāha illā anta waḥdaka lā sharīka lak, yā badīʿa''s-samāwāti wa''l-arḍ, yā dha''l-jalāli wa''l-ikrām, yā ḥayyu yā qayyūm, innī asʾaluka''l-jannah, wa aʿūdhu bika mina''n-nār', '“O Allah! I ask You; for the Praise is Yours, none has the right to be worshipped but You, You are One and You have no associate, O Originator of Heavens and Earth, O Full of Majesty and Honor, O Ever Living, O Everlasting; I ask You the Gardens (Paradise) and I ask refuge with You from the Fire.”', 1, '', '', 'Prophetic Supplications', 88),
  ('bocp_089', 'book_of_prayer', '', 'رَبِّ اغْفِرْ لِي، وَتُبْ عَلَيَّ، إِنَّكَ أَنْتَ التَّوَّابُ الْغَفُورُ', 'Rabbi''ghfir lī, wa tub ʿalayy, innaka anta''t-tawwābu''l-ghafūr', '“Lord! Forgive me and accept my repentance; verily You are the One Who accepts repentance and the Most Forgiving.”', 1, '', '', 'Prophetic Supplications', 89),
  ('bocp_090', 'book_of_prayer', '', 'اللَّهُمَّ بِعِلْمِكَ الْغَيْبَ، وَقُدْرَتِكَ عَلَى الْخَلْقِ، أَحْيِنِي مَا عَلِمْتَ الْحَيَاةَ خَيْرًا لِي، وَتَوَفَّنِي إِذَا عَلِمْتَ الْوَفَاةَ خَيْرًا لِي، اللَّهُمَّ إِنِّي أَسْأَلُكَ خَشْيَتَكَ فِي الْغَيْبِ، وَأَسْأَلُكَ الْقَصْدَ فِي الْغِنَى وَالْفَقْرِ، وَأَسْأَلُكَ نَعِيمًا لَا يَنْفَدُ، وَأَسْأَلُكَ قُرَّةَ عَيْنٍ لَا تَنْقَطِعُ، وَأَسْأَلُكَ الرِّضَا بَعْدَ الْقَضَاءِ، وَأَسْأَلُكَ بَرْدَ الْعَيْشِ بَعْدَ الْمَوْتِ، وَأَسْأَلُكَ لَذَّةَ النَّظَرِ إِلَى وَجْهِكَ، وَالشَّوْقَ إِلَى لِقَائِكَ فِي غَيْرِ ضَرَّاءَ مُضِرَّةٍ، وَلَا فِتْنَةٍ مُضِلَّةٍ، اللَّهُمَّ زَيِّنَّا بِزِينَةِ الْإِيمَانِ، وَاجْعَلْنَا هُدَاةً مُهْتَدِينَ', 'Allāhumma bi-ʿilmika''l-ghayb, wa qudratika ʿala''l-khalq, aḥyinī mā ʿalimta''l-ḥayāta khayran lī, wa tawaffanī idhā ʿalimta''l-wafāta khayran lī, Allāhumma innī asʾaluka khashyataka fi''l-ghayb, wa asʾaluka''l-qaṣda fi''l-ghinā wa''l-faqr, wa asʾaluka naʿīman lā yanfad, wa asʾaluka qurrata ʿaynin lā tanqaṭiʿ, wa asʾaluka''r-riḍā baʿda''l-qaḍāʾ, wa asʾaluka barda''l-ʿayshi baʿda''l-mawt, wa asʾaluka ladhdhata''n-naẓari ilā wajhik, wa''sh-shawqa ilā liqāʾika fī ghayri ḍarrāʾa muḍirrah, wa lā fitnatin muḍillah, Allāhumma zayyinnā bi-zīnati''l-īmān, wa''jʿalnā hudātan muhtadīn', '“O Allah! By Your Knowledge of the unseen, and Your Power upon (all) creatures; give me life if in Your Knowledge life is better for me and give me death if in Your Knowledge death is better for me; O Allah! I ask You to make me fear You whether in secret (or open), I ask You to make me moderate both in times of richness and poverty, I ask You to provide me favor without an end, I ask You that I should be ceaselessly delighted (to obey You), I ask You a favorable living, I ask You a cool life after death, I ask You the pleasure of seeing Your Face (in the Day of Judgment), and longing to meet You without adversity and causing injury, and no trial which may lead to aberration; O Allah! Adorn us with the ornament of Faith and make among those who guide others and the rightly guided.”', 1, '', '', 'Prophetic Supplications', 90),
  ('bocp_091', 'book_of_prayer', '', 'اللَّهُمَّ طَهِّرْنِي مِنَ الذُّنُوبِ وَالْخَطَايَا، اللَّهُمَّ نَقِّنِي مِنْهَا كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنَ الدَّنَسِ، اللَّهُمَّ طَهِّرْنِي بِالثَّلْجِ وَالْبَرَدِ وَالْمَاءِ الْبَارِدِ', 'Allāhumma ṭahhirnī mina''dh-dhunūbi wa''l-khaṭāyā, Allāhumma naqqinī minhā kamā yunaqqa''th-thawbu''l-abyaḍu mina''d-danas, Allāhumma ṭahhirnī bi''th-thalji wa''l-baradi wa''l-māʾi''l-bārid', '“O Allah! (Please) cleanse me from my sins and transgressions; O Allah purify me from it the like of cleaning the white cloth from dirt; O Allah! Cleanse me with snow and cold waters.”', 1, '', '', 'Prophetic Supplications', 91),
  ('bocp_092', 'book_of_prayer', '', 'اللَّهُمَّ رَبَّ جَبْرَائِيلَ وَمِيكَائِيلَ وَرَبَّ إِسْرَافِيلَ، أَعُوذُ بِكَ مِنْ حَرِّ النَّارِ، وَمِنْ عَذَابِ الْقَبْرِ', 'Allāhumma rabba jibrāʾīla wa mīkāʾīla wa rabba isrāfīl, aʿūdhu bika min ḥarri''n-nār, wa min ʿadhābi''l-qabr', '“O Allah! The Lord of Jibril, Mikaeel, and Lord of Israfil; I ask refuge with You from the heat of the Fire and from the punishment of the grave.”', 1, '', '', 'Prophetic Supplications', 92),
  ('bocp_093', 'book_of_prayer', '', 'اللَّهُمَّ أَلْهِمْنِي رُشْدِي، وَأَعِذْنِي مِنْ شَرِّ نَفْسِي', 'Allāhumma alhimnī rushdī, wa aʿidhnī min sharri nafsī', '“O Allah! Convey to me guidance and save me against the evil of myself.”', 1, '', '', 'Prophetic Supplications', 93),
  ('bocp_094', 'book_of_prayer', '', 'اللَّهُمَّ رَبَّ السَّمَاوَاتِ وَرَبَّ الْأَرْضِ، وَرَبَّ الْعَرْشِ الْعَظِيمِ، رَبَّنَا وَرَبَّ كُلِّ شَيْءٍ، فَالِقَ الْحَبِّ وَالنَّوَى، وَمُنْزِلَ التَّوْرَاةِ وَالْإِنْجِيلِ وَالْفُرْقَانِ، أَعُوذُ بِكَ مِنْ شَرِّ كُلِّ شَيْءٍ أَنْتَ آخِذٌ بِنَاصِيَتِهِ، اللَّهُمَّ أَنْتَ الْأَوَّلُ فَلَيْسَ قَبْلَكَ شَيْءٌ، وَأَنْتَ الْآخِرُ فَلَيْسَ بَعْدَكَ شَيْءٌ، وَأَنْتَ الظَّاهِرُ فَلَيْسَ فَوْقَكَ شَيْءٌ، وَأَنْتَ الْبَاطِنُ فَلَيْسَ دُونَكَ شَيْءٌ، اقْضِ عَنَّا الدَّيْنَ وَأَغْنِنَا مِنَ الْفَقْرِ', 'Allāhumma rabba''s-samāwāti wa rabba''l-arḍ, wa rabba''l-ʿarshi''l-ʿaẓīm, rabbanā wa rabba kulli shayʾ, fāliqa''l-ḥabbi wa''n-nawā, wa munzila''t-tawrāti wa''l-injīli wa''l-furqān, aʿūdhu bika min sharri kulli shayʾin anta ākhidhun bi-nāṣiyatih, Allāhumma anta''l-awwalu fa-laysa qablaka shayʾ, wa anta''l-ākhiru fa-laysa baʿdaka shayʾ, wa anta''ẓ-ẓāhiru fa-laysa fawqaka shayʾ, wa anta''l-bāṭinu fa-laysa dūnaka shayʾ, iqḍi ʿanna''d-dayna wa aghninā mina''l-faqr', '“O Allah! The Lord of the Heavens and Earth, the Lord of the Great Throne! O our Lord and Lord of everything, O You Who causes the seed-grain and the fruit-stone (like date-stone) to split and sprout, You revealed the Tawrat (Torah), the Injeel (Gospel), and the Furqaan (Criterion); I ask refuge with You from the badness of everything (which) You have the grasp of its forelock; O Allah! You are the First and nothing precedes You. You are the Last and nothing succeeds You. You are the Most High and nothing is above You. You are the All-Aware of the secrets and whatever concealed, there is no one more aware than You. Pay debts on my behalf and make me impervious to destitution.”', 1, '', '', 'Prophetic Supplications', 94),
  ('bocp_095', 'book_of_prayer', '', 'اللَّهُمَّ أَلِّفْ بَيْنَ قُلُوبِنَا، وَأَصْلِحْ ذَاتَ بَيْنِنَا، وَاهْدِنَا سُبُلَ السَّلَامِ، وَنَجِّنَا مِنَ الظُّلُمَاتِ إِلَى النُّورِ، وَجَنِّبْنَا الْفَوَاحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ، وَبَارِكْ لَنَا فِي أَسْمَاعِنَا وَأَبْصَارِنَا، وَقُلُوبِنَا، وَأَزْوَاجِنَا، وَذُرِّيَّاتِنَا، وَتُبْ عَلَيْنَا إِنَّكَ أَنْتَ التَّوَّابُ الرَّحِيمُ، وَاجْعَلْنَا شَاكِرِينَ لِنِعَمِكَ، مُثْنِينَ بِهَا عَلَيْكَ، قَابِلِينَ لَهَا وَأَتِمِمْهَا عَلَيْنَا', 'Allāhumma allif bayna qulūbinā, wa aṣliḥ dhāta bayninā, wa''hdinā subula''s-salām, wa najjinā mina''ẓ-ẓulumāti ila''n-nūr, wa jannibna''l-fawāḥisha mā ẓahara minhā wa mā baṭan, wa bārik lanā fī asmāʿinā wa abṣārinā, wa qulūbinā, wa azwājinā, wa dhurriyyātinā, wa tub ʿalaynā innaka anta''t-tawwābu''r-raḥīm, wa''jʿalnā shākirīna li-niʿamik, muthnīna bihā ʿalayk, qābilīna lahā wa atmimhā ʿalaynā', '“O Allah! Make closer our hearts, and set aright our relationships, and guide us to the peaceful way, and save us from the darkness towards the light of Islam, and take away from us all evils whether it is apparent or hidden, and make healthy our hearing and seeing, and our hearts, and wives, and our family, and forgive us; verily, You are the One Who accepts repentance and the Most Merciful; and make us grateful of Your providence, and Praising You, and accepting Your favor, and make it complete for us.”', 1, '', '', 'Prophetic Supplications', 95),
  ('bocp_096', 'book_of_prayer', '', 'اللَّهُمَّ جَنِّبْنِي مُنْكَرَاتِ الْأَخْلَاقِ وَالْأَهْوَاءِ وَالْأَعْمَالِ وَالْأَدْوَاءِ', 'Allāhumma jannibnī munkarāti''l-akhlāqi wa''l-ahwāʾi wa''l-aʿmāli wa''l-adwāʾ', '“O Allah! I seek Your protection from every evil conduct, bad deeds, desires and diseases.”', 1, '', '', 'Prophetic Supplications', 96),
  ('bocp_097', 'book_of_prayer', '', 'اللَّهُمَّ حَاسِبْنِي حِسَابًا يَسِيرًا', 'Allāhumma ḥāsibnī ḥisāban yasīran', '“O Allah! Account me swiftly (in the Day of Judgment).”', 1, '', '', 'Prophetic Supplications', 97),
  ('bocp_098', 'book_of_prayer', '', 'اللَّهُمَّ أَعِنَّا عَلَى ذِكْرِكَ، وَشُكْرِكَ، وَحُسْنِ عِبَادَتِكَ', 'Allāhumma aʿinnā ʿalā dhikrik, wa shukrik, wa ḥusni ʿibādatik', '“O Allah! Help us to remember You, and to be grateful to You, and to worship You in the best way.”', 1, '', '', 'Prophetic Supplications', 98),
  ('bocp_099', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ إِيمَانًا لَا يَرْتَدُّ، وَنَعِيمًا لَا يَنْفَدُ، وَمُرَافَقَةَ مُحَمَّدٍ فِي أَعْلَى جَنَّةِ الْخُلْدِ', 'Allāhumma innī asʾaluka īmānan lā yartadd, wa naʿīman lā yanfad, wa murāfaqata Muḥammadin fī aʿlā jannati''l-khuld', '“O Allah! I ask You an immovable faith (with You), and everlasting bliss, and be with Prophet Mohammad (pbuh) in the highest Paradise.”', 1, '', '', 'Prophetic Supplications', 99),
  ('bocp_100', 'book_of_prayer', '', 'اللَّهُمَّ قِنِي شَرَّ نَفْسِي، وَاعْزِمْ لِي عَلَى أَرْشَدِ أَمْرِي، اغْفِرْ لِي مَا أَسْرَرْتُ وَمَا أَعْلَنْتُ وَمَا أَخْطَأْتُ وَمَا عَمَدْتُ، وَمَا عَلِمْتُ وَمَا جَهِلْتُ', 'Allāhumma qinī sharra nafsī, wa''ʿzim lī ʿalā arshadi amrī, ighfir lī mā asrartu wa mā aʿlantu wa mā akhṭaʾtu wa mā ʿamadtu, wa mā ʿalimtu wa mā jahiltu', '“O Allah! Save me against the badness of myself, guide me towards the right way, forgive me for my sins whether secrets or concealed, by mistake or intentional; both I have knowledge or I have no knowledge of.”', 1, '', '', 'Prophetic Supplications', 100),
  ('bocp_101', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ غَلَبَةِ الدَّيْنِ، وَغَلَبَةِ الْعَدُوِّ، وَشَمَاتَةِ الْأَعْدَاءِ', 'Allāhumma innī aʿūdhu bika min ghalabati''d-dayn, wa ghalabati''l-ʿaduww, wa shamātati''l-aʿdāʾ', '“O Allah! I seek refuge with You against being ruined by debts, and supremacy of opponents and satire of the enemies.”', 1, '', '', 'Prophetic Supplications', 101),
  ('bocp_102', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ وَأَسْتَجِيرُ بِكَ مِنَ النَّارِ', 'Allāhumma innī asʾaluka''l-jannata wa astajīru bika mina''n-nār', '“O Allah! I ask from You the Paradise and I seek Your protection from the Hell-Fire.”', 1, '', '', 'Prophetic Supplications', 102),
  ('bocp_103', 'book_of_prayer', '', 'اللَّهُمَّ اغْفِرْ لِي، وَاهْدِنِي، وَارْزُقْنِي، وَعَافِنِي، وَأَعُوذُ بِكَ مِنْ ضِيقِ الْمَقَامِ يَوْمَ الْقِيَامَةِ', 'Allāhumma''ghfir lī, wa''hdinī, wa''rzuqnī, wa ʿāfinī, wa aʿūdhu bika min ḍīqi''l-maqāmi yawma''l-qiyāmah', '“O Allah! Forgive me, guide me, provide me ample livelihood, and protect me (from evil); and I ask refuge with You against tightness of situation in the Day of Resurrection.”', 1, '', '', 'Prophetic Supplications', 103),
  ('bocp_104', 'book_of_prayer', '', 'اللَّهُمَّ مَتِّعْنِي بِسَمْعِي وَبَصَرِي، وَاجْعَلْهُمَا الْوَارِثَ مِنِّي، وَانْصُرْنِي عَلَى مَنْ يَظْلِمُنِي وَخُذْ بِثَأْرِي', 'Allāhumma mattiʿnī bi-samʿī wa baṣarī, wa''jʿalhuma''l-wāritha minnī, wa''nṣurnī ʿalā man yaẓlimunī wa khudh bi-thaʾrī', '“O Allah! Let my hearing and seeing be beneficial to me and make the two (my hearing and seeing) permanent for me; and help me against anyone who deceives me and You take from him my rights.”', 1, '', '', 'Prophetic Supplications', 104),
  ('bocp_105', 'book_of_prayer', '', 'اللَّهُمَّ لَكَ الْحَمْدُ لَا إِلَٰهَ إِلَّا أَنْتَ، أَنْتَ الْمَنَّانُ بَدِيعُ السَّمَاوَاتِ وَالْأَرْضِ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ يَا حَيُّ يَا قَيُّومُ', 'Allāhumma laka''l-ḥamdu lā ilāha illā ant, anta''l-mannānu badīʿu''s-samāwāti wa''l-arḍ yā dha''l-jalāli wa''l-ikrām yā ḥayyu yā qayyūm', '“O Allah! Yours are all Praises, none has the right to be worshipped but You. You are the Most Beneficent, the Originator of the Heavens and the Earth, O You full of Majesty and Honor, O You the Ever-Living and the Everlasting.”', 1, '', '', 'Prophetic Supplications', 105),
  ('bocp_106', 'book_of_prayer', '', 'اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ قَيِّمُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ، وَلَكَ الْحَمْدُ لَكَ مُلْكُ السَّمَاوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ، وَلَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ، وَلَكَ الْحَمْدُ أَنْتَ مَلِكُ السَّمَاوَاتِ وَالْأَرْضِ، وَلَكَ الْحَمْدُ أَنْتَ الْحَقُّ، وَوَعْدُكَ الْحَقُّ، وَلِقَاؤُكَ حَقٌّ، وَقَوْلُكَ حَقٌّ، وَالْجَنَّةُ حَقٌّ، وَالنَّارُ حَقٌّ، وَالنَّبِيُّونَ حَقٌّ، وَمُحَمَّدٌ حَقٌّ، وَالسَّاعَةُ حَقٌّ', 'Allāhumma laka''l-ḥamdu anta qayyimu''s-samāwāti wa''l-arḍi wa man fīhinn, wa laka''l-ḥamdu laka mulku''s-samāwāti wa''l-arḍi wa man fīhinn, wa laka''l-ḥamdu anta nūru''s-samāwāti wa''l-arḍi wa man fīhinn, wa laka''l-ḥamdu anta maliku''s-samāwāti wa''l-arḍ, wa laka''l-ḥamdu anta''l-ḥaqq, wa waʿduka''l-ḥaqq, wa liqāʾuka ḥaqq, wa qawluka ḥaqq, wa''l-jannatu ḥaqq, wa''n-nāru ḥaqq, wa''n-nabiyyūna ḥaqq, wa Muḥammadun ḥaqq, wa''s-sāʿatu ḥaqq', '“O Allah! Yours are all Praises, You are the One Who sustain and protect the Heavens and the Earth and all that exist in them. Yours are all Praises, Yours is the dominion of the Heavens and the Earth and all that exist in them. Yours are all Praises, You are the Light of the Heavens and the Earth and all that exist in them. Yours are all Praises, You are the Sovereign of the Heavens and the Earth and all that exist in them. And Yours all the Praises, You are the Truth, Your promises are True, meeting with You is certain, Your Word (the Qur''an) is Truth, the Jannah (Paradise) is Truth, the Hell-Fire is Truth, the Prophets are Truth, Mohammad (pbuh) is Truth, and the Hour (the Final Day) is Truth.”', 1, '', '', 'Prophetic Supplications', 106),
  ('bocp_107', 'book_of_prayer', '', 'اللَّهُمَّ لَكَ أَسْلَمْتُ، وَبِكَ آمَنْتُ، وَعَلَيْكَ تَوَكَّلْتُ، وَإِلَيْكَ أَنَبْتُ، وَبِكَ خَاصَمْتُ وَإِلَيْكَ حَاكَمْتُ، فَاغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ، أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لَا إِلَٰهَ إِلَّا أَنْتَ، وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ', 'Allāhumma laka aslamtu, wa bika āmantu, wa ʿalayka tawakkaltu, wa ilayka anabtu, wa bika khāṣamtu wa ilayka ḥākamtu, fa''ghfir lī mā qaddamtu wa mā akhkhartu wa mā asrartu wa mā aʿlantu, anta''l-muqaddimu wa anta''l-muʾakhkhiru lā ilāha illā ant, wa lā ḥawla wa lā quwwata illā bi''llāh', '“O Allah! I submit myself to You, and I believe in You, and I depend on You, and I repent to You and return to You, and to You I leave the judgment (for those who refuse the message), and to You I submit for judgment. Forgive me (O Allah) for what I did earlier and what I did later, and what I did secretly and what I did openly. You Alone can make one progress or draw backward. None has the right to be worshipped but You. And there is no power and no strength except with Allah.”', 1, '', '', 'Prophetic Supplications', 107),
  ('bocp_108', 'book_of_prayer', '', 'اللَّهُمَّ اهْدِنِي فِيمَنْ هَدَيْتَ، وَعَافِنِي فِيمَنْ عَافَيْتَ، وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ، وَبَارِكْ لِي فِيمَا أَعْطَيْتَ، وَقِنِي شَرَّ مَا قَضَيْتَ فَإِنَّكَ تَقْضِي وَلَا يُقْضَى عَلَيْكَ، وَإِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ، تَبَارَكْتَ رَبَّنَا وَتَعَالَيْتَ', 'Allāhumma''hdinī fīman hadayt, wa ʿāfinī fīman ʿāfayt, wa tawallanī fīman tawallayt, wa bārik lī fīmā aʿṭayt, wa qinī sharra mā qaḍayt fa-innaka taqḍī wa lā yuqḍā ʿalayk, wa innahu lā yadhillu man wālayt, tabārakta rabbanā wa taʿālayt', '“O Allah! Guide me (to the right Path) with those who You have guided, and make me healthy (strong) with those whom You have given good health (strength), place me under Your care among those whom You have taken care of, bless for me whatever You have provided, protect me from the evil things which You have decreed for indeed You rule and none can rule You, whoever You keep under Your Care none can humiliate. You are the Blessed, our Lord, and You are the Exalted.”', 1, '', '', 'Prophetic Supplications', 108),
  ('bocp_109', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ خَيْرِ مَا سَأَلَكَ مِنْهُ عَبْدُكَ وَنَبِيُّكَ مُحَمَّدٌ وَعِبَادُكَ الصَّالِحُونَ، وَأَعُوذُ بِكَ مِنْ شَرِّ مَا اسْتَعَاذَ مِنْهُ عَبْدُكَ وَنَبِيُّكَ مُحَمَّدٌ وَعِبَادُكَ الصَّالِحُونَ', 'Allāhumma innī asʾaluka min khayri mā saʾalaka minhu ʿabduka wa nabiyyuka Muḥammadun wa ʿibāduka''ṣ-ṣāliḥūn, wa aʿūdhu bika min sharri ma''staʿādha minhu ʿabduka wa nabiyyuka Muḥammadun wa ʿibāduka''ṣ-ṣāliḥūn', '“O Allah! I ask from You the best which had been sought by Your slave and Prophet Muhammad (pbuh) and Your righteous servants. And I ask refuge with You against the evil of all such things from which protection had been sought by Your slave and Prophet Muhammad (pbuh) and Your righteous servants.”', 1, '', '', 'Prophetic Supplications', 109),
  ('bocp_110', 'book_of_prayer', '', 'اللَّهُمَّ أَنْتَ رَبِّي، لَا إِلَٰهَ إِلَّا أَنْتَ خَلَقْتَنِي وَأَنَا عَبْدُكَ، وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ، أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ، أَبُوءُ لَكَ بِنِعْمَتِكَ عَلَيَّ، وَأَبُوءُ بِذَنْبِي فَاغْفِرْ لِي فَإِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ', 'Allāhumma anta rabbī, lā ilāha illā anta khalaqtanī wa anā ʿabduk, wa anā ʿalā ʿahdika wa waʿdika ma''staṭaʿt, aʿūdhu bika min sharri mā ṣanaʿt, abūʾu laka bi-niʿmatika ʿalayy, wa abūʾu bi-dhanbī fa''ghfir lī fa-innahu lā yaghfiru''dh-dhunūba illā ant', '“O Allah! You are my Lord, none has the right to be worshipped except You, You created me and I am Your servant and I abide to Your covenant and promise as best I can, I take refuge in You from the evil of which I committed. I acknowledge Your favor upon me and I acknowledge my sin, so forgive me, for verily none can forgive sin except You.”', 1, '', '', 'Prophetic Supplications', 110),
  ('bocp_111', 'book_of_prayer', '', 'اللَّهُمَّ اكْفِنَا شَرَّ الْأَشْرَارِ وَكَيْدَ الْفُجَّارِ، وَشَرَّ كُلِّ طَارِقٍ يَطْرُقُ إِلَّا طَارِقًا يَطْرُقُ بِخَيْرٍ يَا عَزِيزُ يَا غَفَّارُ', 'Allāhumma''kfinā sharra''l-ashrāri wa kayda''l-fujjār, wa sharra kulli ṭāriqin yaṭruqu illā ṭāriqan yaṭruqu bi-khayrin yā ʿazīzu yā ghaffār', '“O Allah! Prevent us from the evil of all bad things, and from the craftiness of immoral people and from evil of the entire night visitor that comes except those who came for good (O Allah). O the All-Mighty, O the Oft-Forgiving.”', 1, '', '', 'Prophetic Supplications', 111),
  ('bocp_112', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ أَنْ تُبَارِكَ فِي سَمْعِي، وَفِي بَصَرِي، وَفِي خَلْقِي، وَفِي خُلُقِي، وَفِي أَهْلِي، وَفِي مَحْيَايَ، وَفِي عَمَلِي، وَتَقَبَّلْ حَسَنَاتِي، وَأَسْأَلُكَ الدَّرَجَاتِ الْعُلَى مِنَ الْجَنَّةِ', 'Allāhumma innī asʾaluka an tubārika fī samʿī, wa fī baṣarī, wa fī khalqī, wa fī khuluqī, wa fī ahlī, wa fī maḥyāy, wa fī ʿamalī, wa taqabbal ḥasanātī, wa asʾaluka''d-darajāti''l-ʿulā mina''l-jannah', '“O Allah! I ask from You bless my hearing, and my seeing, and myself, and my family, and my living, and my deeds, and accept my best (deeds), and I seek from You the highest level of Paradise.”', 1, '', '', 'Prophetic Supplications', 112),
  ('bocp_113', 'book_of_prayer', '', 'اللَّهُمَّ اغْفِرْ لِي ذَنْبِي كُلَّهُ: دِقَّهُ وَجِلَّهُ، وَأَوَّلَهُ وَآخِرَهُ، وَعَلَانِيَتَهُ وَسِرَّهُ', 'Allāhumma''ghfir lī dhanbī kullah: diqqahu wa jillah, wa awwalahu wa ākhirah, wa ʿalāniyatahu wa sirrah', '“O Allah! Forgive all my sins: the smallest and the greatest of which, the first and last of which, and both that are openly and secretly committed.”', 1, '', '', 'Prophetic Supplications', 113),
  ('bocp_114', 'book_of_prayer', '', 'اللَّهُمَّ لَكَ الْحَمْدُ كُلُّهُ، اللَّهُمَّ لَا قَابِضَ لِمَا بَسَطْتَ، وَلَا بَاسِطَ لِمَا قَبَضْتَ، وَلَا هَادِيَ لِمَنْ أَضْلَلْتَ، وَلَا مُضِلَّ لِمَنْ هَدَيْتَ، وَلَا مُعْطِيَ لِمَا مَنَعْتَ، وَلَا مَانِعَ لِمَا أَعْطَيْتَ، وَلَا مُقَرِّبَ لِمَا بَاعَدْتَ، وَلَا مُبَاعِدَ لِمَا قَرَّبْتَ، اللَّهُمَّ ابْسُطْ عَلَيْنَا مِنْ بَرَكَاتِكَ وَرَحْمَتِكَ وَفَضْلِكَ وَرِزْقِكَ، اللَّهُمَّ إِنِّي أَسْأَلُكَ النَّعِيمَ الْمُقِيمَ الَّذِي لَا يَحُولُ وَلَا يَزُولُ، اللَّهُمَّ إِنِّي أَسْأَلُكَ النَّعِيمَ يَوْمَ الْعَيْلَةِ، وَالْأَمْنَ يَوْمَ الْخَوْفِ، اللَّهُمَّ إِنِّي عَائِذٌ بِكَ مِنْ شَرِّ مَا أَعْطَيْتَنَا، وَشَرِّ مَا مَنَعْتَ، اللَّهُمَّ حَبِّبْ إِلَيْنَا الْإِيمَانَ وَزَيِّنْهُ فِي قُلُوبِنَا، وَكَرِّهْ إِلَيْنَا الْكُفْرَ وَالْفُسُوقَ وَالْعِصْيَانَ وَاجْعَلْنَا مِنَ الرَّاشِدِينَ، اللَّهُمَّ تَوَفَّنَا مُسْلِمِينَ، وَأَحْيِنَا مُسْلِمِينَ وَأَلْحِقْنَا بِالصَّالِحِينَ غَيْرَ خَزَايَا وَلَا مَفْتُونِينَ، اللَّهُمَّ قَاتِلِ الْكَفَرَةَ الَّذِينَ يُكَذِّبُونَ رُسُلَكَ، وَيَصُدُّونَ عَنْ سَبِيلِكَ وَاجْعَلْ عَلَيْهِمْ رِجْزَكَ وَعَذَابَكَ، اللَّهُمَّ قَاتِلِ الْكَفَرَةَ الَّذِينَ أُوتُوا الْكِتَابَ إِلَٰهَ الْحَقِّ', 'Allāhumma laka''l-ḥamdu kulluh, Allāhumma lā qābiḍa limā basaṭt, wa lā bāsiṭa limā qabaḍt, wa lā hādiya liman aḍlalt, wa lā muḍilla liman hadayt, wa lā muʿṭiya limā manaʿt, wa lā māniʿa limā aʿṭayt, wa lā muqarriba limā bāʿadt, wa lā mubāʿida limā qarrabt, Allāhumma''bsuṭ ʿalaynā min barakātika wa raḥmatika wa faḍlika wa rizqik, Allāhumma innī asʾaluka''n-naʿīma''l-muqīma''lladhī lā yaḥūlu wa lā yazūl, Allāhumma innī asʾaluka''n-naʿīma yawma''l-ʿaylah, wa''l-amna yawma''l-khawf, Allāhumma innī ʿāʾidhun bika min sharri mā aʿṭaytanā, wa sharri mā manaʿt, Allāhumma ḥabbib ilayna''l-īmāna wa zayyinhu fī qulūbinā, wa karrih ilayna''l-kufra wa''l-fusūqa wa''l-ʿiṣyāna wa''jʿalnā mina''r-rāshidīn, Allāhumma tawaffanā muslimīn, wa aḥyinā muslimīn wa alḥiqnā bi''ṣ-ṣāliḥīna ghayra khazāyā wa lā maftūnīn, Allāhumma qātili''l-kafarata''lladhīna yukadhdhibūna rusulak, wa yaṣuddūna ʿan sabīlika wa''jʿal ʿalayhim rijzaka wa ʿadhābak, Allāhumma qātili''l-kafarata''lladhīna ūtu''l-kitāba ilāha''l-ḥaqq', '“O Allah! All Praises are due to You (Alone). O Allah! None can take hold unless with Your help, and no extensor for anyone You deny of (help), and no guidance for anyone You cause to go astray, and none can misguide those whom You have guided, none can give those You deny of any assistance, and none can object to whomever You want to give Your help, none can bring near of whom You cause to be far away, and none can bring away of anyone You cause to be near (to You). O Allah! Provide us Your blessings, Your mercy, Your grace, and subsistence. O Allah! I seek from You steady blessings. O Allah! I ask from You favor on the day of hardships, security in the day of fear. O Allah! I seek Your protection against the evil of what You have given us and the evil of all things which You have denied us (to have). O Allah! Let us love the Faith (in You) and let it be accepted by our hearts. Let us dislike the unbelief, immorality and rebellion, and make us among the righteous. O Allah! Take our life as Muslim and let us live as Muslim and make us among Your righteous servants without difficulties and trials. O Allah! Defeat the Kuffar who deny Your Messenger, who prevent the propagation of Your Way; and inflict upon them Your punishment. O Allah! Defeat the Kuffar in whose hands are the books, Lord of Truth. (Ameen)”', 1, '', '', 'Prophetic Supplications', 114),
  ('bocp_115', 'book_of_prayer', '', 'اللَّهُمَّ اغْفِرْ لِي، وَارْحَمْنِي، وَاهْدِنِي، وَعَافِنِي، وَارْزُقْنِي، وَاجْبُرْنِي، وَارْفَعْنِي', 'Allāhumma''ghfir lī, wa''rḥamnī, wa''hdinī, wa ʿāfinī, wa''rzuqnī, wa''jburnī, wa''rfaʿnī', '“O Allah! Forgive me, have Mercy on me, guide me, provide good health and livelihood, comfort and elevate my reputation.”', 1, '', '', 'Prophetic Supplications', 115),
  ('bocp_116', 'book_of_prayer', '', 'اللَّهُمَّ زِدْنَا وَلَا تُنْقِصْنَا، وَأَكْرِمْنَا وَلَا تُهِنَّا، وَأَعْطِنَا وَلَا تُحْرِمْنَا، وَآثِرْنَا وَلَا تُؤْثِرْ عَلَيْنَا، وَأَرْضِنَا وَارْضَ عَنَّا', 'Allāhumma zidnā wa lā tunqiṣnā, wa akrimnā wa lā tuhinnā, wa aʿṭinā wa lā taḥrimnā, wa āthirnā wa lā tuʾthir ʿalaynā, wa arḍinā wa''rḍa ʿannā', '“O Allah! Increase upon us Your favor and do not decrease it, Be Kind on us and do not dislike us, give us (provisions) and do not disown us, let us be the first and let no one before us, and love You and You love us.”', 1, '', '', 'Prophetic Supplications', 116),
  ('bocp_117', 'book_of_prayer', '', 'اللَّهُمَّ كَمَا أَحْسَنْتَ خَلْقِي، فَأَحْسِنْ خُلُقِي', 'Allāhumma kamā aḥsanta khalqī, fa-aḥsin khuluqī', '“O Allah! Like as You have created us from the best of mould, make our best our behavior.”', 1, '', '', 'Prophetic Supplications', 117),
  ('bocp_118', 'book_of_prayer', '', 'اللَّهُمَّ ثَبِّتْنِي، وَاجْعَلْنِي هَادِيًا مَهْدِيًّا', 'Allāhumma thabbitnī, wa''jʿalnī hādiyan mahdiyyan', '“O Allah! Let me firmed in my belief, make me guide and be guided to the right Path.”', 1, '', '', 'Prophetic Supplications', 118),
  ('bocp_119', 'book_of_prayer', '', 'اللَّهُمَّ آتِنِي الْحِكْمَةَ الَّتِي مَنْ أُوتِيَهَا فَقَدْ أُوتِيَ خَيْرًا كَثِيرًا', 'Allāhumma ātini''l-ḥikmata''llatī man ūtiyahā faqad ūtiya khayran kathīran', '“O Allah! Provide me wisdom, whom You provided with wisdom surely had multitude of good.”', 1, '', '', 'Prophetic Supplications', 119),
  ('bocp_120', 'book_of_prayer', '', 'بِسْمِ اللَّهِ الَّذِي لَا يَضُرُّ مَعَ اسْمِهِ شَيْءٌ فِي الْأَرْضِ وَلَا فِي السَّمَاءِ وَهُوَ السَّمِيعُ الْعَلِيمُ', 'Bismi''llāhi''lladhī lā yaḍurru maʿa''smihi shayʾun fi''l-arḍi wa lā fi''s-samāʾ, wa huwa''s-samīʿu''l-ʿalīm', '“In the Name of Allah, Who with His Name nothing will get harm on Earth and in the Heavens, He is the All-Hearer, the All-Knower.”', 1, '', '', 'Prophetic Supplications', 120),
  ('bocp_121', 'book_of_prayer', '', 'بِسْمِ اللَّهِ ذِي الشَّأْنِ، عَظِيمِ السُّلْطَانِ، شَدِيدِ الْبُرْهَانِ، قَوِيِّ الْأَرْكَانِ، مَا شَاءَ اللَّهُ كَانَ، أَعُوذُ بِاللَّهِ مِنْ كُلِّ شَيْطَانٍ؛ إِنْسٍ وَجَانٍّ', 'Bismi''llāhi dhi''sh-shaʾn, ʿaẓīmi''s-sulṭān, shadīdi''l-burhān, qawiyyi''l-arkān, mā shāʾa''llāhu kān, aʿūdhu bi''llāhi min kulli shayṭān; insin wa jānn', '“In the Name of Allah, the Most Powerful, with the Great Power (and Authority), with powerful Evidence, with Solid Pillars, whatever He likes happens. I seek refuge with Allah against all Shaytan (Satan) whether it is man or jinn.”', 1, '', '', 'Prophetic Supplications', 121),
  ('bocp_122', 'book_of_prayer', '', 'أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ', 'Aʿūdhu bi-kalimāti''llāhi''t-tāmmāti min sharri mā khalaq', '“I seek refuge with the complete Word of Allah against the evil of His creatures.”', 1, '', '', 'Morning & Evening Remembrance', 122),
  ('bocp_123', 'book_of_prayer', '', 'أَعُوذُ بِوَجْهِ اللَّهِ الْعَظِيمِ، الَّذِي لَيْسَ شَيْءٌ أَعْظَمُ مِنْهُ، وَبِكَلِمَاتِ اللَّهِ التَّامَّاتِ الَّتِي لَا يُجَاوِزُهُنَّ بَرٌّ وَلَا فَاجِرٌ، مِنْ شَرِّ مَا خَلَقَ وَذَرَأَ وَبَرَأَ، وَمِنْ شَرِّ مَا يَنْزِلُ مِنَ السَّمَاءِ وَمَا يَعْرُجُ فِيهَا، وَمِنْ شَرِّ مَا يَلِجُ فِي الْأَرْضِ وَمَا يَخْرُجُ مِنْهَا، وَمِنْ شَرِّ طَوَارِقِ اللَّيْلِ وَالنَّهَارِ إِلَّا طَارِقًا يَطْرُقُ بِخَيْرٍ يَا رَحْمَانُ', 'Aʿūdhu bi-wajhi''llāhi''l-ʿaẓīm, alladhī laysa shayʾun aʿẓamu minh, wa bi-kalimāti''llāhi''t-tāmmāti''llatī lā yujāwizuhunna barrun wa lā fājir, min sharri mā khalaqa wa dharaʾa wa baraʾ, wa min sharri mā yanzilu mina''s-samāʾi wa mā yaʿruju fīhā, wa min sharri mā yaliju fi''l-arḍi wa mā yakhruju minhā, wa min sharri ṭawāriqi''l-layli wa''n-nahāri illā ṭāriqan yaṭruqu bi-khayrin yā raḥmān', '“I seek refuge by the Greatness of Allah''s Face, Who has nothing greater than Him, and the Complete Word of Allah which no good and bad man can overcome; against the evil of creatures, and what He has scattered and created; and from the evil of what descends from the Heavens and what ascends into it, and from the evil of what enters the Earth and what comes out from it; and from the evil of the night and day comers except those who come for good. O Merciful.”', 1, '', '', 'Morning & Evening Remembrance', 123),
  ('bocp_124', 'book_of_prayer', '', 'أَصْبَحْنَا وَأَصْبَحَ الْمُلْكُ لِلَّهِ الْوَاحِدِ الْقَهَّارِ، وَالْحَمْدُ لِلَّهِ', 'Aṣbaḥnā wa aṣbaḥa''l-mulku li''llāhi''l-wāḥidi''l-qahhār, wa''l-ḥamdu li''llāh', '“We have reached the morning and at this very time unto Allah belongs all sovereignty, the One and Only, the Most Powerful. And all Praises are due to Allah.”', 1, '', '', 'Morning & Evening Remembrance', 124),
  ('bocp_125', 'book_of_prayer', '', 'لَا إِلَٰهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ، وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ', 'Lā ilāha illa''llāhu waḥdahu lā sharīka lah, lahu''l-mulku wa lahu''l-ḥamd, wa huwa ʿalā kulli shayʾin qadīr', '“None has the right to be worshipped but Allah, Alone without partner, to Him belongs all sovereignty and praise and He is over all things Omnipotent.”', 1, '', '', 'Morning & Evening Remembrance', 125),
  ('bocp_126', 'book_of_prayer', '', 'رَبِّ أَعُوذُ بِكَ مِنَ الْكَسَلِ وَالْهَرَمِ وَسُوءِ الْكِبَرِ، وَمِنْ فِتْنَةِ الدُّنْيَا وَعَذَابِ الْقَبْرِ', 'Rabbi aʿūdhu bika mina''l-kasali wa''l-harami wa sūʾi''l-kibar, wa min fitnati''d-dunyā wa ʿadhābi''l-qabr', '“O Lord! I ask refuge with You from laziness, cowardice, and decrepitude and the evil of becoming too old, and from the trials of this World and the torment in the grave.”', 1, '', '', 'Morning & Evening Remembrance', 126),
  ('bocp_127', 'book_of_prayer', '', 'أَصْبَحْنَا وَأَصْبَحَ الْمُلْكُ لِلَّهِ رَبِّ الْعَالَمِينَ', 'Aṣbaḥnā wa aṣbaḥa''l-mulku li''llāhi rabbi''l-ʿālamīn', '“We have reached the morning and at this very time unto Allah belongs all sovereignty, the Lord of the Worlds.”', 1, '', '', 'Morning & Evening Remembrance', 127),
  ('bocp_128', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ خَيْرَ هَذَا الْيَوْمِ: فَتْحَهُ، وَنَصْرَهُ، وَنُورَهُ، وَبَرَكَتَهُ، وَهُدَاهُ، وَأَعُوذُ بِكَ مِنْ شَرِّ مَا بَعْدَهُ', 'Allāhumma innī asʾaluka khayra hādha''l-yawm: fatḥahu, wa naṣrahu, wa nūrahu, wa barakatahu, wa hudāhu, wa aʿūdhu bika min sharri mā baʿdahu', '“O Allah! I ask You the best of this day: its success and victory, and its light, blessing, and guidance. And I ask refuge with You against the evil after it.”', 1, '', '', 'Morning & Evening Remembrance', 128),
  ('bocp_129', 'book_of_prayer', '', 'اللَّهُمَّ بِكَ أَصْبَحْنَا وَبِكَ أَمْسَيْنَا، وَبِكَ نَحْيَا وَبِكَ نَمُوتُ، وَإِلَيْكَ النُّشُورُ، أَصْبَحْنَا وَأَصْبَحَ الْمُلْكُ لِلَّهِ، وَالْحَمْدُ لِلَّهِ لَا شَرِيكَ لَهُ، لَا إِلَٰهَ إِلَّا هُوَ إِلَيْهِ النُّشُورُ', 'Allāhumma bika aṣbaḥnā wa bika amsaynā, wa bika naḥyā wa bika namūt, wa ilayka''n-nushūr, aṣbaḥnā wa aṣbaḥa''l-mulku li''llāh, wa''l-ḥamdu li''llāhi lā sharīka lah, lā ilāha illā huwa ilayhi''n-nushūr', '“O Allah! By Your leave we have reached the morning and by Your leave we have reached the evening, by Your leave we live and die and unto You is our resurrection. We have reached the morning and at this very time unto Allah belongs all sovereignty, and all Praises are due to Allah, He has no partner, none has the right to be worshipped but He, and unto Him is our resurrection.”', 1, '', '', 'Morning & Evening Remembrance', 129),
  ('bocp_130', 'book_of_prayer', '', 'اللَّهُمَّ فَاطِرَ السَّمَاوَاتِ وَالْأَرْضِ، عَالِمَ الْغَيْبِ وَالشَّهَادَةِ، رَبَّ كُلِّ شَيْءٍ وَمَلِيكَهُ، أَشْهَدُ أَنْ لَا إِلَٰهَ إِلَّا أَنْتَ، أَعُوذُ بِكَ مِنْ شَرِّ نَفْسِي، وَمِنْ شَرِّ الشَّيْطَانِ وَشِرْكِهِ، وَأَنْ أَقْتَرِفَ عَلَى نَفْسِي سُوءًا أَوْ أَجُرَّهُ إِلَى مُسْلِمٍ', 'Allāhumma fāṭira''s-samāwāti wa''l-arḍ, ʿālima''l-ghaybi wa''sh-shahādah, rabba kulli shayʾin wa malīkah, ashhadu an lā ilāha illā ant, aʿūdhu bika min sharri nafsī, wa min sharri''sh-shayṭāni wa shirkih, wa an aqtarifa ʿalā nafsī sūʾan aw ajurrahu ilā muslim', '“O Allah! The Creator of Heavens and the Earth, the All-Knower of the unseen and the seen, Lord and Owner of all things; I bear witness that none has the right to be worshipped but You. I ask refuge with You from the evil of myself, and from the evil of Shaytan (Satan) and his associating of other with Allah, and from the errors committed against my soul and with the expense of fellow Muslim.”', 1, '', '', 'Morning & Evening Remembrance', 130),
  ('bocp_131', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَصْبَحْتُ أُشْهِدُكَ، وَأُشْهِدُ حَمَلَةَ عَرْشِكَ، وَمَلَائِكَتَكَ، وَجَمِيعَ خَلْقِكَ، أَنَّكَ أَنْتَ اللَّهُ، لَا إِلَٰهَ إِلَّا أَنْتَ وَحْدَكَ لَا شَرِيكَ لَكَ، وَأَنَّ مُحَمَّدًا عَبْدُكَ وَرَسُولُكَ', 'Allāhumma innī aṣbaḥtu ush-hiduka, wa ush-hidu ḥamalata ʿarshik, wa malāʾikatak, wa jamīʿa khalqik, annaka anta''llāh, lā ilāha illā anta waḥdaka lā sharīka lak, wa anna Muḥammadan ʿabduka wa rasūluk', '“O Allah! Verily I have reached the morning and call on You, the bearers of Your Throne, Your angels, and all Your creation to witness that You are Allah, none has the right to be worshipped but You, Alone, without partner and that Muhammad is Your servant and Messenger.”', 1, '', '', 'Morning & Evening Remembrance', 131),
  ('bocp_132', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَفْوَ وَالْعَافِيَةَ فِي: دِينِي، وَدُنْيَايَ، وَأَهْلِي، وَمَالِي', 'Allāhumma innī asʾaluka''l-ʿafwa wa''l-ʿāfiyata fī: dīnī, wa dunyāy, wa ahlī, wa mālī', '“O Allah! I seek from You forgiveness and health regarding my Faith, my world, my family and my possessions.”', 1, '', '', 'Morning & Evening Remembrance', 132),
  ('bocp_133', 'book_of_prayer', '', 'اللَّهُمَّ اسْتُرْ عَوْرَاتِي، وَآمِنْ رَوْعَاتِي، اللَّهُمَّ احْفَظْنِي مِنْ بَيْنِ يَدَيَّ وَمِنْ خَلْفِي، وَعَنْ يَمِينِي وَعَنْ شِمَالِي وَمِنْ فَوْقِي، وَأَعُوذُ بِعَظَمَتِكَ أَنْ أُغْتَالَ مِنْ تَحْتِي', 'Allāhumma''stur ʿawrātī, wa āmin rawʿātī, Allāhumma''ḥfaẓnī min bayni yadayya wa min khalfī, wa ʿan yamīnī wa ʿan shimālī wa min fawqī, wa aʿūdhu bi-ʿaẓamatika an ughtāla min taḥtī', '“O Allah! Cover up my defects and save me from fear. Protect me from my right and from my left, and from above and from before me and from behind me. I seek refuge with You by Your Greatness lest I may be murdered from beneath me.”', 1, '', '', 'Morning & Evening Remembrance', 133),
  ('bocp_134', 'book_of_prayer', '', 'رَضِيتُ بِاللَّهِ رَبًّا، وَبِالْإِسْلَامِ دِينًا، وَبِمُحَمَّدٍ نَبِيًّا وَرَسُولًا', 'Raḍītu bi''llāhi rabban, wa bi''l-islāmi dīnan, wa bi-Muḥammadin nabiyyan wa rasūlan', '“I am pleased that (You) O Allah is my Lord, and Islam is my religion, and Muhammad (pbuh) is my Prophet and Messenger (of Allah).”', 1, '', '', 'Morning & Evening Remembrance', 134),
  ('bocp_135', 'book_of_prayer', '', 'اللَّهُمَّ مَا أَصْبَحَ بِي مِنْ نِعْمَةٍ أَوْ بِأَحَدٍ مِنْ خَلْقِكَ، فَمِنْكَ وَحْدَكَ لَا شَرِيكَ لَكَ، فَلَكَ الْحَمْدُ وَلَكَ الشُّكْرُ', 'Allāhumma mā aṣbaḥa bī min niʿmatin aw bi-aḥadin min khalqik, fa-minka waḥdaka lā sharīka lak, fa-laka''l-ḥamdu wa laka''sh-shukr', '“O Allah! What blessing I or any of Your creation have risen up, is from You alone, without partner, so for You is all praise and unto You all thanks.”', 1, '', '', 'Morning & Evening Remembrance', 135),
  ('bocp_136', 'book_of_prayer', '', 'اللَّهُمَّ عَافِنِي فِي بَدَنِي، اللَّهُمَّ عَافِنِي فِي سَمْعِي، اللَّهُمَّ عَافِنِي فِي بَصَرِي لَا إِلَٰهَ إِلَّا أَنْتَ', 'Allāhumma ʿāfinī fī badanī, Allāhumma ʿāfinī fī samʿī, Allāhumma ʿāfinī fī baṣarī lā ilāha illā ant', '“O Allah! Make healthy my body. O Allah! Make healthy my hearing. O Allah! Make healthy my sight. None has the right to be worshipped but You.”', 1, '', '', 'Morning & Evening Remembrance', 136),
  ('bocp_137', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْكُفْرِ وَالْفَقْرِ، وَمِنْ عَذَابِ الْقَبْرِ، لَا إِلَٰهَ إِلَّا أَنْتَ', 'Allāhumma innī aʿūdhu bika mina''l-kufri wa''l-faqr, wa min ʿadhābi''l-qabr, lā ilāha illā ant', '“O Allah! I ask refuge with You from disbelief, and poverty, and from the torment in the grave, none has the right to be worshipped but You. (3x)”', 1, '', '', 'Morning & Evening Remembrance', 137),
  ('bocp_138', 'book_of_prayer', '', 'سُبْحَانَ اللَّهِ وَبِحَمْدِهِ لَا قُوَّةَ إِلَّا بِاللَّهِ، مَا شَاءَ اللَّهُ كَانَ، وَمَا لَمْ يَشَأْ لَمْ يَكُنْ، أَعْلَمُ أَنَّ اللَّهَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ، وَأَنَّ اللَّهَ قَدْ أَحَاطَ بِكُلِّ شَيْءٍ عِلْمًا', 'Subḥāna''llāhi wa bi-ḥamdih, lā quwwata illā bi''llāh, mā shāʾa''llāhu kān, wa mā lam yashaʾ lam yakun, aʿlamu anna''llāha ʿalā kulli shayʾin qadīr, wa anna''llāha qad aḥāṭa bi-kulli shayʾin ʿilman', '“All Glory to Allah and all praise to Him, no power except with Allah, whatever Allah wanted happens and whatever He does not want never happens, know that Allah has power over all things, and that Allah surrounds all things in (His) Knowledge.”', 1, '', '', 'Morning & Evening Remembrance', 138),
  ('bocp_139', 'book_of_prayer', '', 'أَصْبَحْنَا عَلَى فِطْرَةِ الْإِسْلَامِ، وَكَلِمَةِ الْإِخْلَاصِ، وَدِينِ نَبِيِّنَا مُحَمَّدٍ، وَعَلَى مِلَّةِ أَبِينَا إِبْرَاهِيمَ، حَنِيفًا مُسْلِمًا وَمَا كَانَ مِنَ الْمُشْرِكِينَ', 'Aṣbaḥnā ʿalā fiṭrati''l-islām, wa kalimati''l-ikhlāṣ, wa dīni nabiyyinā Muḥammad, wa ʿalā millati abīnā Ibrāhīm, ḥanīfan musliman wa mā kāna mina''l-mushrikīn', '“We rise upon the Fitrah (nature) of Islam, and the word of pure faith and upon the religion of our Prophet Muhammad (pbuh) and the religion of our forefather Ibrahim (Abraham), who was a Muslim and of true faith and was not of those associate others with Allah.”', 1, '', '', 'Morning & Evening Remembrance', 139),
  ('bocp_140', 'book_of_prayer', '', 'يَا حَيُّ يَا قَيُّومُ، يَا بَدِيعَ السَّمَوَاتِ وَالْأَرْضِ، يَا ذَا الْجَلَالِ وَالْإِكْرَامِ، لَا إِلَٰهَ إِلَّا أَنْتَ، بِرَحْمَتِكَ أَسْتَغِيثُ، أَصْلِحْ لِي شَأْنِي وَلَا تَكِلْنِي إِلَى نَفْسِي طَرْفَةَ عَيْنٍ', 'Yā ḥayyu yā qayyūm, yā badīʿa''s-samāwāti wa''l-arḍ, yā dha''l-jalāli wa''l-ikrām, lā ilāha illā ant, bi-raḥmatika astaghīth, aṣliḥ lī shaʾnī wa lā takilnī ilā nafsī ṭarfata ʿayn', '“O Ever Living, O Everlasting, O the Originator of Heavens and the Earth, O Full of Majesty and Honor; none has the right to be worshipped but You; by Your Mercy I ask Your help to set right all my deeds and do not entrust to me my affairs even in a wink of an eye.”', 1, '', '', 'Morning & Evening Remembrance', 140),
  ('bocp_141', 'book_of_prayer', '', 'اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَٰهَ إِلَّا أَنْتَ، خَلَقْتَنِي وَأَنَا عَبْدُكَ، وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ، أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ، أَبُوءُ لَكَ بِنِعْمَتِكَ عَلَيَّ وَأَبُوءُ بِذَنْبِي، فَاغْفِرْ لِي، إِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ', 'Allāhumma anta rabbī lā ilāha illā ant, khalaqtanī wa anā ʿabduk, wa anā ʿalā ʿahdika wa waʿdika ma''staṭaʿt, aʿūdhu bika min sharri mā ṣanaʿt, abūʾu laka bi-niʿmatika ʿalayya wa abūʾu bi-dhanbī, fa''ghfir lī, innahu lā yaghfiru''dh-dhunūba illā ant', '“O Allah! You are my Lord, none has the right to be worshipped except You, You created me and I am Your servant and I abide to Your covenant and promise as best I can, I take refuge in You from the evil of which I committed. I acknowledge Your favor upon me and I acknowledge my sin, so forgive me, for verily none can forgive sin except You.”', 1, '', '', 'Morning & Evening Remembrance', 141),
  ('bocp_142', 'book_of_prayer', '', 'اللَّهُمَّ أَنْتَ أَحَقُّ مَنْ ذُكِرَ، وَأَحَقُّ مَنْ عُبِدَ، وَأَنْصَرُ مَنِ ابْتُغِيَ، وَأَرْأَفُ مَنْ مَلَكَ، وَأَجْوَدُ مَنْ سُئِلَ، وَأَوْسَعُ مَنْ أَعْطَى، أَنْتَ الْمَلِكُ لَا شَرِيكَ لَكَ، وَالْفَرْدُ الَّذِي لَا نِدَّ لَكَ، كُلُّ شَيْءٍ هَالِكٌ إِلَّا وَجْهَكَ، لَنْ تُطَاعَ إِلَّا بِإِذْنِكَ، وَلَنْ تُعْصَى إِلَّا بِعِلْمِكَ، تُطَاعُ فَتَشْكُرُ وَتُعْصَى فَتَغْفِرُ، أَقْرَبُ شَهِيدٍ وَأَدْنَى حَفِيظٍ، حُلْتَ دُونَ النُّفُوسِ وَأَخَذْتَ بِالنَّوَاصِي، وَكَتَبْتَ الْآثَارَ وَنَسَخْتَ الْآجَالَ، الْقُلُوبُ لَكَ مُفْضِيَةٌ وَالسِّرُّ عِنْدَكَ عَلَانِيَةٌ، الْحَلَالُ مَا أَحْلَلْتَ، وَالْحَرَامُ مَا حَرَّمْتَ، وَالدِّينُ مَا شَرَعْتَ، وَالْخَلْقُ خَلْقُكَ وَالْعَبْدُ عَبْدُكَ، وَأَنْتَ اللَّهُ الرَّؤُوفُ الرَّحِيمُ، أَسْأَلُكَ بِنُورِ وَجْهِكَ الَّذِي أَشْرَقَتْ لَهُ السَّمَاوَاتُ وَالْأَرْضُ، أَنْ تَقْبَلَنِي فِي هَذِهِ الْغَدَاةِ وَأَنْ تُجِيرَنِي مِنَ النَّارِ بِقُدْرَتِكَ', 'Allāhumma anta aḥaqqu man dhukir, wa aḥaqqu man ʿubid, wa anṣaru mani''btughiy, wa arʾafu man malak, wa ajwadu man suʾil, wa awsaʿu man aʿṭā, anta''l-maliku lā sharīka lak, wa''l-fardu''lladhī lā nidda lak, kullu shayʾin hālikun illā wajhak, lan tuṭāʿa illā bi-idhnik, wa lan tuʿṣā illā bi-ʿilmik, tuṭāʿu fa-tashkur wa tuʿṣā fa-taghfir, aqrabu shahīdin wa adnā ḥafīẓ, ḥulta dūna''n-nufūsi wa akhadhta bi''n-nawāṣī, wa katabta''l-āthāra wa nasakhta''l-ājāl, al-qulūbu laka mufḍiyatun wa''s-sirru ʿindaka ʿalāniyah, al-ḥalālu mā aḥlalt, wa''l-ḥarāmu mā ḥarramt, wa''d-dīnu mā sharaʿt, wa''l-khalqu khalquka wa''l-ʿabdu ʿabduk, wa anta''llāhu''r-raʾūfu''r-raḥīm, asʾaluka bi-nūri wajhika''lladhī ashraqat lahu''s-samāwātu wa''l-arḍ, an taqbalanī fī hādhihi''l-ghadāti wa an tujīranī mina''n-nāri bi-qudratik', '“O Allah! You Alone deserve remembering and worshiping, and You Alone can help us against the disbelievers, and You are Merciful to Your servants, and Most Kind to whoever invokes Him, and Has the Power to provide; You are the Lord and has no partner, and the One and Only without the like, everyone will taste death except Allah, none will obey except by His will, and none will disobey except He knows; His servants obey and He is thankful, and disobey but He forgives. I ask You by the light of Your Face by which the heavens and earth are illumined, to accept me this morning and to protect me from the Fire by Your Power.”', 1, '', '', 'Morning & Evening Remembrance', 142),
  ('bocp_143', 'book_of_prayer', '', 'حَسْبِيَ اللَّهُ لَا إِلَٰهَ إِلَّا هُوَ عَلَيْهِ تَوَكَّلْتُ وَهُوَ رَبُّ الْعَرْشِ الْعَظِيمِ', 'Ḥasbiya''llāhu lā ilāha illā huwa ʿalayhi tawakkaltu wa huwa rabbu''l-ʿarshi''l-ʿaẓīm', '“Allah is Sufficient for me, none has the right to be worshipped except Him, upon Him I rely and He is Lord of the Exalted Throne.”', 1, '', '', 'Morning & Evening Remembrance', 143),
  ('bocp_144', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْهَمِّ وَالْحَزَنِ، وَأَعُوذُ بِكَ مِنَ الْعَجْزِ وَالْكَسَلِ، وَمِنَ الْبُخْلِ وَالْجُبْنِ، وَأَعُوذُ بِكَ مِنْ غَلَبَةِ الدَّيْنِ وَقَهْرِ الرِّجَالِ', 'Allāhumma innī aʿūdhu bika mina''l-hammi wa''l-ḥazan, wa aʿūdhu bika mina''l-ʿajzi wa''l-kasal, wa mina''l-bukhli wa''l-jubn, wa aʿūdhu bika min ghalabati''d-dayni wa qahri''r-rijāl', '“O Allah! I ask refuge with You against worry, sorrow, helplessness; and I ask refuge with against laziness, cowardice, and from miserliness, and I ask refuge with You from debt and the burden of indebtedness and overpowering of men.”', 1, '', '', 'Morning & Evening Remembrance', 144),
  ('bocp_145', 'book_of_prayer', '', 'أَصْبَحْنَا وَأَصْبَحَ الْمُلْكُ لِلَّهِ، وَالْكِبْرِيَاءُ وَالْعَظَمَةُ وَالْخَلْقُ وَالْأَمْرُ، وَاللَّيْلُ وَالنَّهَارُ وَمَا يَضَحَّى فِيهِمَا لِلَّهِ وَحْدَهُ', 'Aṣbaḥnā wa aṣbaḥa''l-mulku li''llāh, wa''l-kibriyāʾu wa''l-ʿaẓamatu wa''l-khalqu wa''l-amr, wa''l-laylu wa''n-nahāru wa mā yaḍaḥḥā fīhimā li''llāhi waḥdah', '“We have reached the morning and at this very time all sovereignty belongs to Allah, the Glory, the Greatness, the Creation, the Order, the night and the day all belong to Allah, the Only One.”', 1, '', '', 'Morning & Evening Remembrance', 145),
  ('bocp_146', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْ أَوَّلَ هَذَا الْيَوْمِ صَلَاحًا، وَأَوْسَطَهُ فَلَاحًا، وَآخِرَهُ نَجَاحًا، أَسْأَلُكَ خَيْرَيِ الدُّنْيَا وَالْآخِرَةِ يَا أَرْحَمَ الرَّاحِمِينَ', 'Allāhumma''jʿal awwala hādha''l-yawmi ṣalāḥan, wa awsaṭahu falāḥan, wa ākhirahu najāḥan, asʾaluka khayrayi''d-dunyā wa''l-ākhirah yā arḥama''r-rāḥimīn', '“O Allah! Make the first of this day rightness, the middle prosperity, and the last (part) a success; I ask You the best of this World and the Hereafter, O You Most Merciful of those who show mercy.”', 1, '', '', 'Further Supplications', 146),
  ('bocp_147', 'book_of_prayer', '', 'اللَّهُمَّ فَاطِرَ السَّمَوَاتِ عَالِمَ الْغَيْبِ وَالشَّهَادَةِ ذَا الْجَلَالِ وَالْإِكْرَامِ، إِنِّي أَعْهَدُ إِلَيْكَ فِي هَذِهِ الْحَيَاةِ الدُّنْيَا وَأُشْهِدُكَ وَكَفَى بِكَ شَهِيدًا: أَنِّي أَشْهَدُ أَنْ لَا إِلَٰهَ إِلَّا أَنْتَ وَحْدَكَ لَا شَرِيكَ لَكَ، وَأَنَّ مُحَمَّدًا عَبْدُكَ وَرَسُولُكَ، وَأَشْهَدُ أَنَّ وَعْدَكَ حَقٌّ، وَلِقَاءَكَ حَقٌّ، وَالْجَنَّةَ وَالنَّارَ حَقٌّ، وَأَنَّ السَّاعَةَ آتِيَةٌ لَا رَيْبَ فِيهَا، وَأَنَّكَ تَبْعَثُ مَنْ فِي الْقُبُورِ، وَأَنَّكَ إِنْ تَكِلْنِي إِلَى نَفْسِي، تَكِلْنِي إِلَى ضَعْفٍ وَعَوْرَةٍ وَذَنْبٍ وَخَطِيئَةٍ، وَإِنِّي لَا أَثِقُ إِلَّا بِرَحْمَتِكَ، فَاغْفِرْ لِي ذُنُوبِي كُلَّهَا وَثُبْ عَلَيَّ، إِنَّكَ أَنْتَ التَّوَّابُ الرَّحِيمُ', 'Allāhumma fāṭira''s-samāwāti ʿālima''l-ghaybi wa''sh-shahādati dha''l-jalāli wa''l-ikrām, innī aʿhadu ilayka fī hādhihi''l-ḥayāti''d-dunyā wa ush-hiduka wa kafā bika shahīdā: annī ash-hadu an lā ilāha illā anta waḥdaka lā sharīka lak, wa anna Muḥammadan ʿabduka wa rasūluk, wa ash-hadu anna waʿdaka ḥaqq, wa liqāʾaka ḥaqq, wa''l-jannata wa''n-nāra ḥaqq, wa anna''s-sāʿata ātiyatun lā rayba fīhā, wa annaka tabʿathu man fi''l-qubūr, wa annaka in takilnī ilā nafsī, takilnī ilā ḍaʿfin wa ʿawratin wa dhanbin wa khaṭīʾah, wa innī lā athiqu illā bi-raḥmatik, fa''ghfir lī dhunūbī kullahā wa thub ʿalayy, innaka anta''t-tawwābu''r-raḥīm', '“O Allah! Creator of the heavens, Knower of the unseen and the seen, Possessor of Majesty and Honor; I promise You here in this World and let You witness, and You are Sufficient as a Witness: that I bear witness that none has the right to be worshipped but You, You are One and You have no partner; and indeed Muhammad is Your slave and Messenger; and I bear witness that Your Promise is True, the Meeting with You (in the Day of Judgment) is True, and the Paradise and the Hell-Fire are True, and the Hour will come without doubt, and verily You will resurrect those in their graves; and verily, if You leave me to myself I will be left to weakness, deficiency, sin and error; and I trust none except Your Mercy, so forgive all my sins, and accept my repentance; verily, You are the One Who accepts repentance, the Most Merciful.”', 1, '', '', 'Further Supplications', 147),
  ('bocp_148', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ', 'Allāhumma innī aʿūdhu bika min an uradda ilā ardhali''l-ʿumur', '“O Allah! I seek refuge with You from being sent back to geriatric old age.”', 1, '', '', 'Further Supplications', 148),
  ('bocp_149', 'book_of_prayer', '', 'اللَّهُمَّ اهْدِنِي لِأَحْسَنِ الْأَعْمَالِ، وَالْأَخْلَاقِ، لَا يَهْدِي لِأَحْسَنِهَا إِلَّا أَنْتَ، وَاصْرِفْ عَنِّي سَيِّئَهَا، لَا يَصْرِفُ عَنِّي سَيِّئَهَا إِلَّا أَنْتَ', 'Allāhumma''hdinī li-aḥsani''l-aʿmāl, wa''l-akhlāq, lā yahdī li-aḥsanihā illā ant, wa''ṣrif ʿannī sayyiʾahā, lā yaṣrifu ʿannī sayyiʾahā illā ant', '“O Allah! Guide me to do the best deeds and ethics, none can guide me to it except You; and save me from its evil and none can save from it except You.”', 1, '', '', 'Further Supplications', 149),
  ('bocp_150', 'book_of_prayer', '', 'اللَّهُمَّ أَصْلِحْ لِي دِينِي، وَوَسِّعْ لِي فِي دَارِي، وَبَارِكْ لِي فِي رِزْقِي', 'Allāhumma aṣliḥ lī dīnī, wa wassiʿ lī fī dārī, wa bārik lī fī rizqī', '“O Allah! Set aright my Faith, widen my dwelling and bless me my livelihood.”', 1, '', '', 'Further Supplications', 150),
  ('bocp_151', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْقَسْوَةِ وَالْغَفْلَةِ، وَالذُّلَّةِ وَالْمَسْكَنَةِ، وَأَعُوذُ بِكَ مِنَ الْكُفْرِ وَالْفُسُوقِ وَالشِّقَاقِ، وَالسُّمْعَةِ وَالرِّيَاءِ، وَأَعُوذُ بِكَ مِنَ الصَّمَمِ وَالْبَكَمِ وَالْجُذَامِ وَسَيِّئِ الْأَسْقَامِ', 'Allāhumma innī aʿūdhu bika mina''l-qaswati wa''l-ghaflah, wa''dh-dhullati wa''l-maskanah, wa aʿūdhu bika mina''l-kufri wa''l-fusūqi wa''sh-shiqāq, wa''s-sumʿati wa''r-riyāʾ, wa aʿūdhu bika mina''ṣ-ṣamami wa''l-bakami wa''l-judhāmi wa sayyiʾi''l-asqām', '“O Allah! I seek refuge with You from cruelty, and forgetfulness, and humiliation, and misery; and I seek refuge with You from disbelief, and immorality, and rebellion, grandstanding and showiness; and I seek refuge with You against deafness, dumbness, insanity, leprosy, paralysis and other foul diseases.”', 1, '', '', 'Further Supplications', 151),
  ('bocp_152', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْهَدْمِ وَالتَّرَدِّي، وَمِنَ الْغَرَقِ وَالْحَرَقِ وَالْهَرَمِ، وَأَعُوذُ بِكَ مِنْ أَنْ يَتَخَبَّطَنِيَ الشَّيْطَانُ عِنْدَ الْمَوْتِ، وَأَعُوذُ بِكَ مِنْ أَنْ أَمُوتَ لَدِيغًا، وَأَعُوذُ بِكَ مِنْ طَمَعٍ يَهْدِي إِلَى طَبَعٍ', 'Allāhumma innī aʿūdhu bika mina''l-hadmi wa''t-taraddī, wa mina''l-gharaqi wa''l-ḥaraqi wa''l-haram, wa aʿūdhu bika min an yatakhabbaṭaniya''sh-shayṭānu ʿinda''l-mawt, wa aʿūdhu bika min an amūta ladīghan, wa aʿūdhu bika min ṭamaʿin yahdī ilā ṭabaʿin', '“O Allah! I ask refuge with You from destruction, and deterioration, and sinking, and burning and decrepitude; I ask refuge with You from being overcome by the Shaitan (Satan) during my death, I ask refuge with You from death by venom; and I seek refuge with You from greediness that guide to malignant heart.”', 1, '', '', 'Further Supplications', 152),
  ('bocp_153', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ الثَّبَاتَ فِي الْأَمْرِ، وَالْعَزِيمَةَ عَلَى الرُّشْدِ، وَأَسْأَلُكَ شُكْرَ نِعْمَتِكَ وَحُسْنَ عِبَادَتِكَ، وَأَسْأَلُكَ قَلْبًا سَلِيمًا وَلِسَانًا صَادِقًا، وَأَسْأَلُكَ مِنْ خَيْرِ مَا تَعْلَمُ وَأَعُوذُ بِكَ مِنْ شَرِّ مَا تَعْلَمُ، وَأَسْتَغْفِرُكَ مِمَّا تَعْلَمُ، وَأَنْتَ عَلَّامُ الْغُيُوبِ', 'Allāhumma innī asʾaluka''th-thabāta fi''l-amr, wa''l-ʿazīmata ʿala''r-rushd, wa asʾaluka shukra niʿmatika wa ḥusna ʿibādatik, wa asʾaluka qalban salīman wa lisānan ṣādiqan, wa asʾaluka min khayri mā taʿlamu wa aʿūdhu bika min sharri mā taʿlam, wa astaghfiruka mimmā taʿlam, wa anta ʿallāmu''l-ghuyūb', '“O Allah! I seek from You firmness in all matters, and steadfastness on the right path. I seek from You strength to thank You for Your graces and to worship You properly. I seek from You a rightly guided heart, a truthful tongue. I seek from You the best which You know, I seek refuge with You against any such evils which You know. I seek forgiveness for the sins which You know. Verily, You know the unseen.”', 1, '', '', 'Further Supplications', 153),
  ('bocp_154', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: فِعْلَ الْخَيْرَاتِ وَتَرْكَ الْمُنْكَرَاتِ وَحُبَّ الْمَسَاكِينِ، وَأَنْ تَغْفِرَ لِي وَتَرْحَمَنِي، وَإِذَا أَرَدْتَ بِعِبَادِكَ فِتْنَةً فَتَوَفَّنِي إِلَيْكَ غَيْرَ مَفْتُونٍ', 'Allāhumma innī asʾaluka: fiʿla''l-khayrāti wa tarka''l-munkarāti wa ḥubba''l-masākīn, wa an taghfira lī wa tarḥamanī, wa idhā aradta bi-ʿibādika fitnatan fatawaffanī ilayka ghayra maftūn', '“O Allah! I ask You to let me do the good deeds and leave the forbidden ones, and love the poor, and forgive me and have mercy on me; if You want destruction for Your servants, (please) take my life (in order) not to be included with them.”', 1, '', '', 'Further Supplications', 154),
  ('bocp_155', 'book_of_prayer', '', 'اللَّهُمَّ حَبِّبْنِي إِلَيْكَ وَإِلَى مَلَائِكَتِكَ وَأَنْبِيَائِكَ وَجَمِيعِ خَلْقِكَ', 'Allāhumma ḥabbibnī ilayka wa ilā malāʾikatika wa anbiyāʾika wa jamīʿi khalqik', '“O Allah! Provide me Your Love, and of the Angels, and of Your Prophets, and of all Your creatures.”', 1, '', '', 'Further Supplications', 155),
  ('bocp_156', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْ حُبَّكَ أَحَبَّ إِلَيَّ مِنْ نَفْسِي وَأَهْلِي وَمَالِي وَوَلَدِي وَمِنَ الْمَاءِ الْبَارِدِ عَلَى الظَّمَأِ', 'Allāhumma''jʿal ḥubbaka aḥabba ilayya min nafsī wa ahlī wa mālī wa waladī wa mina''l-māʾi''l-bāridi ʿala''ẓ-ẓamaʾ', '“O Allah! Make my love to You more than my love to myself, family, wealth, and child and more than the cold water in times of thirst.”', 1, '', '', 'Further Supplications', 156),
  ('bocp_157', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْ خَيْرَ عُمُرِي آخِرَهُ، وَخَيْرَ عَمَلِي خَوَاتِمَهُ، وَخَيْرَ أَيَّامِي يَوْمَ لِقَائِكَ', 'Allāhumma''jʿal khayra ʿumurī ākhirah, wa khayra ʿamalī khawātimah, wa khayra ayyāmī yawma liqāʾik', '“O Allah! Make best the last (part) of my life, and the best of my deeds are the final ones, and the best of my days is the day I meet You.”', 1, '', '', 'Further Supplications', 157),
  ('bocp_158', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ عِيشَةً نَقِيَّةً، وَمِيتَةً سَوِيَّةً، وَمَرَدًّا غَيْرَ مَخْذُولٍ وَلَا فَاضِحٍ', 'Allāhumma innī asʾaluka ʿīshatan naqiyyah, wa mītatan sawiyyah, wa maraddan ghayra makhdhūlin wa lā fāḍiḥ', '“O Allah! I seek from You clean living, and peaceful death, and a return (to You) that is neither disgraceful nor humiliating.”', 1, '', '', 'Further Supplications', 158),
  ('bocp_159', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنِي صَبُورًا وَاجْعَلْنِي شَكُورًا، وَاجْعَلْنِي فِي عَيْنِي صَغِيرًا وَفِي أَعْيُنِ النَّاسِ كَبِيرًا، رَبِّ اغْفِرْ وَارْحَمْ وَاهْدِنِي السَّبِيلَ الْأَقْوَمَ', 'Allāhumma''jʿalnī ṣabūran wa''jʿalnī shakūran, wa''jʿalnī fī ʿaynī ṣaghīran wa fī aʿyuni''n-nāsi kabīran, rabbi''ghfir wa''rḥam wa''hdini''s-sabīla''l-aqwam', '“O Allah! Make me patient, and make me grateful, and make me small in my own eyes while big in the eyes of the people; O Lord! Forgive me, and have mercy on me, and guide me to the Right Path.”', 1, '', '', 'Further Supplications', 159),
  ('bocp_160', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: خَيْرَ الْمَسْأَلَةِ، وَخَيْرَ الدُّعَاءِ، وَخَيْرَ النَّجَاحِ، وَخَيْرَ الثَّوَابِ، وَثَبِّتْنِي وَثَقِّلْ مَوَازِينِي وَحَقِّقْ إِيمَانِي، وَارْفَعْ دَرَجَتِي وَتَقَبَّلْ صَلَاتِي وَاغْفِرْ خَطِيئَاتِي، وَأَسْأَلُكَ الدَّرَجَاتِ الْعُلَى مِنَ الْجَنَّةِ، آمِينَ', 'Allāhumma innī asʾaluka: khayra''l-masʾalah, wa khayra''d-duʿāʾ, wa khayra''n-najāḥ, wa khayra''th-thawāb, wa thabbitnī wa thaqqil mawāzīnī wa ḥaqqiq īmānī, wa''rfaʿ darajatī wa taqabbal ṣalātī wa''ghfir khaṭīʾātī, wa asʾaluka''d-darajāti''l-ʿulā mina''l-jannah, āmīn', '“O Allah! I seek from You the best request, and the best supplication, and the best victory, and the best reward, and make me firm, and make heavy the weight of my good deeds, and strengthen my Faith, and elevate my rank, and accept my salah (prayer), and forgive my errors, and I seek from You the highest level of Paradise; Amen.”', 1, '', '', 'Further Supplications', 160),
  ('bocp_161', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: فَوَاتِحَ الْخَيْرِ وَخَوَاتِمَهُ وَجَوَامِعَهُ، وَأَوَّلَهُ وَآخِرَهُ، وَظَاهِرَهُ وَبَاطِنَهُ، وَالدَّرَجَاتِ الْعُلَى مِنَ الْجَنَّةِ، آمِينَ', 'Allāhumma innī asʾaluka: fawātiḥa''l-khayri wa khawātimahu wa jawāmiʿah, wa awwalahu wa ākhirah, wa ẓāhirahu wa bāṭinah, wa''d-darajāti''l-ʿulā mina''l-jannah, āmīn', '“O Allah! I seek from You the opening of the door of good for me, its closing and its totality, and its first and last, and the apparent and the secret of which, and the highest level of Paradise. Amen.”', 1, '', '', 'Further Supplications', 161),
  ('bocp_162', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: خَيْرَ مَا آتِي، وَخَيْرَ مَا أَفْعَلُ، وَخَيْرَ مَا بَطَنَ وَخَيْرَ مَا ظَهَرَ، وَأَسْأَلُكَ الدَّرَجَاتِ الْعُلَى مِنَ الْجَنَّةِ. آمِينَ', 'Allāhumma innī asʾaluka: khayra mā ātī, wa khayra mā afʿal, wa khayra mā baṭana wa khayra mā ẓahar, wa asʾaluka''d-darajāti''l-ʿulā mina''l-jannah. āmīn', '“O Allah! I seek from You the best that has to come, and best of what I have done, and the best from the hidden and the apparent, and I seek from You the highest level of Paradise. Amen.”', 1, '', '', 'Further Supplications', 162),
  ('bocp_163', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: أَنْ تَرْفَعَ ذِكْرِي، وَتَضَعَ وِزْرِي، وَتُطَهِّرَ قَلْبِي، وَتُحَصِّنَ فَرْجِي، وَتَغْفِرَ لِي ذَنْبِي، وَأَسْأَلُكَ الدَّرَجَاتِ الْعُلَى مِنَ الْجَنَّةِ. آمِينَ', 'Allāhumma innī asʾaluka: an tarfaʿa dhikrī, wa taḍaʿa wizrī, wa tuṭahhira qalbī, wa tuḥaṣṣina farjī, wa taghfira lī dhanbī, wa asʾaluka''d-darajāti''l-ʿulā mina''l-jannah. āmīn', '“O Allah! I seek from You to elevate my mention, and take away my sin, and purify my heart, and keep chaste my private part, and forgive me my sins, and grant me the highest level of Paradise.”', 1, '', '', 'Further Supplications', 163),
  ('bocp_164', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: أَنْ تُبَارِكَ لِي فِي سَمْعِي وَفِي بَصَرِي، وَفِي رُوحِي وَفِي خَلْقِي، وَفِي أَهْلِي وَفِي مَحْيَايَ وَفِي عَمَلِي، وَتَقَبَّلْ حَسَنَاتِي، وَأَسْأَلُكَ الدَّرَجَاتِ الْعُلَى مِنَ الْجَنَّةِ. آمِينَ', 'Allāhumma innī asʾaluka: an tubārika lī fī samʿī wa fī baṣarī, wa fī rūḥī wa fī khalqī, wa fī ahlī wa fī maḥyāya wa fī ʿamalī, wa taqabbal ḥasanātī, wa asʾaluka''d-darajāti''l-ʿulā mina''l-jannah. āmīn', '“O Allah! I ask from You to bless my hearing, and my seeing, and my soul, and myself, and my family, and my living, and my deeds, and accept my best (deeds), and I seek from You the highest level of Paradise. Amen.”', 1, '', '', 'Further Supplications', 164),
  ('bocp_165', 'book_of_prayer', '', 'اللَّهُمَّ اغْفِرْ لَنَا وَارْحَمْنَا وَارْضَ عَنَّا، وَتَقَبَّلْ مِنَّا، وَأَدْخِلْنَا الْجَنَّةَ وَنَجِّنَا مِنَ النَّارِ، وَأَصْلِحْ لَنَا شَأْنَنَا كُلَّهُ', 'Allāhumma''ghfir lanā wa''rḥamnā wa''rḍa ʿannā, wa taqabbal minnā, wa adkhilna''l-jannata wa najjinā mina''n-nār, wa aṣliḥ lanā shaʾnanā kullah', '“O Allah! Forgive us, and have mercy on us, and be pleased with us, and accept for us (our deeds), and admit us in Your Paradise, and save us from the Fire, and set aright for us all our undertakings.”', 1, '', '', 'Further Supplications', 165),
  ('bocp_166', 'book_of_prayer', '', 'اللَّهُمَّ لَا تَدَعْ لَنَا ذَنْبًا إِلَّا غَفَرْتَهُ، وَلَا عَيْبًا إِلَّا سَتَرْتَهُ، وَلَا هَمًّا إِلَّا فَرَّجْتَهُ، وَلَا دَيْنًا إِلَّا قَضَيْتَهُ، وَلَا حَاجَةً مِنْ حَوَائِجِ الدُّنْيَا وَالْآخِرَةِ هِيَ لَكَ رِضًا وَلَنَا صَلَاحٌ، إِلَّا قَضَيْتَهَا يَا أَرْحَمَ الرَّاحِمِينَ', 'Allāhumma lā tadaʿ lanā dhanban illā ghafartah, wa lā ʿayban illā satartah, wa lā hamman illā farrajtah, wa lā daynan illā qaḍaytah, wa lā ḥājatan min ḥawāʾiji''d-dunyā wa''l-ākhirati hiya laka riḍan wa lanā ṣalāḥun, illā qaḍaytahā yā arḥama''r-rāḥimīn', '“O Allah! Please do not leave for us a sin unless You forgive it, nor a fault unless You cover it, nor a worry unless You remove it, nor a debt unless You pay it, nor any need from the needs of this World and the Hereafter in which is Your pleasure and our betterment, unless You fulfill it, O Most Merciful of those who show mercy.”', 1, '', '', 'Further Supplications', 166),
  ('bocp_167', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ رَحْمَةً مِنْ عِنْدِكَ، تَهْدِي بِهَا قَلْبِي، وَتَجْمَعُ بِهَا أَمْرِي، وَتَلُمُّ بِهَا شَعْثِي، وَتَحْفَظُ بِهَا غَائِبِي، وَتَرْفَعُ بِهَا شَاهِدِي، وَتُبَيِّضُ بِهَا وَجْهِي، وَتُزَكِّي بِهَا عَمَلِي، وَتُلْهِمُنِي بِهَا رُشْدِي، وَتَرُدُّ بِهَا أُلْفَتِي، وَتَعْصِمُنِي بِهَا مِنْ كُلِّ سُوءٍ', 'Allāhumma innī asʾaluka raḥmatan min ʿindik, tahdī bihā qalbī, wa tajmaʿu bihā amrī, wa talummu bihā shaʿthī, wa taḥfaẓu bihā ghāʾibī, wa tarfaʿu bihā shāhidī, wa tubayyiḍu bihā wajhī, wa tuzakkī bihā ʿamalī, wa tulhimunī bihā rushdī, wa taruddu bihā ulfatī, wa taʿṣimunī bihā min kulli sūʾ', '“O Allah! I seek from You Mercy to guide my heart, and to set aright my deeds, and to sum up my successes, and to protect my secrets, and to elevate my standing, and to whiten my face, and to purify my deeds, and to direct me to the best of affairs, and to restore my affection, and to save me from all evils.”', 1, '', '', 'Further Supplications', 167),
  ('bocp_168', 'book_of_prayer', '', 'اللَّهُمَّ أَعْطِنِي إِيمَانًا صَادِقًا، وَيَقِينًا لَيْسَ بَعْدَهُ كُفْرٌ، وَرَحْمَةً أَنَالُ بِهَا شَرَفَ كَرَامَتِكَ فِي الدُّنْيَا وَالْآخِرَةِ', 'Allāhumma aʿṭinī īmānan ṣādiqan, wa yaqīnan laysa baʿdahu kufrun, wa raḥmatan anālu bihā sharafa karāmatika fi''d-dunyā wa''l-ākhirah', '“O Allah! Give me truthful Iman (belief), and certainty without uncertainty at last, and Mercy which I would receive through Your Esteem Honor here in this World and in the Hereafter.”', 1, '', '', 'Further Supplications', 168),
  ('bocp_169', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ الْفَوْزَ يَوْمَ الْقَضَاءِ وَعَيْشَ السُّعَدَاءِ وَمَنْزِلَ الشُّهَدَاءِ، وَمُرَافَقَةَ الْأَنْبِيَاءِ وَالنَّصْرَ عَلَى الْأَعْدَاءِ', 'Allāhumma innī asʾaluka''l-fawza yawma''l-qaḍāʾi wa ʿaysha''s-suʿadāʾi wa manzila''sh-shuhadāʾ, wa murāfaqata''l-anbiyāʾi wa''n-naṣra ʿala''l-aʿdāʾ', '“O Allah! I seek from You success in the Day of Judgment, and pleasant life, and be among the Shuhadaa (those who died fighting in the Way of Allah), and to be together with the Prophets, and victory against the enemies.”', 1, '', '', 'Further Supplications', 169),
  ('bocp_170', 'book_of_prayer', '', 'اللَّهُمَّ أُنْزِلُ بِكَ حَاجَتِي وَإِنْ قَصُرَ رَأْيِي وَضَعُفَ عِلْمِي وَعَمَلِي، افْتَقَرْتُ إِلَى رَحْمَتِكَ فَأَسْأَلُكَ يَا قَاضِيَ الْأُمُورِ، وَيَا شَافِيَ الصُّدُورِ كَمَا تُجِيرُ بَيْنَ الْبُحُورِ أَنْ تُجِيرَنِي مِنْ عَذَابِ السَّعِيرِ، وَمِنْ فِتْنَةِ الْقُبُورِ، وَمِنْ دَعْوَةِ الثُّبُورِ', 'Allāhumma unzilu bika ḥājatī wa in qaṣura raʾyī wa ḍaʿufa ʿilmī wa ʿamalī, iftaqartu ilā raḥmatika fa-asʾaluka yā qāḍiya''l-umūr, wa yā shāfiya''ṣ-ṣudūri kamā tujīru bayna''l-buḥūri an tujīranī min ʿadhābi''s-saʿīr, wa min fitnati''l-qubūr, wa min daʿwati''th-thubūr', '“O Allah! I entrust to You all my needs, despite the decrease of my thinking, the weakening of my knowledge and deeds, I am in dire need of Your Mercy, so provide me (Your Mercy), O You the Judge of all affairs, and O You Who cure the hearts; like as You separated the seas, please take me away from punishment of the Hell, and from the infliction in the grave, and from the cry of perdition.”', 1, '', '', 'Further Supplications', 170),
  ('bocp_171', 'book_of_prayer', '', 'اللَّهُمَّ مَا قَصُرَ عَنْهُ رَأْيِي، وَضَعُفَ عَنْهُ عَمَلِي وَعِلْمِي، وَلَمْ تَبْلُغْهُ مَسْأَلَتِي مِنْ خَيْرٍ وَعَدْتَهُ أَحَدًا مِنْ خَلْقِكَ، أَوْ خَيْرٍ أَنْتَ مُعْطِيهِ أَحَدًا مِنْ عِبَادِكَ، فَإِنِّي أَرْغَبُ إِلَيْكَ فِيهِ، وَأَسْأَلُكَ إِيَّاهُ بِرَحْمَتِكَ يَا رَبَّ الْعَالَمِينَ', 'Allāhumma mā qaṣura ʿanhu raʾyī, wa ḍaʿufa ʿanhu ʿamalī wa ʿilmī, wa lam tablughhu masʾalatī min khayrin waʿadtahu aḥadan min khalqik, aw khayrin anta muʿṭīhi aḥadan min ʿibādik, fa-innī arghabu ilayka fīh, wa asʾaluka iyyāhu bi-raḥmatika yā rabba''l-ʿālamīn', '“O Allah! Whatever my mind is short of, and of which my knowledge and deeds are weak, and my request did not reach — of the best of what You promised to one of Your servants; verily, I need it from You, and I seek it through Your Mercy, O Lord of the Worlds.”', 1, '', '', 'Further Supplications', 171),
  ('bocp_172', 'book_of_prayer', '', 'اللَّهُمَّ ذَا الْحَبْلِ الشَّدِيدِ، وَالْأَمْرِ الرَّشِيدِ أَسْأَلُكَ: الْأَمْنَ يَوْمَ الْوَعِيدِ، وَالْجَنَّةَ يَوْمَ الْخُلُودِ، مَعَ الْمُقَرَّبِينَ الشُّهُودِ، الرُّكَّعِ السُّجُودِ، الْمُوفِينَ بِالْعُهُودِ، إِنَّكَ رَحِيمٌ وَدُودٌ، تَفْعَلُ مَا تُرِيدُ', 'Allāhumma dha''l-ḥabli''sh-shadīd, wa''l-amri''r-rashīdi asʾaluk: al-amna yawma''l-waʿīd, wa''l-jannata yawma''l-khulūd, maʿa''l-muqarrabīna''sh-shuhūd, ar-rukkaʿi''s-sujūd, al-mūfīna bi''l-ʿuhūd, innaka raḥīmun wadūd, tafʿalu mā turīd', '“O Allah! With You is the strong rope and clear guidance, grant me peace in the Appointed Day, and Paradise in the Eternal Day, and be among those Nearer to You and those whom You witnessed, those who bow and prostrate for You, and those who fulfill their promises; verily, You are the Most Merciful and the Most Affectionate, You do whatever You want.”', 1, '', '', 'Further Supplications', 172),
  ('bocp_173', 'book_of_prayer', '', 'سُبْحَانَ مَنْ لَا يَنْبَغِي التَّسْبِيحُ إِلَّا لَهُ، سُبْحَانَ ذِي الْفَضْلِ وَالنِّعَمِ، سُبْحَانَ ذِي الْمَجْدِ وَالْكَرَمِ، سُبْحَانَ الَّذِي أَحْصَى كُلَّ شَيْءٍ عِلْمُهُ', 'Subḥāna man lā yanbaghi''t-tasbīḥu illā lah, subḥāna dhi''l-faḍli wa''n-niʿam, subḥāna dhi''l-majdi wa''l-karam, subḥāna''lladhī aḥṣā kulla shayʾin ʿilmuh', '“Glory be to Allah whose none has the right to be glorified but He, Glory be to Allah Who has Full Favor and Comfort, Glory be to Allah Who has Full Honor and Kindness, Glory be to Allah in Whose Knowledge everything is hidden.”', 1, '', '', 'Further Supplications', 173),
  ('bocp_174', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: الْعَفْوَ وَالْعَافِيَةَ وَالْمُعَافَاةَ الدَّائِمَةَ، فِي الدِّينِ وَالدُّنْيَا وَالْآخِرَةِ', 'Allāhumma innī asʾaluka: al-ʿafwa wa''l-ʿāfiyata wa''l-muʿāfāta''d-dāʾimah, fi''d-dīni wa''d-dunyā wa''l-ākhirah', '“O Allah! I seek from You forgiveness, and full of abundance and security in my religion and life in this World and in the Hereafter.”', 1, '', '', 'Further Supplications', 174),
  ('bocp_175', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: صِحَّةً فِي إِيمَانٍ، وَإِيمَانًا فِي حُسْنِ خُلُقٍ، وَنَجَاحًا يَتْبَعُهُ نَجَاحٌ، وَرَحْمَةً مِنْكَ وَعَافِيَةً مِنْكَ، وَمَغْفِرَةً مِنْكَ وَرِضْوَانًا', 'Allāhumma innī asʾaluka: ṣiḥḥatan fī īmān, wa īmānan fī ḥusni khuluq, wa najāḥan yatbaʿuhu najāḥ, wa raḥmatan minka wa ʿāfiyatan mink, wa maghfiratan minka wa riḍwānan', '“O Allah! I seek from You good health with iman (belief), and iman (belief) with good ethics, and success followed by success, and Mercy from You, and comfort from You, and forgiveness and favor.”', 1, '', '', 'Further Supplications', 175),
  ('bocp_176', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: الصِّحَّةَ وَالْعِفَّةَ، وَحُسْنَ الْخُلُقِ، وَالرِّضَا بِالْقَدَرِ', 'Allāhumma innī asʾaluka: aṣ-ṣiḥḥata wa''l-ʿiffah, wa ḥusna''l-khuluq, wa''r-riḍā bi''l-qadar', '“O Allah! I seek from You good health, and purity, and good ethics, and acceptance of predestination.”', 1, '', '', 'Further Supplications', 176),
  ('bocp_177', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنَا: هَادِينَ مَهْدِيِّينَ، غَيْرَ ضَالِّينَ وَلَا مُضِلِّينَ، سِلْمًا لِأَوْلِيَائِكَ، حَرْبًا لِأَعْدَائِكَ، نُحِبُّ بِحُبِّكَ مَنْ أَحَبَّكَ، وَنُعَادِي بِعَدَاوَتِكَ مَنْ عَادَاكَ', 'Allāhumma''jʿalnā: hādīna mahdiyyīn, ghayra ḍāllīna wa lā muḍillīn, silman li-awliyāʾik, ḥarban li-aʿdāʾik, nuḥibbu bi-ḥubbika man aḥabbak, wa nuʿādī bi-ʿadāwatika man ʿādāk', '“O Allah! Make us among those who are guided and guiding others, and not with those who are gone astray and misguiding others, and be secured with Your Friends, and fighting against Your enemies, and we love by Your Love whomever You Loved, and we abhor by Your abhorrence whomever You abhorred.”', 1, '', '', 'Further Supplications', 177),
  ('bocp_178', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ: مِنْ شَرِّ نَفْسِي، وَمِنْ شَرِّ كُلِّ دَابَّةٍ أَنْتَ آخِذٌ بِنَاصِيَتِهَا، إِنَّ رَبِّي عَلَى صِرَاطٍ مُسْتَقِيمٍ', 'Allāhumma innī aʿūdhu bika: min sharri nafsī, wa min sharri kulli dābbatin anta ākhidhun bi-nāṣiyatihā, inna rabbī ʿalā ṣirāṭin mustaqīm', '“O Allah! I seek refuge with You against the evils of myself, and from the evils of all creatures whose foreheads with Allah''s grasp; verily, my Lord is upon the Right Path.”', 1, '', '', 'Further Supplications', 178),
  ('bocp_179', 'book_of_prayer', '', 'اللَّهُمَّ فَارِجَ الْهَمِّ وَكَاشِفَ الْغَمِّ، مُجِيبَ دَعْوَةِ الْمُضْطَرِّينَ، رَحْمَنَ الدُّنْيَا وَالْآخِرَةِ وَرَحِيمَهُمَا، ارْحَمْنِي رَحْمَةً تُغْنِينِي بِهَا عَنْ رَحْمَةِ مَنْ سِوَاكَ', 'Allāhumma fārija''l-hammi wa kāshifa''l-ghamm, mujība daʿwati''l-muḍṭarrīn, raḥmāna''d-dunyā wa''l-ākhirati wa raḥīmahumā, irḥamnī raḥmatan tughnīnī bihā ʿan raḥmati man siwāk', '“O Allah! You are the one Who lift uncertainties, and clear the concealed, and answer the invocation of those compelled or in hardship, the Merciful in this World and in the Hereafter and Merciful to both; have enough mercy on me for me not to turn to other (than You).”', 1, '', '', 'Further Supplications', 179),
  ('bocp_180', 'book_of_prayer', '', 'أَصْبَحْنَا بِاللَّهِ الَّذِي لَيْسَ شَيْءٌ مِنْهُ مُمْتَنِعٌ، وَبِعِزَّةِ اللَّهِ لَا تُرَامُ وَلَا تُضَامُ، وَبِسُلْطَانِ اللَّهِ الْمَنِيعِ نَحْتَجِبُ، وَبِأَسْمَاءِ اللَّهِ الْحُسْنَى كُلِّهَا، عَائِذًا بِاللَّهِ مِنَ الْأَبَالِسَةِ، وَمِنْ شَرِّ شَيَاطِينِ الْإِنْسِ وَالْجِنِّ، وَمِنْ شَرِّ كُلِّ مُعْلِنٍ أَوْ مُسِرٍّ، وَمِنْ شَرِّ مَا يَكْمُنُ بِاللَّيْلِ وَيَخْرُجُ بِالنَّهَارِ، أَوْ يَكْمُنُ بِالنَّهَارِ وَيَخْرُجُ بِاللَّيْلِ، وَمِنْ شَرِّ مَا خَلَقَ وَذَرَأَ وَبَرَأَ، وَمِنْ شَرِّ إِبْلِيسَ وَجُنُودِهِ، وَمِنْ شَرِّ كُلِّ دَابَّةٍ أَنْتَ آخِذٌ بِنَاصِيَتِهَا', 'Aṣbaḥnā bi''llāhi''lladhī laysa shayʾun minhu mumtaniʿ, wa bi-ʿizzati''llāhi lā turāmu wa lā tuḍām, wa bi-sulṭāni''llāhi''l-manīʿi naḥtajib, wa bi-asmāʾi''llāhi''l-ḥusnā kullihā, ʿāʾidhan bi''llāhi mina''l-abālisah, wa min sharri shayāṭīni''l-insi wa''l-jinn, wa min sharri kulli muʿlinin aw musirr, wa min sharri mā yakmunu bi''l-layli wa yakhruju bi''n-nahār, aw yakmunu bi''n-nahāri wa yakhruju bi''l-layl, wa min sharri mā khalaqa wa dharaʾa wa baraʾ, wa min sharri iblīsa wa junūdih, wa min sharri kulli dābbatin anta ākhidhun bi-nāṣiyatihā', '“We reached the morning by Allah''s Power, and none can stop it, and with His unfading Might and with Allah''s Authority we seek refuge, and with all His Beautiful Names; against the badness of Shaitan (Satan) of men and jinn, and from the evil of whatever is known and hidden, and from the evil of the night comers and the day goers or the day comers and the night goers, and from the evil of all creatures, and from the badness of the Devil and his soldiers, and from the evils of all creatures whose foreheads are in Your Grasp.”', 1, '', '', 'Further Supplications', 180),
  ('bocp_181', 'book_of_prayer', '', 'أَعُوذُ بِاللَّهِ مِمَّا اسْتَعَاذَ بِهِ مُوسَى وَعِيسَى وَإِبْرَاهِيمُ الَّذِي وَفَّى، وَمِنْ شَرِّ مَا خَلَقَ وَذَرَأَ وَبَرَأَ، وَمِنْ شَرِّ إِبْلِيسَ وَجُنُودِهِ، وَمِنْ شَرِّ مَا يَتَّقِي', 'Aʿūdhu bi''llāhi mimma''staʿādha bihi Mūsā wa ʿĪsā wa Ibrāhīmu''lladhī waffā, wa min sharri mā khalaqa wa dharaʾa wa baraʾ, wa min sharri iblīsa wa junūdih, wa min sharri mā yattaqī', '“I seek refuge with Allah against which Musa (Moses) and ''Isa (Jesus) and Ibrahim (Abraham) — who fulfilled (his covenant) — had asked for protection, and from the evils of all that is created, made and brought forth, and from the badness of the Devil and his soldiers, and from the evil of what one guards against.”', 1, '', '', 'Further Supplications', 181),
  ('bocp_182', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ: خَيْرَ مَا عِنْدَكَ وَأَفِضْ عَلَيَّ مِنْ فَضْلِكَ، وَانْشُرْ عَلَيَّ مِنْ رَحْمَتِكَ وَأَنْزِلْ عَلَيَّ مِنْ بَرَكَاتِكَ', 'Allāhumma innī asʾaluka: khayra mā ʿindaka wa afiḍ ʿalayya min faḍlik, wa''nshur ʿalayya min raḥmatik wa anzil ʿalayya min barakātik', '“O Allah! I seek from You all the good, and grant me from Your Power and from Your Mercy, and send me down Your blessing.”', 1, '', '', 'Further Supplications', 182),
  ('bocp_183', 'book_of_prayer', '', 'اللَّهُمَّ لَكَ الْحَمْدُ كُلُّهُ، وَلَكَ الْمُلْكُ كُلُّهُ وَبِيَدِكَ الْخَيْرُ كُلُّهُ، وَإِلَيْكَ يُرْجَعُ الْأَمْرُ كُلُّهُ عَلَانِيَتُهُ وَسِرُّهُ، فَأَهْلٌ أَنْتَ أَنْ تُحْمَدَ إِنَّكَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ', 'Allāhumma laka''l-ḥamdu kulluh, wa laka''l-mulku kulluhu wa bi-yadika''l-khayru kulluh, wa ilayka yurjaʿu''l-amru kulluhu ʿalāniyatuhu wa sirruh, fa-ahlun anta an tuḥmada innaka ʿalā kulli shayʾin qadīr', '“O Allah! All Praises are belong to You, All dominions are belong to You, and all goods are in Your Hand, and to You return all the affairs, whether apparent or secret; therefore, You have the right to be praised; verily, You have Power over all things.”', 1, '', '', 'Further Supplications', 183),
  ('bocp_184', 'book_of_prayer', '', 'اللَّهُمَّ اغْفِرْ لِي جَمِيعَ مَا مَضَى مِنْ ذُنُوبِي، وَاعْصِمْنِي فِيمَا بَقِيَ مِنْ عُمُرِي، وَارْزُقْنِي عَمَلًا زَاكِيًا تُرْضَى بِهِ عَنِّي', 'Allāhumma''ghfir lī jamīʿa mā maḍā min dhunūbī, wa''ʿṣimnī fīmā baqiya min ʿumurī, wa''rzuqnī ʿamalan zākiyan turḍā bihi ʿannī', '“O Allah! Forgive all my previous sins, and safeguard the remaining part of my life, and bestow on me clean deeds that will make You pleased with me.”', 1, '', '', 'Further Supplications', 184),
  ('bocp_185', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي ضَعِيفٌ فَقَوِّنِي فِي رِضَاكَ، وَخُذْ إِلَى الْخَيْرِ بِنَاصِيَتِي، وَاجْعَلِ الْإِسْلَامَ مُنْتَهَى رَجَائِي', 'Allāhumma innī ḍaʿīfun fa-qawwinī fī riḍāk, wa khudh ila''l-khayri bi-nāṣiyatī, wa''jʿali''l-islāma muntahā rajāʾī', '“O Allah! Verily, I am weak so please strengthen me at Your Pleasure, and take my forelock to goodness, and make Islam as my final goal.”', 1, '', '', 'Further Supplications', 185),
  ('bocp_186', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي ضَعِيفٌ فَقَوِّنِي، وَإِنِّي ذَلِيلٌ فَأَعِزَّنِي، وَإِنِّي فَقِيرٌ فَأَغْنِنِي', 'Allāhumma innī ḍaʿīfun fa-qawwinī, wa innī dhalīlun fa-aʿizzanī, wa innī faqīrun fa-aghninī', '“O Allah! Verily, I am weak so please strengthen me, and I am humiliated so please elevate me, and I am poor so please enrich me.”', 1, '', '', 'Further Supplications', 186),
  ('bocp_187', 'book_of_prayer', '', 'اللَّهُمَّ قَاتِلِ الْكَفَرَةَ الَّذِينَ يُكَذِّبُونَ رُسُلَكَ، وَيَصُدُّونَ عَنْ سَبِيلِكَ، وَاجْعَلْ عَلَيْهِمْ رِجْزَكَ وَعَذَابَكَ', 'Allāhumma qātili''l-kafarata''lladhīna yukadhdhibūna rusulak, wa yaṣuddūna ʿan sabīlik, wa''jʿal ʿalayhim rijzaka wa ʿadhābak', '“O Allah! Defeat the disbelievers who deny Your Messenger, and those who prevent Your Way, and impose upon them Your castigation and punishment.”', 1, '', '', 'Further Supplications', 187),
  ('bocp_188', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ: الطَّعْنِ، وَالطَّاعُونِ، وَالْوَبَاءِ، وَعَظِيمِ الْبَلَاءِ، فِي النَّفْسِ وَالْأَهْلِ وَالْمَالِ وَالْوَلَدِ، اللَّهُ أَكْبَرُ، اللَّهُ أَكْبَرُ، اللَّهُ أَكْبَرُ مِمَّا نَخَافُ وَنَحْذَرُ، اللَّهُ أَكْبَرُ، اللَّهُ أَكْبَرُ، اللَّهُ أَكْبَرُ عَدَدَ ذُنُوبِنَا حَتَّى تُغْفَرَ', 'Allāhumma innī aʿūdhu bika min: aṭ-ṭaʿn, wa''ṭ-ṭāʿūn, wa''l-wabāʾ, wa ʿaẓīmi''l-balāʾ, fi''n-nafsi wa''l-ahli wa''l-māli wa''l-walad, Allāhu akbar, Allāhu akbar, Allāhu akbaru mimmā nakhāfu wa naḥdhar, Allāhu akbar, Allāhu akbar, Allāhu akbaru ʿadada dhunūbinā ḥattā tughfar', '“O Allah! I seek refuge with You against death by knife stab, and the plague, and cholera and communicable illnesses; and I seek refuge with You against the great trial in my self, my family, my wealth and child; Allah is the Most Great, Allah is the Most Great, Allah is the Most Great! Of which we must fear and avoid His punishment; Allah the Most Great, Allah the Most Great, Allah the Most Great, the number of our sins until they are forgiven.”', 1, '', '', 'Further Supplications', 188),
  ('bocp_189', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ: مِنَ الطَّعْنِ وَالطَّاعُونِ وَمِنْ هُجُومِ الْبَلَاءِ، وَمِنْ مَوْتِ الْفَجْأَةِ وَمِنْ سَعْرَةِ الْحُمَّى، وَمِنْ سُوءِ الْقَضَاءِ وَمِنْ شَرِّ الْبَلَاءِ، وَنَعُوذُ بِكَ مِنْ دَرَكِ الشَّقَاءِ وَشَمَاتَةِ الْأَعْدَاءِ، يَا حَيُّ يَا قَيُّومُ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ، اكْشِفْ عَنَّا الْعَذَابَ إِنَّا مُؤْمِنُونَ، اصْرِفْ عَنَّا عَذَابَ جَهَنَّمَ إِنَّ عَذَابَهَا كَانَ غَرَامًا، رَبَّنَا ظَلَمْنَا أَنْفُسَنَا وَإِنْ لَمْ تَغْفِرْ لَنَا وَتَرْحَمْنَا لَنَكُونَنَّ مِنَ الْخَاسِرِينَ بِرَحْمَتِكَ يَا رَبَّ الْعَالَمِينَ يَا اللَّهُ يَا حَافِظُ يَا اللَّهُ يَا رَافِعُ', 'Allāhumma innī aʿūdhu bika: mina''ṭ-ṭaʿni wa''ṭ-ṭāʿūni wa min hujūmi''l-balāʾ, wa min mawti''l-fajʾati wa min saʿrati''l-ḥummā, wa min sūʾi''l-qaḍāʾi wa min sharri''l-balāʾ, wa naʿūdhu bika min daraki''sh-shaqāʾi wa shamātati''l-aʿdāʾ, yā ḥayyu yā qayyūmu yā dha''l-jalāli wa''l-ikrām, ikshif ʿanna''l-ʿadhāba innā muʾminūn, iṣrif ʿannā ʿadhāba jahannama inna ʿadhābahā kāna gharāmā, rabbanā ẓalamnā anfusanā wa in lam taghfir lanā wa tarḥamnā lanakūnanna mina''l-khāsirīna bi-raḥmatika yā rabba''l-ʿālamīna yā Allāhu yā ḥāfiẓu yā Allāhu yā rāfiʿ', '“O Allah! I seek refuge with You from death by knife stab, and by cholera, and by calamities, and by sudden death, and by high fever, and by bad fate and trials; and I seek refuge with You from an evil home (Hell), and from overcoming of enemies, O Ever Living, O Everlasting, O Full of Majesty and Honor, take away from us the punishment for we are believers, protect us from the punishment of the Hell-Fire its punishment is indeed painful; Our Lord, we corrupted ourselves and if You do not forgive and have mercy on us we will be among the losers; by Your Mercy O Lord of the Worlds, O Allah, O Protector, O Allah, O the One Who raises.”', 1, '', '', 'Further Supplications', 189),
  ('bocp_190', 'book_of_prayer', '', 'اللَّهُمَّ عَجِّلْ لِأَوْلِيَائِكَ الْفَرَجَ وَالْعَافِيَةَ وَزِدْ لِي فِي حَيَاتِي، فَإِنَّكَ أَنْتَ اللَّهُ الَّذِي يَهَبُ عَيْشَ الْأَبَدِ لِأَهْلِ الْآخِرَةِ، فَهَبْ لِي عُمْرًا طَوِيلًا مَدِيدًا وَعَيْشًا مَزِيدًا فِي عَافِيَتِكَ وَرِضَاكَ؛ فَإِنَّكَ وَلِيُّ ذَلِكَ، وَالْقَادِرُ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ', 'Allāhumma ʿajjil li-awliyāʾika''l-faraja wa''l-ʿāfiyata wa zid lī fī ḥayātī, fa-innaka anta''llāhu''lladhī yahabu ʿaysha''l-abadi li-ahli''l-ākhirah, fa-hab lī ʿumran ṭawīlan madīdan wa ʿayshan mazīdan fī ʿāfiyatika wa riḍāk; fa-innaka waliyyu dhālik, wa''l-qādiru ʿalayhi fi''d-dunyā wa''l-ākhirah', '“O Allah! Please accelerate for Your Awliyaa (most pious servants) their salvation, and forgiveness, and increase for me my life, for You are Allah Who let His creatures live forever in the Final day; therefore, give me long and sustainable life with additional forgiveness and mercy, and You Alone are the Owner and the Power over these in this World and in the Hereafter.”', 1, '', '', 'Further Supplications', 190),
  ('bocp_191', 'book_of_prayer', '', 'أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ غَضَبِهِ وَأَلِيمِ عِقَابِهِ وَشَرِّ عِبَادِهِ، وَمِنْ شَرِّ هَمَزَاتِ الشَّيَاطِينِ وَأَنْ يَحْضُرُونِ', 'Aʿūdhu bi-kalimāti''llāhi''t-tāmmāti min ghaḍabihi wa alīmi ʿiqābihi wa sharri ʿibādih, wa min sharri hamazāti''sh-shayāṭīni wa an yaḥḍurūn', '“I seek refuge by the Complete Words of Allah from His Anger, and painful punishment, and from the evil of His slaves, and from the evils of the whispers and presence of Shaitan (Satan).”', 1, '', '', 'Further Supplications', 191),
  ('bocp_192', 'book_of_prayer', '', 'اللَّهُمَّ أَنْتَ تَكْشِفُ الْمَأْثَمَ وَالْمَغْرَمَ', 'Allāhumma anta takshifu''l-maʾthama wa''l-maghram', '“O Allah! You are the One Who removes sin and the debt.”', 1, '', '', 'Further Supplications', 192),
  ('bocp_193', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَشْكُو إِلَيْكَ ضَعْفَ قُوَّتِي وَقِلَّةَ حِيلَتِي، وَهَوَانِي عَلَى النَّاسِ، بِرَحْمَتِكَ يَا رَبَّ الْعَالَمِينَ، أَنْتَ رَبُّ الْمُسْتَضْعَفِينَ وَأَنْتَ رَبِّي إِلَى مَنْ تَكِلُنِي؟ إِلَى بَعِيدٍ يَتَجَهَّمُنِي أَوْ إِلَى عَدُوٍّ مَلَّكْتَهُ أَمْرِي؟ إِنْ لَمْ يَكُنْ بِكَ غَضَبٌ عَلَيَّ فَلَا أُبَالِي، وَلَكِنْ عَافِيَتُكَ أَوْسَعُ لِي، أَعُوذُ بِنُورِ وَجْهِكَ الَّذِي أَشْرَقَتْ لَهُ الظُّلُمَاتُ، وَصَلَحَ عَلَيْهِ أَمْرُ الدُّنْيَا وَالْآخِرَةِ، مِنْ أَنْ يَحِلَّ بِي سَخَطُكَ أَوْ يَنْزِلَ عَلَيَّ عَذَابُكَ، لَكَ الْعُتْبَى حَتَّى تَرْضَى، وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِكَ', 'Allāhumma innī ashkū ilayka ḍaʿfa quwwatī wa qillata ḥīlatī, wa hawānī ʿala''n-nās, bi-raḥmatika yā rabba''l-ʿālamīn, anta rabbu''l-mustaḍʿafīna wa anta rabbī ilā man takilunī? ilā baʿīdin yatajahhamunī aw ilā ʿaduwwin mallaktahu amrī? in lam yakun bika ghaḍabun ʿalayya fa-lā ubālī, wa lākin ʿāfiyatuka awsaʿu lī, aʿūdhu bi-nūri wajhika''lladhī ashraqat lahu''ẓ-ẓulumāt, wa ṣalaḥa ʿalayhi amru''d-dunyā wa''l-ākhirah, min an yaḥilla bī sakhaṭuka aw yanzila ʿalayya ʿadhābuk, laka''l-ʿutbā ḥattā tarḍā, wa lā ḥawla wa lā quwwata illā bik', '“O Allah! To You Alone I mention the weakness of my power, and smallness of my knowledge, and humiliation with the people; and by Your Mercy O Lord of the Worlds, You the Lord of the weak, and You are my Lord, to whom do You leave me? To a stranger who would scowl at me, or to an enemy You have given mastery over my affair? If You have no wrath upon me, I do not care; but Your forgiveness is far greater for me. I seek refuge in the light of Your Face by which the darknesses are lit and the affairs of this world and the Hereafter are set right, from Your wrath descending upon me or Your punishment befalling me; to You is the appeal until You are pleased, and there is no power and no strength except by You.”', 1, '', '', 'Further Supplications', 193),
  ('bocp_194', 'book_of_prayer', '', 'اللَّهُمَّ عَلِّمْنِي مَا يَنْفَعُنِي، وَانْفَعْنِي بِمَا عَلَّمْتَنِي، وَزِدْنِي عِلْمًا', 'Allāhumma ʿallimnī mā yanfaʿunī, wa''nfaʿnī bimā ʿallamtanī, wa zidnī ʿilman', '“O Allah! Please teach me all which is beneficial to me, and benefit me from what You taught me, and increase me in knowledge.”', 1, '', '', 'Further Supplications', 194),
  ('bocp_195', 'book_of_prayer', '', 'اللَّهُمَّ يَا مُعَلِّمَ إِبْرَاهِيمَ عَلِّمْنِي، وَيَا مُفَهِّمَ سُلَيْمَانَ فَهِّمْنِي', 'Allāhumma yā muʿallima Ibrāhīma ʿallimnī, wa yā mufahhima Sulaymāna fahhimnī', '“O Allah! O Teacher of Ibrahim (Abraham) please teach me, O Allah Who had let Prophet Sulaiman (Solomon) comprehend, let me understand things.”', 1, '', '', 'Further Supplications', 195),
  ('bocp_196', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْ لِي وَلِلْمُسْلِمِينَ مِنْ كُلِّ هَمٍّ فَرَجًا، وَمِنْ كُلِّ ضِيقٍ مَخْرَجًا، وَمِنْ كُلِّ بَلَاءٍ عَافِيَةً', 'Allāhumma''jʿal lī wa li''l-muslimīna min kulli hammin farajan, wa min kulli ḍīqin makhrajan, wa min kulli balāʾin ʿāfiyatan', '“O Allah! Grant me and the Muslims happiness for every sorrow; and success for every humiliation; and peace for every trial.”', 1, '', '', 'Further Supplications', 196),
  ('bocp_197', 'book_of_prayer', '', 'اللَّهُمَّ مَنْ أَرَادَ الْمُسْلِمِينَ بِسُوءٍ فَاشْغَلْهُ فِي نَفْسِهِ', 'Allāhumma man arāda''l-muslimīna bi-sūʾin fa''shghilhu fī nafsih', '“O Allah! Whoever intend bad for the Muslims please give it back to himself.”', 1, '', '', 'Further Supplications', 197),
  ('bocp_198', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّا نَدْرَأُ بِكَ فِي نُحُورِهِمْ وَنَعُوذُ بِكَ مِنْ شُرُورِهِمْ', 'Allāhumma innā nadraʾu bika fī nuḥūrihim wa naʿūdhu bika min shurūrihim', '“O Allah! We seek from You preventing them upon their necks; and we seek refuge with You against their evils.”', 1, '', '', 'Further Supplications', 198),
  ('bocp_199', 'book_of_prayer', '', 'اللَّهُمَّ اغْفِرْ لِي وَلِوَالِدَيَّ وَلِلْمُسْلِمِينَ وَالْمُسْلِمَاتِ وَالْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ الْأَحْيَاءِ مِنْهُمْ وَالْأَمْوَاتِ إِنَّكَ قَرِيبٌ مُجِيبُ الدَّعْوَاتِ رَبُّ الْعَالَمِينَ', 'Allāhumma''ghfir lī wa li-wālidayya wa li''l-muslimīna wa''l-muslimāti wa''l-muʾminīna wa''l-muʾmināti''l-aḥyāʾi minhum wa''l-amwāt, innaka qarībun mujību''d-daʿawāti rabbu''l-ʿālamīn', '“O Allah! Forgive me, and my parents, and the Muslim men and women, and the believers men and women, whether alive or dead, You are the Most Near and Hearer of invocation, the Lord of the Worlds.”', 1, '', '', 'Further Supplications', 199),
  ('bocp_200', 'book_of_prayer', '', 'اللَّهُمَّ طَهِّرْ قَلْبِي مِنَ النِّفَاقِ، وَعَمَلِي مِنَ الرِّيَاءِ، وَلِسَانِي مِنَ الْكَذِبِ، وَعَيْنِي مِنَ الْخِيَانَةِ، إِنَّكَ تَعْلَمُ خَائِنَةَ الْأَعْيُنِ وَمَا تُخْفِي الصُّدُورُ', 'Allāhumma ṭahhir qalbī mina''n-nifāq, wa ʿamalī mina''r-riyāʾ, wa lisānī mina''l-kadhib, wa ʿaynī mina''l-khiyānah, innaka taʿlamu khāʾinata''l-aʿyuni wa mā tukhfi''ṣ-ṣudūr', '“O Allah! Purify my heart from hypocrisy, and my deeds from showiness, and my tongue from lies, and my eyes from treachery; verily, You Know the treachery of the eyes and what the hearts conceal.”', 1, '', '', 'Further Supplications', 200),
  ('bocp_201', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ نَفْسًا مُطْمَئِنَّةً بِلِقَائِكَ وَتَقْنَعُ بِعَطَائِكَ وَتَرْضَى بِقَضَائِكَ', 'Allāhumma innī asʾaluka nafsan muṭmaʾinnatan bi-liqāʾika wa taqnaʿu bi-ʿaṭāʾika wa tarḍā bi-qaḍāʾik', '“O Allah! I seek from You a self which is calm by the time I meet You, and content with Your gift, and pleased with the fate which You predestined.”', 1, '', '', 'Further Supplications', 201),
  ('bocp_202', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّكَ تَعْلَمُ سِرِّي وَعَلَانِيَتِي فَاقْبَلْ مَعْذِرَتِي، وَتَعْلَمُ حَاجَتِي فَأَعْطِنِي سُؤْلِي', 'Allāhumma innaka taʿlamu sirrī wa ʿalāniyatī fa''qbal maʿdhiratī, wa taʿlamu ḥājatī fa-aʿṭinī suʾlī', '“O Allah! Verily, You Know the secrets and the apparent, so please accept my apology; and You Know my need, so please grant me my request.”', 1, '', '', 'Further Supplications', 202),
  ('bocp_203', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ إِيمَانًا يُبَاشِرُ قَلْبِي، وَيَقِينًا صَادِقًا حَتَّى أَعْلَمَ أَنَّهُ لَنْ يُصِيبَنِي إِلَّا مَا كَتَبْتَ لِي، وَأَنَّ مَا أَصَابَنِي لَمْ يَكُنْ لِيُخْطِئَنِي وَمَا أَخْطَأَنِي لَمْ يَكُنْ لِيُصِيبَنِي', 'Allāhumma innī asʾaluka īmānan yubāshiru qalbī, wa yaqīnan ṣādiqan ḥattā aʿlama annahu lan yuṣībanī illā mā katabta lī, wa anna mā aṣābanī lam yakun li-yukhṭiʾanī wa mā akhṭaʾanī lam yakun li-yuṣībanī', '“O Allah! I seek from You faith that pervades my heart, and truthful certainty, until I know that nothing will befall me except what You have decreed for me, and that what has befallen me could not have missed me, and what has missed me could not have befallen me.”', 1, '', '', 'Further Supplications', 203),
  ('bocp_204', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ إِيمَانًا أَهْتَدِي بِهِ، وَنُورًا أَقْتَدِي بِهِ، وَرِزْقًا حَلَالًا أَكْتَفِي بِهِ', 'Allāhumma innī asʾaluka īmānan ahtadī bih, wa nūran aqtadī bih, wa rizqan ḥalālan aktafī bih', '“O Allah! I seek from You belief that will guide me, and light that will lead, and enough lawful subsistence.”', 1, '', '', 'Further Supplications', 204),
  ('bocp_205', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنِي أُحِبُّكَ بِقَلْبِي كُلِّهِ، وَأُرْضِيكَ بِجُهْدِي كُلِّهِ', 'Allāhumma''jʿalnī uḥibbuka bi-qalbī kullih, wa urḍīka bi-juhdī kullih', '“O Allah! Grant me the Love of You with all my heart, and that I please You with all my struggles (in Your Way).”', 1, '', '', 'Further Supplications', 205),
  ('bocp_206', 'book_of_prayer', '', 'اللَّهُمَّ مَا زَوَيْتَ عَنِّي مِمَّا أُحِبُّ فَاجْعَلْهُ قُوَّةً لِي فِيمَا تُحِبُّ، وَاجْعَلْنِي لَكَ كَمَا تُحِبُّ', 'Allāhumma mā zawayta ʿannī mimmā uḥibbu fa''jʿalhu quwwatan lī fīmā tuḥibb, wa''jʿalnī laka kamā tuḥibb', '“O Allah! Whatever You have kept away from me of what I love, make it strength for me in what You love; and make me, for You, as You love.”', 1, '', '', 'Further Supplications', 206),
  ('bocp_207', 'book_of_prayer', '', 'سُبْحَانَ اللَّهِ مِلْءَ الْمِيزَانِ وَمُنْتَهَى الْعِلْمِ وَمَبْلَغَ الرِّضَا وَزِنَةَ الْعَرْشِ، وَلَا إِلَٰهَ إِلَّا اللَّهُ مِلْءَ الْمِيزَانِ وَمُنْتَهَى الْعِلْمِ وَمَبْلَغَ الرِّضَا وَزِنَةَ الْعَرْشِ، وَاللَّهُ أَكْبَرُ مِلْءَ الْمِيزَانِ وَمُنْتَهَى الْعِلْمِ وَمَبْلَغَ الرِّضَا وَزِنَةَ الْعَرْشِ', 'Subḥāna''llāhi milʾa''l-mīzāni wa muntaha''l-ʿilmi wa mablagha''r-riḍā wa zinata''l-ʿarsh, wa lā ilāha illa''llāhu milʾa''l-mīzāni wa muntaha''l-ʿilmi wa mablagha''r-riḍā wa zinata''l-ʿarsh, wa''llāhu akbaru milʾa''l-mīzāni wa muntaha''l-ʿilmi wa mablagha''r-riḍā wa zinata''l-ʿarsh', '“Glory be to Allah, Full is the Scale, and the Possessor of all Knowledge, the Bestower of Favor, the Owner of the Most Beautiful Throne; and none has the right to be worshipped but Allah, Full is the Scale... and Allah is the Most Great, Full is the Scale, and the Possessor of all Knowledge, the Bestower of Favor, the Owner of the Most Beautiful Throne.”', 1, '', '', 'Further Supplications', 207),
  ('bocp_208', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّكَ عَلِمْتَ مَا تَحْتَ أَرْضِكَ كَعِلْمِكَ بِمَا فَوْقَ عَرْشِكَ، وَكَانَتْ وَسَاوِسُ الصُّدُورِ كَالْعَلَانِيَةِ عِنْدَكَ، وَعَلَانِيَةُ الْقَوْلِ كَالسِّرِّ فِي عِلْمِكَ، وَانْقَادَ كُلُّ شَيْءٍ لِعَظَمَتِكَ، وَخَضَعَ كُلُّ سُلْطَانٍ لِسُلْطَانِكَ، وَصَارَ أَمْرُ الدُّنْيَا وَالْآخِرَةِ كُلُّهُ بِيَدَيْكَ، اجْعَلْ لِي مِنْ كُلِّ هَمٍّ وَغَمٍّ أَصْبَحْتُ فِيهِ فَرَجًا وَمَخْرَجًا', 'Allāhumma innaka ʿalimta mā taḥta arḍika ka-ʿilmika bimā fawqa ʿarshik, wa kānat wasāwisu''ṣ-ṣudūri ka''l-ʿalāniyati ʿindak, wa ʿalāniyatu''l-qawli ka''s-sirri fī ʿilmik, wa''nqāda kullu shayʾin li-ʿaẓamatik, wa khaḍaʿa kullu sulṭānin li-sulṭānik, wa ṣāra amru''d-dunyā wa''l-ākhirati kulluhu bi-yadayk, ijʿal lī min kulli hammin wa ghammin aṣbaḥtu fīhi farajan wa makhrajan', '“O Allah! Verily, You are the One Who know all that is inside Your Earth as You Know all that is above Your Throne, the whispers of the hearts are so apparent to You, and the apparent words are like secrets in Your Knowledge, and all creatures are obedient to Your Greatness, and every authority is humble before Your Authority, and all affairs in this World and in the Last Day move by Your Hand; please grant me, for every doubt and worry I am in, relief and a way out.”', 1, '', '', 'Further Supplications', 208),
  ('bocp_209', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّ عَفْوَكَ عَنْ ذُنُوبِي، وَتَجَاوُزَكَ عَنْ خَطِيئَتِي، أَطْمَعَنِي أَنْ أَسْأَلَكَ مَا لَا أَسْتَوْجِبُهُ مِمَّا قَصَّرْتُ فِيهِ، أَدْعُوكَ آمِنًا وَأَسْأَلُكَ مُسْتَأْنِسًا، وَإِنَّكَ لَلْمُحْسِنُ إِلَيَّ وَأَنِّي لَلْمُسِيءُ إِلَى نَفْسِي فِيمَا بَيْنِي وَبَيْنَكَ، تَتَوَدَّدُ إِلَيَّ بِالنِّعَمِ وَأَتَبَغَّضُ إِلَيْكَ بِالْمَعَاصِي، وَلَكِنَّ الثِّقَةَ بِكَ حَمَلَتْنِي عَلَى الْجَرَاءَةِ عَلَيْكَ، فَعُدْ بِفَضْلِكَ وَإِحْسَانِكَ عَلَيَّ إِنَّكَ أَنْتَ التَّوَّابُ الرَّحِيمُ، لَا إِلَٰهَ غَيْرُكَ، الْبَدِيعُ لَيْسَ قَبْلَكَ شَيْءٌ، وَالدَّائِمُ غَيْرُ الْغَافِلِ، وَالَّذِي لَا يَمُوتُ وَخَالِقُ مَا يُرَى وَمَا لَا يُرَى، كُلَّ يَوْمٍ أَنْتَ فِي شَأْنٍ، وَسِعْتَ اللَّهُمَّ كُلَّ شَيْءٍ رَحْمَةً وَعِلْمًا، يَا رَحْمَنُ، يَا رَحِيمُ، يَا كَرِيمُ، يَا أَحَدُ، يَا صَمَدُ، يَا حَيُّ، يَا مُحْيِي، يَا قَيُّومُ، لَا إِلَٰهَ إِلَّا أَنْتَ، يَا رَبَّنَا إِنَّا عَبِيدُكَ وَفِي سَبِيلِكَ، اجْعَلْ لَنَا السَّبِيلَ إِلَى كُلِّ خَيْرٍ', 'Allāhumma inna ʿafwaka ʿan dhunūbī, wa tajāwuzaka ʿan khaṭīʾatī, aṭmaʿanī an asʾalaka mā lā astawjibuhu mimmā qaṣṣartu fīh, adʿūka āminan wa asʾaluka mustaʾnisan, wa innaka la''l-muḥsinu ilayya wa annī la''l-musīʾu ilā nafsī fīmā baynī wa baynak, tatawaddadu ilayya bi''n-niʿami wa atabaghghaḍu ilayka bi''l-maʿāṣī, wa lākinna''th-thiqata bika ḥamalatnī ʿala''l-jarāʾati ʿalayk, fa-ʿud bi-faḍlika wa iḥsānika ʿalayya innaka anta''t-tawwābu''r-raḥīm, lā ilāha ghayruk, al-badīʿu laysa qablaka shayʾ, wa''d-dāʾimu ghayru''l-ghāfil, wa''lladhī lā yamūtu wa khāliqu mā yurā wa mā lā yurā, kulla yawmin anta fī shaʾn, wasiʿta''llāhumma kulla shayʾin raḥmatan wa ʿilman, yā raḥmān, yā raḥīm, yā karīm, yā aḥad, yā ṣamad, yā ḥayy, yā muḥyī, yā qayyūm, lā ilāha illā ant, yā rabbanā innā ʿabīduka wa fī sabīlik, ijʿal lana''s-sabīla ilā kulli khayr', '“O Allah! Verily, Your forgiveness of my sins, and Your overlooking of my faults, has made me hopeful to ask You for what I do not deserve, of what I have fallen short in; I call upon You feeling secure and ask You feeling at ease, for You are the One Who is good to me while I wrong myself in what is between me and You; You draw near to me with blessings while I distance myself from You with sins; yet trust in You has emboldened me before You; so return upon me with Your bounty and goodness, for You are the Acceptor of repentance, the Merciful. There is no god but You, the Originator before whom there was nothing, the Everlasting Who is never heedless, the One Who does not die, Creator of what is seen and unseen; every day You are engaged in an affair; You encompass all things in mercy and knowledge, O Most Gracious, O Most Merciful, O Most Generous, O One, O Self-Sufficient, O Ever Living, O Giver of Life, O Sustainer; there is no god but You; O our Lord, we are Your servants and on Your path; grant us the way to every good.”', 1, '', '', 'Further Supplications', 209),
  ('bocp_210', 'book_of_prayer', '', 'اللَّهُمَّ حَنِّنْ عَلَيَّ عِبَادَكَ وَإِمَاءَكَ، أَغْنِنِي عَنْ شِرَارِ عِبَادِكَ يَا أَرْحَمَ الرَّاحِمِينَ، يَا وَدُودُ يَا ذَا الْعَرْشِ الْمَجِيدِ يَا فَعَّالًا لِمَا يُرِيدُ، أَسْأَلُكَ بِعِزِّكَ الَّذِي لَا يُرَامُ، وَبِمُلْكِكَ الَّذِي لَا يُضَامُ، وَبِنُورِكَ الَّذِي مَلَأَ أَرْكَانَ عَرْشِكَ أَنْ تَكْفِيَنِي شَرَّ كَذَا وَكَذَا، يَا مُغِيثُ أَغِثْنِي، يَا مُغِيثُ أَغِثْنِي، يَا مُغِيثُ أَغِثْنِي', 'Allāhumma ḥannin ʿalayya ʿibādaka wa imāʾak, aghninī ʿan shirāri ʿibādika yā arḥama''r-rāḥimīn, yā wadūdu yā dha''l-ʿarshi''l-majīdi yā faʿʿālan limā yurīd, asʾaluka bi-ʿizzika''lladhī lā yurām, wa bi-mulkika''lladhī lā yuḍām, wa bi-nūrika''lladhī malaʾa arkāna ʿarshika an takfiyanī sharra kadhā wa kadhā, yā mughīthu aghithnī, yā mughīthu aghithnī, yā mughīthu aghithnī', '“O Allah! Let Your slaves men and women love me, and make me independent of the wicked among Your slaves; O Most Merciful of those who show mercy, O Most Affectionate, O Possessor of the Most Beautiful Throne, O Doer of what He Wants; I seek by Your unfading Might, and by Your Dominion that cannot be harmed, and by Your Light that fills all corners of Your Throne, that You suffice me against the evil of such-and-such; O Reliever, relieve me; O Reliever, relieve me; O Reliever, relieve me.”', 1, '', '', 'Further Supplications', 210),
  ('bocp_211', 'book_of_prayer', '', 'أَعُوذُ بِعِزَّةِ اللَّهِ وَعَظَمَتِهِ وَبِعِزَّةِ اللَّهِ وَقُدْرَتِهِ وَبِعِزَّةِ اللَّهِ وَسُلْطَانِهِ وَبِعِزِّ جَلَالِ اللَّهِ مِنْ شَرِّ مَا خَلَقَ وَذَرَأَ وَبَرَأَ، وَمِنْ شَرِّ مَا تَحْتَ الثَّرَى، وَمِنْ شَرِّ كُلِّ دَابَّةٍ رَبِّي آخِذٌ بِنَاصِيَتِهَا، إِنَّ رَبِّي عَلَى صِرَاطٍ مُسْتَقِيمٍ، وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ الْعَلِيِّ الْعَظِيمِ، مَلْجَأَ كُلِّ هَارِبٍ وَمَأْوَى كُلِّ خَائِفٍ، أَقِي بِهَا نَفْسِي وَدِينِي وَأَهْلِي وَمَالِي، وَجَمِيعَ نِعَمِ إِلَهِي وَمَوْلَايَ وَسَيِّدِي عِنْدِي', 'Aʿūdhu bi-ʿizzati''llāhi wa ʿaẓamatihi wa bi-ʿizzati''llāhi wa qudratihi wa bi-ʿizzati''llāhi wa sulṭānihi wa bi-ʿizzi jalāli''llāhi min sharri mā khalaqa wa dharaʾa wa baraʾ, wa min sharri mā taḥta''th-tharā, wa min sharri kulli dābbatin rabbī ākhidhun bi-nāṣiyatihā, inna rabbī ʿalā ṣirāṭin mustaqīm, wa lā ḥawla wa lā quwwata illā bi''llāhi''l-ʿaliyyi''l-ʿaẓīm, maljaʾa kulli hāribin wa maʾwā kulli khāʾif, aqī bihā nafsī wa dīnī wa ahlī wa mālī, wa jamīʿa niʿami ilāhī wa mawlāya wa sayyidī ʿindī', '“I seek refuge by the Might of Allah and His Greatness, by the Might of Allah and His Power, by the Might of Allah and His Authority, and by the Might of Allah''s Majesty; against the evil of all His creations, and from the evil of those beneath the soil, and from every creature whose forelock my Lord grasps; verily, my Lord is upon the Right Path; and there is no power and no strength except by Allah, the Most High, the Most Great, the refuge of every fleeing one and shelter of every fearful one; by it I guard myself, my religion, my family, my wealth, and all the blessings my God, Master and Lord has granted me.”', 1, '', '', 'Further Supplications', 211),
  ('bocp_212', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنِي مِنَ الشَّاكِرِينَ لِآلَائِكَ الصَّابِرِينَ عَلَى بَلَائِكَ، النَّاصِرِينَ لِأَوْلِيَائِكَ', 'Allāhumma''jʿalnī mina''sh-shākirīna li-ālāʾika''ṣ-ṣābirīna ʿalā balāʾik, an-nāṣirīna li-awliyāʾik', '“O Allah! Make me among the grateful for Your favors, the steadfast through Your trials, and the helpers of Your friends (the pious servants).”', 1, '', '', 'Further Supplications', 212),
  ('bocp_213', 'book_of_prayer', '', 'اللَّهُمَّ لَا تَحْرِمْنِي خَيْرَ مَا عِنْدَكَ بِسُوءِ مَا عِنْدِي', 'Allāhumma lā taḥrimnī khayra mā ʿindaka bi-sūʾi mā ʿindī', '“O Allah! Please do not prevent me from the good that is with You by the evil that is from me.”', 1, '', '', 'Further Supplications', 213),
  ('bocp_214', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ عَيْشًا قَارًّا، وَرِزْقًا دَارًّا، وَعَمَلًا بَارًّا', 'Allāhumma innī asʾaluka ʿayshan qārran, wa rizqan dārran, wa ʿamalan bārran', '“O Allah! Grant me a settled living; and abundant sustenance; and righteous deeds.”', 1, '', '', 'Further Supplications', 214),
  ('bocp_215', 'book_of_prayer', '', 'اللَّهُمَّ أَغْنِنِي بِالِافْتِقَارِ إِلَيْكَ، وَلَا تُفْقِرْنِي بِالِاسْتِغْنَاءِ عَنْكَ', 'Allāhumma aghninī bi''l-iftiqāri ilayk, wa lā tufqirnī bi''l-istighnāʾi ʿanik', '“O Allah! Enrich me through my need of You, and do not impoverish me through independence from You.”', 1, '', '', 'Further Supplications', 215),
  ('bocp_216', 'book_of_prayer', '', 'اللَّهُمَّ اسْتُرْ عَوْرَتِي وَآمِنْ رَوْعَتِي وَخَفِّفْ لَوْعَتِي', 'Allāhumma''stur ʿawratī wa āmin rawʿatī wa khaffif lawʿatī', '“O Allah! Cover up my defects, calm my fear, and lighten my anguish.”', 1, '', '', 'Further Supplications', 216),
  ('bocp_217', 'book_of_prayer', '', 'اللَّهُمَّ آجِرْنِي عَلَى حُسْنِ عِبَادَتِكَ وَوَفِّقْنِي لِاسْتِفْتَاحِ أَبْوَابِ رَحْمَتِكَ وَاسْتِمْطَارِ سَمَاحَتِكَ', 'Allāhumma ājirnī ʿalā ḥusni ʿibādatik, wa waffiqnī li''stiftāḥi abwābi raḥmatik wa''stimṭāri samāḥatik', '“O Allah! Reward me for worshipping You well, and grant me success in opening the gates of Your mercy and in seeking the rain of Your generosity.”', 1, '', '', 'Further Supplications', 217),
  ('bocp_218', 'book_of_prayer', '', 'اللَّهُمَّ سَلِّمْنَا وَلَا تُسْلِمْنَا', 'Allāhumma sallimnā wa lā tuslimnā', '“O Allah! Keep us safe and do not abandon us (to Your trials).”', 1, '', '', 'Further Supplications', 218),
  ('bocp_219', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنَا فِي ضَمَانِكَ وَأَمَانِكَ وَإِحْسَانِكَ', 'Allāhumma''jʿalnā fī ḍamānika wa amānika wa iḥsānik', '“O Allah! Place us within Your guarantee, Your security, and Your goodness.”', 1, '', '', 'Further Supplications', 219),
  ('bocp_220', 'book_of_prayer', '', 'اللَّهُمَّ اغْفِرْ لِي كُلَّ ذَنْبٍ وَاحْفَظْنِي مِنْ كُلِّ جَنْبٍ وَفَرِّجْ عَنِّي كُلَّ كَرْبٍ', 'Allāhumma''ghfir lī kulla dhanbin wa''ḥfaẓnī min kulli janbin wa farrij ʿannī kulla karbin', '“O Allah! Forgive me every sin, protect me from every side, and relieve me of every distress.”', 1, '', '', 'Further Supplications', 220),
  ('bocp_221', 'book_of_prayer', '', 'اللَّهُمَّ أَعِنِّي عَلَى الْمَوْتِ وَكُرْبَتِهِ، وَالْقَبْرِ وَغُمَّتِهِ، وَالصِّرَاطِ وَزَلَّتِهِ، وَيَوْمِ الْقِيَامَةِ وَرَوْعَتِهِ', 'Allāhumma aʿinnī ʿala''l-mawti wa kurbatih, wa''l-qabri wa ghummatih, wa''ṣ-ṣirāṭi wa zallatih, wa yawmi''l-qiyāmati wa rawʿatih', '“O Allah! Help me at the time of death and its agony, the grave and its gloom, the Bridge and its slipping, and the Day of Judgment and its terror.”', 1, '', '', 'Further Supplications', 221),
  ('bocp_222', 'book_of_prayer', '', 'اللَّهُمَّ جَمِّلْ أَمْرِي مَا أَحْيَيْتَنِي، وَعَافِنِي مَا أَبْقَيْتَنِي، وَبَارِكْ لِي فِيمَا خَوَّلْتَنِي، وَاحْفَظْ عَلَيَّ مَا أَوْلَيْتَنِي، وَارْحَمْنِي إِذَا تَوَفَّيْتَنِي، وَآنِسْ وَحْشَتِي إِذَا أَرْمَسْتَنِي، وَتَفَضَّلْ عَلَيَّ إِذَا حَاسَبْتَنِي، وَلَا تَسْلُبْنِي الْإِيمَانَ وَقَدْ عَرَّفْتَنِي', 'Allāhumma jammil amrī mā aḥyaytanī, wa ʿāfinī mā abqaytanī, wa bārik lī fīmā khawwaltanī, wa''ḥfaẓ ʿalayya mā awlaytanī, wa''rḥamnī idhā tawaffaytanī, wa ānis waḥshatī idhā armastanī, wa tafaḍḍal ʿalayya idhā ḥāsabtanī, wa lā taslubni''l-īmāna wa qad ʿarraftanī', '“O Allah! Beautify my affair as long as You keep me alive, grant me well-being as long as You let me remain, bless what You have bestowed on me, preserve for me what You have granted, have mercy on me when You take my soul, comfort my loneliness when You bury me, be gracious to me when You hold me to account, and do not strip me of faith after You have made me know it.”', 1, '', '', 'Further Supplications', 222),
  ('bocp_223', 'book_of_prayer', '', 'اللَّهُمَّ ثَبِّتْ فِي الْخَيْرَاتِ وَطْأَتِي، وَنَفِّسْ بَعْدَ الْمَوْتِ كُرْبَتِي، وَبَارِكْ لِي فِي مَصِيرِي وَمُنْقَلَبِي، وَلَا تُخْفِرْ ذِمَّتِي يَا غَايَةَ رَغْبَتِي', 'Allāhumma thabbit fi''l-khayrāti waṭʾatī, wa naffis baʿda''l-mawti kurbatī, wa bārik lī fī maṣīrī wa munqalabī, wa lā tukhfir dhimmatī yā ghāyata raghbatī', '“O Allah! Make my footing firm in good deeds, relieve my distress after death, bless me in my destination and return, and do not break my covenant, O Goal of my desire.”', 1, '', '', 'Further Supplications', 223),
  ('bocp_224', 'book_of_prayer', '', 'اللَّهُمَّ لَا تَقْطَعْ رَجَائِي، وَبَلِّغْنِيَ الْأَمَانِيَّ وَاكْفِنِي الْأَعَادِيَ وَأَصْلِحْ لِي شَأْنِي وَاكْفِنِي أَمْرَ دِينِي وَدُنْيَايَ وَآخِرَتِي، وَارْزُقْنِي قَلْبًا تَوَّابًا، لَا كَافِرًا وَلَا مُرْتَابًا، وَاغْفِرْ لِي وَاهْدِنِي وَارْزُقْنِي وَأَنْتَ خَيْرُ الرَّازِقِينَ، بِرَحْمَتِكَ يَا أَرْحَمَ الرَّاحِمِينَ', 'Allāhumma lā taqṭaʿ rajāʾī, wa ballighniya''l-amāniyya wa''kfini''l-aʿādiya wa aṣliḥ lī shaʾnī wa''kfinī amra dīnī wa dunyāya wa ākhiratī, wa''rzuqnī qalban tawwāban, lā kāfiran wa lā murtāban, wa''ghfir lī wa''hdinī wa''rzuqnī wa anta khayru''r-rāziqīn, bi-raḥmatika yā arḥama''r-rāḥimīn', '“O Allah! Do not cut off my hope, let me attain my wishes, suffice me against the enemies, set right my affair, and suffice me in the matter of my religion, my world, and my Hereafter; and grant me a repentant heart, neither disbelieving nor doubting; and forgive me, guide me, and provide me, for You are the Best of Providers, by Your Mercy, O Most Merciful of those who show mercy.”', 1, '', '', 'Further Supplications', 224),
  ('bocp_225', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْتَهْدِيكَ لِأَرْشَدِ أُمُورِي وَأَسْتَجِيرُكَ مِنْ شَرِّ نَفْسِي، سُبْحَانَ رَبِّيَ الْأَعْلَى الْوَهَّابِ', 'Allāhumma innī astahdīka li-arshadi umūrī wa astajīruka min sharri nafsī, subḥāna rabbiya''l-aʿla''l-wahhāb', '“O Allah! I seek Your guidance to the most upright of my affairs, and I seek Your protection from the evil of myself; Glory be to my Lord, the Most High, the Bestower.”', 1, '', '', 'Further Supplications', 225),
  ('bocp_226', 'book_of_prayer', '', 'يَا عَالِمَ الْخَفِيَّاتِ، رَفِيعَ الدَّرَجَاتِ، ذَا الْعَرْشِ يُلْقِي الرُّوحَ مِنْ أَمْرِهِ عَلَى مَنْ يَشَاءُ مِنْ عِبَادِهِ، غَافِرَ الذَّنْبِ قَابِلَ التَّوْبِ شَدِيدَ الْعِقَابِ ذَا الطَّوْلِ، لَا إِلَٰهَ إِلَّا أَنْتَ إِلَيْكَ الْمَصِيرُ، لَا إِلَٰهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ، سُبْحَانَ اللَّهِ وَبِحَمْدِهِ، أَسْتَغْفِرُ اللَّهَ، لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ، الْأَوَّلُ وَالْآخِرُ وَالظَّاهِرُ وَالْبَاطِنُ وَهُوَ بِكُلِّ شَيْءٍ عَلِيمٌ', 'Yā ʿālima''l-khafiyyāt, rafīʿa''d-darajāt, dha''l-ʿarshi yulqi''r-rūḥa min amrihi ʿalā man yashāʾu min ʿibādih, ghāfira''dh-dhanbi qābila''t-tawbi shadīda''l-ʿiqābi dha''ṭ-ṭawl, lā ilāha illā anta ilayka''l-maṣīr, lā ilāha illa''llāhu wa''llāhu akbar, subḥāna''llāhi wa bi-ḥamdih, astaghfiru''llāh, lā ḥawla wa lā quwwata illā bi''llāh, al-awwalu wa''l-ākhiru wa''ẓ-ẓāhiru wa''l-bāṭinu wa huwa bi-kulli shayʾin ʿalīm', '“O Knower of the hidden things, the Exalter of ranks, Owner of the Throne, Who casts the spirit by His command upon whom He wills of His servants; Forgiver of sin, Accepter of repentance, Severe in punishment, Possessor of bounty; there is no god but You, to You is the return. There is no god but Allah and Allah is the Most Great; Glory and praise be to Allah; I seek Allah''s forgiveness; there is no power and no strength except by Allah, the First, the Last, the Apparent, the Concealed, and He Knows everything.”', 1, '', '', 'Further Supplications', 226),
  ('bocp_227', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْتَغْفِرُكَ مِمَّا تُبْتُ إِلَيْكَ مِنْهُ ثُمَّ عُدْتُ فِيهِ، وَأَسْتَغْفِرُكَ لِمَا جَعَلْتُهُ لَكَ عَلَى نَفْسِي فَلَمْ أُوفِ لَكَ بِهِ، وَأَسْتَغْفِرُكَ مِمَّا زَعَمْتُ أَنِّي أَرَدْتُ بِهِ وَجْهَكَ فَخَالَطَ قَلْبِي مَا قَدْ عَلِمْتَ', 'Allāhumma innī astaghfiruka mimmā tubtu ilayka minhu thumma ʿudtu fīh, wa astaghfiruka limā jaʿaltuhu laka ʿalā nafsī fa-lam ūfi laka bih, wa astaghfiruka mimmā zaʿamtu annī aradtu bihi wajhaka fa-khālaṭa qalbī mā qad ʿalimt', '“O Allah! I seek Your forgiveness for what I repented from and then returned to, for what I pledged to You upon myself and did not fulfill, and for what I claimed I intended Your Face by, yet my heart was mixed with what You know.”', 1, '', '', 'Further Supplications', 227),
  ('bocp_228', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّا نَتَوَسَّلُ إِلَيْكَ بِمَا تَوَسَّلَ بِهِ عِبَادُكَ الصَّالِحُونَ وَأَوْلِيَاؤُكَ الْمُقَرَّبُونَ، أَنْ تَجْعَلَ لَنَا مِنَ الْفَهْمِ عَنْكَ وَعَنْ رَسُولِكَ مَا نَبْلُغُ بِهِ مَنَازِلَ الصِّدِّيقِينَ، وَتَحْشُرَنَا بِهِ فِي زُمْرَةِ الْعُلَمَاءِ الْعَامِلِينَ', 'Allāhumma innā natawassalu ilayka bimā tawassala bihi ʿibāduka''ṣ-ṣāliḥūna wa awliyāʾuka''l-muqarrabūn, an tajʿala lanā mina''l-fahmi ʿanka wa ʿan rasūlika mā nablughu bihi manāzila''ṣ-ṣiddīqīn, wa taḥshuranā bihi fī zumrati''l-ʿulamāʾi''l-ʿāmilīn', '“O Allah! We seek means to You by that which Your righteous servants and Your servants drawn near sought means to You — that You grant us such understanding of You and of Your Messenger by which we attain the stations of the truthful, and be gathered by it among the company of the scholars who act upon their knowledge.”', 1, '', '', 'Further Supplications', 228),
  ('bocp_229', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنَا مِنَ الَّذِينَ سَرَحَتْ أَرْوَاحُهُمْ فِي دَارِ الْعُلَى، وَحَطَّتْ هِمَمُ قُلُوبِهِمْ فِي غَايَةِ التُّقَى، حَتَّى أَنَاخُوا بِرِيَاضِ النَّعِيمِ وَجَنَوْا مِنْ ثِمَارِ رِيَاضِ التَّسْنِيمِ، وَخَاضُوا لُجَّةَ السُّرُورِ، وَشَرِبُوا بِكَأْسِ الرَّحِيقِ الْمَخْتُومِ وَاسْتَظَلُّوا تَحْتَ ظِلِّ الْكَرَامَةِ الظَّلِيلِ', 'Allāhumma''jʿalnā mina''lladhīna saraḥat arwāḥuhum fī dāri''l-ʿulā, wa ḥaṭṭat himamu qulūbihim fī ghāyati''t-tuqā, ḥattā anākhū bi-riyāḍi''n-naʿīm wa janaw min thimāri riyāḍi''t-tasnīm, wa khāḍū lujjata''s-surūr, wa sharibū bi-kaʾsi''r-raḥīqi''l-makhtūm wa''staẓallū taḥta ẓilli''l-karāmati''ẓ-ẓalīl', '“O Allah! Make us among those whose souls roam in the abode of loftiness, whose hearts'' aspirations have settled at the height of piety, until they alight in the gardens of bliss and gather from the fruits of the gardens of Tasnim, and plunge into the depth of joy, and drink from the cup of sealed pure wine, and take shade beneath the shade of honor.”', 1, '', '', 'Further Supplications', 229),
  ('bocp_230', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنَا مِنَ الَّذِينَ فَتَحُوا بَابَ الصَّبْرِ وَأَرْدَمُوا خَنَادِقَ الْجَزَعِ، وَجَازُوا شَدِيدَ الْعِقَابِ، وَعَبَرُوا جِسْرَ الْهَوَى', 'Allāhumma''jʿalnā mina''lladhīna fataḥū bāba''ṣ-ṣabri wa ardamū khanādiqa''l-jazaʿ, wa jāzū shadīda''l-ʿiqāb, wa ʿabarū jisra''l-hawā', '“O Allah! Make us among those who opened the gate of patience, filled in the trenches of anxiety, passed the severe punishment, and crossed the bridge of desire.”', 1, '', '', 'Further Supplications', 230),
  ('bocp_231', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنَا مِنَ الَّذِينَ أَشَارَتْ إِلَيْهِمْ أَعْلَامُ الْهِدَايَةِ وَوَضَحَتْ لَهُمْ طَرِيقُ النَّجَاةِ وَسَلَكُوا سَبِيلَ الْإِخْلَاصِ وَالْيَقِينِ', 'Allāhumma''jʿalnā mina''lladhīna ashārat ilayhim aʿlāmu''l-hidāyah wa waḍaḥat lahum ṭarīqu''n-najāh wa salakū sabīla''l-ikhlāṣi wa''l-yaqīn', '“O Allah! Make us among those to whom the banners of guidance pointed, for whom the path of salvation became clear, and who traversed the way of sincerity and certainty.”', 1, '', '', 'Further Supplications', 231),
  ('bocp_232', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّ نَفْسِي أَمَّارَةٌ بِالسُّوءِ وَالشَّيْطَانُ يُوقِعُنِي كُلَّ سَاعَةٍ فِي خَطِيئَةٍ مِنَ الْكَبَائِرِ فَضْلًا عَنِ الصَّغَائِرِ، وَإِنِّي أُرِيدُ نَزْعِي مِنْ نَزْغِهِ، وَلَا أَسْتَطِيعُ حَتَّى تُوَفِّقَنِي؛ فَإِنَّ بِيَدِكَ الْخَيْرَ، وَالشَّرُّ لَيْسَ إِلَيْكَ فَاغْفِرْ لِي وَثُبْ عَلَيَّ، وَلَا تُنْزِغْ قَلْبِي بَعْدَ إِذْ هَدَيْتَنِي، وَامْنَحْنِي عِلْمًا بِالْكِتَابِ وَالسُّنَّةِ، وَإِنْ لَمْ تَرْحَمْنِي وَتَغْفِرْ لِي أَكُنْ مِنَ الْخَاسِرِينَ، فَاهْدِنِي سَوَاءَ السَّبِيلِ وَاغْفِرْ لِي مَغْفِرَةً تَامَّةً، وَاعْفُ عَنِّي فَإِنَّكَ عَفُوٌّ تُحِبُّ الْعَفْوَ، وَارْزُقْنِي الْعَافِيَةَ فِي الدِّينِ وَالدُّنْيَا وَالْآخِرَةِ، وَمَا ذَلِكَ عَلَيْكَ بِعَزِيزٍ يَا أَرْحَمَ الرَّاحِمِينَ، يَا لَطِيفُ يَا لَطِيفُ، الْطُفْ بِي بِالْقُدْرَةِ الَّتِي اسْتَوَيْتَ بِهَا عَلَى الْعَرْشِ فَلَمْ يَعْلَمْ أَحَدٌ كَيْفِيَّةَ اسْتِوَائِكَ عَلَيْهِ، اكْفِنِي شَرَّ كُلِّ شِرِّيرٍ يَا مَنْ كَانَ قَبْلَ أَنْ يَكُونَ شَيْءٌ وَهُوَ الْمُكَوِّنُ لِكُلِّ شَيْءٍ، وَمَنْ يَكُونُ بَعْدَ مَا لَا يَكُونُ شَيْءٌ أَسْأَلُكَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ، يَا ذَا الطَّوْلِ وَالْإِنْعَامِ، لَا إِلَٰهَ إِلَّا أَنْتَ، رَبَّ الْعَالَمِينَ أَرْحَمَ الرَّاحِمِينَ الْحَنَّانَ الْمَنَّانَ بَدِيعَ السَّمَوَاتِ وَالْأَرْضِ رَبَّ الْعَرْشِ الْعَظِيمِ', 'Allāhumma inna nafsī ammāratun bi''s-sūʾi wa''sh-shayṭānu yūqiʿunī kulla sāʿatin fī khaṭīʾatin mina''l-kabāʾiri faḍlan ʿani''ṣ-ṣaghāʾir, wa innī urīdu nazʿī min nazghih, wa lā astaṭīʿu ḥattā tuwaffiqanī; fa-inna bi-yadika''l-khayr, wa''sh-sharru laysa ilayka fa''ghfir lī wa thub ʿalayy, wa lā tunzigh qalbī baʿda idh hadaytanī, wa''mnaḥnī ʿilman bi''l-kitābi wa''s-sunnah, wa in lam tarḥamnī wa taghfir lī akun mina''l-khāsirīn, fa''hdinī sawāʾa''s-sabīli wa''ghfir lī maghfiratan tāmmah, wa''ʿfu ʿannī fa-innaka ʿafuwwun tuḥibbu''l-ʿafw, wa''rzuqni''l-ʿāfiyata fi''d-dīni wa''d-dunyā wa''l-ākhirah, wa mā dhālika ʿalayka bi-ʿazīzin yā arḥama''r-rāḥimīn, yā laṭīfu yā laṭīf, ulṭuf bī bi''l-qudrati''llati''stawayta bihā ʿala''l-ʿarshi fa-lam yaʿlam aḥadun kayfiyyata''stiwāʾika ʿalayh, ikfinī sharra kulli shirrīrin yā man kāna qabla an yakūna shayʾun wa huwa''l-mukawwinu li-kulli shayʾ, wa man yakūnu baʿda mā lā yakūnu shayʾun asʾaluka yā dha''l-jalāli wa''l-ikrām, yā dha''ṭ-ṭawli wa''l-inʿām, lā ilāha illā anta, rabba''l-ʿālamīna arḥama''r-rāḥimīna''l-ḥannāna''l-mannāna badīʿa''s-samāwāti wa''l-arḍi rabba''l-ʿarshi''l-ʿaẓīm', '“O Allah! My soul commands me to evil and Satan throws me every hour into a sin among the major ones, let alone the minor; I wish to free myself from his incitement but cannot until You grant me success; for in Your hand is good, and evil is not attributed to You, so forgive me and turn to me, and do not let my heart deviate after You have guided me, and grant me knowledge of the Book and the Sunnah; and if You do not have mercy on me and forgive me I will be among the losers; so guide me to the right path and forgive me a complete forgiveness, and pardon me, for You are the Pardoner Who loves to pardon, and grant me well-being in religion, this world and the Hereafter, and that is not hard for You, O Most Merciful of those who show mercy. O Most Gentle, O Most Gentle, be gentle with me by the power with which You rose over the Throne — none knowing the manner of Your rising over it — suffice me against the evil of every evildoer, O You Who were before anything existed and Who is the Maker of all things, and Who remains after nothing remains; I ask You, O Possessor of Majesty and Honor, O Possessor of bounty and favor; there is no god but You, Lord of the Worlds, Most Merciful of those who show mercy, the Compassionate, the Bestower, Originator of the heavens and the earth, Lord of the Great Throne.”', 1, '', '', 'Further Supplications', 232),
  ('bocp_233', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنِي أَخْشَاكَ حَتَّى كَأَنِّي أَرَاكَ وَأَسْعِدْنِي بِتَقْوَاكَ، وَلَا تُجْعَلْنِي بِمَعْصِيَتِكَ مَطْرُودًا، وَرَضِّنِي بِقَضَائِكَ، وَانْصُرْنِي عَلَى مَنْ ظَلَمَنِي، وَأَرِنِي فِيهِ ثَأْرِي وَأَقِرَّ بِذَلِكَ عَيْنِي', 'Allāhumma''jʿalnī akhshāka ḥattā kaʾannī arāka wa asʿidnī bi-taqwāk, wa lā tujʿalnī bi-maʿṣiyatika maṭrūdan, wa raḍḍinī bi-qaḍāʾik, wa''nṣurnī ʿalā man ẓalamanī, wa arinī fīhi thaʾrī wa aqirra bi-dhālika ʿaynī', '“O Allah! Make me fear You as though I see You, make me happy with piety toward You, do not make me banished through disobeying You, make me pleased with Your decree, grant me victory over whoever wronged me, and let me see my redress in him and let that comfort my eye.”', 1, '', '', 'Further Supplications', 233),
  ('bocp_234', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْتَوْدِعُكَ الْيَوْمَ نَفْسِي وَأَهْلِي وَمَالِي وَوَلَدِي، وَمَنْ كَانَ مِنِّي فِي سَبِيلٍ الشَّاهِدِ مِنْهُمْ وَالْغَائِبِ', 'Allāhumma innī astawdiʿuka''l-yawma nafsī wa ahlī wa mālī wa waladī, wa man kāna minnī fī sabīlin ash-shāhidi minhum wa''l-ghāʾib', '“O Allah! Today I entrust to You myself, my family, my wealth, and my children, and whoever is connected to me — the present of them and the absent.”', 1, '', '', 'Further Supplications', 234),
  ('bocp_235', 'book_of_prayer', '', 'اللَّهُمَّ احْفَظْنَا بِحِفْظِ الْإِيمَانِ وَاحْفَظْهُ عَلَيْنَا', 'Allāhumma''ḥfaẓnā bi-ḥifẓi''l-īmāni wa''ḥfaẓhu ʿalaynā', '“O Allah! Protect us with the protection of faith, and preserve it for us.”', 1, '', '', 'Further Supplications', 235),
  ('bocp_236', 'book_of_prayer', '', 'اللَّهُمَّ اجْعَلْنَا فِي رَحْمَتِكَ وَلَا تَسْلُبْنَا فَضْلَكَ، إِنَّا إِلَيْكَ رَاغِبُونَ', 'Allāhumma''jʿalnā fī raḥmatika wa lā taslubnā faḍlak, innā ilayka rāghibūn', '“O Allah! Place us within Your mercy and do not strip us of Your favor; verily, to You we turn in hope.”', 1, '', '', 'Further Supplications', 236),
  ('bocp_237', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّا نَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ، وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ وَالْوَلَدِ، يَا مَنْ هُوَ أَقْرَبُ مِنْ حَبْلِ الْوَرِيدِ، يَا فَعَّالًا لِمَا يُرِيدُ، يَا مَنْ يَحُولُ بَيْنَ الْمَرْءِ وَقَلْبِهِ حُلْ بَيْنَنَا وَبَيْنَ مَنْ يُؤْذِينَا، بِحَوْلِكَ وَقُوَّتِكَ يَا كَافِيَ كُلِّ شَيْءٍ وَلَا يَكْفِي مِنْهُ شَيْءٌ اكْفِنَا مَا يَهُمُّنَا مِنْ أَمْرِ الدُّنْيَا وَالْآخِرَةِ يَا أَرْحَمَ الرَّاحِمِينَ', 'Allāhumma innā naʿūdhu bika min waʿthāʾi''s-safari wa kaʾābati''l-munqalab, wa sūʾi''l-manẓari fi''l-ahli wa''l-māli wa''l-walad, yā man huwa aqrabu min ḥabli''l-warīd, yā faʿʿālan limā yurīd, yā man yaḥūlu bayna''l-marʾi wa qalbihi ḥul baynanā wa bayna man yuʾdhīnā, bi-ḥawlika wa quwwatika yā kāfiya kulli shayʾin wa lā yakfī minhu shayʾun ikfinā mā yahummunā min amri''d-dunyā wa''l-ākhirah yā arḥama''r-rāḥimīn', '“O Allah! We seek refuge with You from the difficulty of travel, and a sorrowful return, and an evil sight in family, wealth and children; O You Who is nearer to us than the jugular vein, O Doer of what He wills, O You Who comes between a man and his heart, come between us and whoever harms us, by Your might and power, O Sufficer of everything Whom nothing can suffice against; suffice us in what troubles us of the affairs of this world and the Hereafter, O Most Merciful of those who show mercy.”', 1, '', '', 'Further Supplications', 237),
  ('bocp_238', 'book_of_prayer', '', 'اللَّهُمَّ وَفِّرْ حَظِّي مِنْ خَيْرٍ تُنْزِلُهُ، أَوْ إِحْسَانٍ تُفْضِلُهُ أَوْ يُسْرٍ تَنْشُرُهُ أَوْ رِزْقٍ تَبْسُطُهُ أَوْ ذَنْبٍ تَغْفِرُهُ أَوْ خَطَأٍ تَسْتُرُهُ، يَا إِلَهِي يَا مَنْ بِيَدِهِ نَاصِيَتِي يَا عَلِيمُ بِضُرِّي وَمَسْكَنَتِي يَا خَيْرُ بِفَقْرِي وَفَاقَتِي يَا رَبِّ أَسْأَلُكَ بِحَقِّكَ وَقُدْسِكَ وَأَعْظَمِ صِفَاتِكَ وَأَسْمَائِكَ: أَنْ تَجْعَلَ أَوْقَاتِي بِاللَّيْلِ وَالنَّهَارِ بِذِكْرِكَ مَعْمُورَةً وَبِخِدْمَتِكَ مَوْصُولَةً وَأَعْمَالِي عِنْدَكَ مَقْبُولَةً، يَا مَنْ عَلَيْهِ مُعَوَّلِي يَا مَنْ إِلَيْهِ شَكَوْتُ أَحْوَالِي، قَوِّ عَلَى خِدْمَتِكَ جَوَارِحِي وَاشْدُدْ عَلَى الْعَزِيمَةِ جَوَانِحِي وَهَبْ لِي الْجِدَّ فِي خَشْيَتِكَ وَالدَّوَامَ عَلَى الِاتِّصَالِ فِي خِدْمَتِكَ حَتَّى أَخَافَكَ مَخَافَةَ الْمُوقِنِينَ وَأَجْتَمِعَ فِي جِوَارِكَ مَعَ الْمُؤْمِنِينَ', 'Allāhumma waffir ḥaẓẓī min khayrin tunziluh, aw iḥsānin tufḍiluhu aw yusrin tanshuruhu aw rizqin tabsuṭuhu aw dhanbin taghfiruhu aw khaṭaʾin tasturuh, yā ilāhī yā man bi-yadihi nāṣiyatī yā ʿalīmu bi-ḍurrī wa maskanatī yā khayru bi-faqrī wa fāqatī yā rabbi asʾaluka bi-ḥaqqika wa qudsika wa aʿẓami ṣifātika wa asmāʾik: an tajʿala awqātī bi''l-layli wa''n-nahāri bi-dhikrika maʿmūratan wa bi-khidmatika mawṣūlatan wa aʿmālī ʿindaka maqbūlah, yā man ʿalayhi muʿawwalī yā man ilayhi shakawtu aḥwālī, qawwi ʿalā khidmatika jawāriḥī wa''shdud ʿala''l-ʿazīmati jawāniḥī wa hab li''l-jidda fī khashyatika wa''d-dawāma ʿala''l-ittiṣāli fī khidmatika ḥattā akhāfaka makhāfata''l-mūqinīna wa ajtamiʿa fī jiwārika maʿa''l-muʾminīn', '“O Allah! Increase my share of any good You send down, or kindness You bestow, or ease You spread, or provision You extend, or sin You forgive, or error You conceal; O my God, O You in Whose hand is my forelock, O Knower of my distress and destitution, O Best (refuge) in my poverty and need, O my Lord, I ask You by Your truth and Your holiness and Your greatest attributes and names: that You make my times by night and day filled with Your remembrance and joined to Your service, and my deeds accepted with You; O You upon Whom I rely, O You to Whom I complain of my states, strengthen my limbs for Your service, fix my heart upon resolve, grant me earnestness in fearing You and constancy in remaining connected to Your service, until I fear You with the fear of the certain and gather in Your neighborhood with the believers.”', 1, '', '', 'Further Supplications', 238),
  ('bocp_239', 'book_of_prayer', '', 'اللَّهُمَّ مَنْ أَرَادَنِي بِسُوءٍ فَرُدَّهُ عَلَيْهِ، وَمَنْ كَادَنِي فَكِدْهُ، وَاجْعَلْنِي مِنْ أَحْسَنِ عِبَادِكَ نَصِيبًا عِنْدَكَ وَأَقْرَبِهِمْ مَنْزِلَةً مِنْكَ وَأَخَصِّهِمْ زُلْفَى لَدَيْكَ، إِنَّهُ لَا يَنَالُ ذَلِكَ إِلَّا بِفَضْلِكَ، وَجُدْ لِي بِجُودِكَ، وَاعْطِفْ عَلَيَّ بِمَجْدِكَ وَاحْفَظْنِي بِرَحْمَتِكَ وَاجْعَلْ لِسَانِي بِذِكْرِكَ لَهِجًا، وَأَقِلْنِي مِنْ عَثْرَتِي وَاغْفِرْ لِي زَلَّتِي، فَإِنَّكَ أَمَرْتَ عِبَادَكَ بِدُعَائِكَ وَضَمِنْتَ لَهُمُ الْإِجَابَةَ، فَإِلَيْكَ يَا رَبِّ نَصَبْتُ وَجْهِي، وَمَدَدْتُ يَدَيَّ فَبِرَحْمَتِكَ اسْتَجِبْ دُعَائِي، وَبَلِّغْنِي مُنَايَ وَلَا تَقْطَعْ رَجَائِي، وَاكْفِنِي شَرَّ أَعْدَائِي يَا سَمِيعَ الدُّعَاءِ، يَا سَابِغَ النِّعَمِ، يَا دَافِعَ النِّقَمِ، يَا نُورَ الْمُسْتَوْحِشِينَ فِي الظُّلَمِ، يَا أَرْحَمَ الرَّاحِمِينَ', 'Allāhumma man arādanī bi-sūʾin fa-ruddahu ʿalayh, wa man kādanī fa-kidh, wa''jʿalnī min aḥsani ʿibādika naṣīban ʿindaka wa aqrabihim manzilatan minka wa akhaṣṣihim zulfā ladayk, innahu lā yanālu dhālika illā bi-faḍlik, wa jud lī bi-jūdik, wa''ʿṭif ʿalayya bi-majdik wa''ḥfaẓnī bi-raḥmatik wa''jʿal lisānī bi-dhikrika lahijan, wa aqilnī min ʿathratī wa''ghfir lī zallatī, fa-innaka amarta ʿibādaka bi-duʿāʾik wa ḍaminta lahumu''l-ijābah, fa-ilayka yā rabbi naṣabtu wajhī, wa madadtu yadayya fa-bi-raḥmatika''stajib duʿāʾī, wa ballighnī munāya wa lā taqṭaʿ rajāʾī, wa''kfinī sharra aʿdāʾī yā samīʿa''d-duʿāʾ, yā sābigha''n-niʿam, yā dāfiʿa''n-niqam, yā nūra''l-mustawḥishīna fi''ẓ-ẓulam, yā arḥama''r-rāḥimīn', '“O Allah! Whoever intends evil against me, turn it back on him; whoever plots against me, outwit him; and make me among Your servants with the best portion with You, the nearest in rank, and the most favored in nearness; for none attains that except by Your grace. Be generous to me with Your generosity, incline to me with Your glory, guard me with Your mercy, and keep my tongue ever-moving with Your remembrance; overlook my stumbling and forgive my slip; for You have commanded Your servants to call upon You and guaranteed them the response; so to You, my Lord, I have turned my face and stretched out my hands — by Your mercy answer my call, let me attain my hopes, do not cut off my hope, and suffice me against the evil of my enemies, O Hearer of supplication, O Lavisher of blessings, O Repeller of afflictions, O Light of those who feel lonely in darknesses, O Most Merciful of those who show mercy.”', 1, '', '', 'Further Supplications', 239),
  ('bocp_240', 'book_of_prayer', '', 'اللَّهُمَّ فَخُذْ بِيَدِي فِي الْمَضَائِقِ وَاكْشِفْ لِي وَجْوَةَ الْحَقَائِقِ وَوَفِّقْنِي لِمَا تُحِبُّ وَاعْصِمْنِي مِنَ الزَّلَلِ، وَلَا تَسْلُبْ عَنِّي سِتْرَ إِحْسَانِكَ، وَقِنِي مَصَارِعَ السُّوءِ وَاكْفِنِي كَيْدَ الْحَاسِدِ وَشَمَاتَةَ الْأَضْدَادِ، وَالْطُفْ بِي فِي سَائِرِ مُتَصَرَّفَاتِي، وَاكْفِنِي مِنْ جَمِيعِ جِهَاتِي يَا أَرْحَمَ الرَّاحِمِينَ', 'Allāhumma fa-khudh bi-yadī fi''l-maḍāʾiqi wa''kshif lī wajwata''l-ḥaqāʾiqi wa waffiqnī limā tuḥibbu wa''ʿṣimnī mina''z-zalal, wa lā taslub ʿannī sitra iḥsānik, wa qinī maṣāriʿa''s-sūʾi wa''kfinī kayda''l-ḥāsidi wa shamātata''l-aḍdād, wa''lṭuf bī fī sāʾiri mutaṣarrafātī, wa''kfinī min jamīʿi jihātī yā arḥama''r-rāḥimīn', '“O Allah! Take my hand in the narrow straits, unveil for me the brightness of realities, grant me success in what You love, protect me from slips, do not strip from me the cover of Your kindness, guard me from the pitfalls of evil, suffice me against the plotting of the envier and the gloating of opponents, be gentle with me in all my dealings, and suffice me from all directions, O Most Merciful of those who show mercy.”', 1, '', '', 'Further Supplications', 240),
  ('bocp_241', 'book_of_prayer', '', 'اللَّهُمَّ كُنْ لِي مُؤَيِّدًا وَنَاصِرًا وَكُنْ بِي رَؤُوفًا رَحِيمًا يَا خَيْرَ الْمَسْؤُولِينَ، إِلَيْكَ أَشْكُو ضَعْفَ قُوَّتِي وَقِلَّةَ حِيلَتِي يَا أَرْحَمَ الرَّاحِمِينَ بِقُدْرَتِكَ عَلَيَّ، وَلَا تَكِلْنِي إِلَى نَفْسِي طَرْفَةَ عَيْنٍ، يَا حَيُّ يَا قَيُّومُ بِرَحْمَتِكَ أَسْتَغِيثُ', 'Allāhumma kun lī muʾayyidan wa nāṣiran wa kun bī raʾūfan raḥīman yā khayra''l-masʾūlīn, ilayka ashkū ḍaʿfa quwwatī wa qillata ḥīlatī yā arḥama''r-rāḥimīna bi-qudratika ʿalayy, wa lā takilnī ilā nafsī ṭarfata ʿayn, yā ḥayyu yā qayyūmu bi-raḥmatika astaghīth', '“O Allah! Be my supporter and helper, and be compassionate and merciful to me, O Best of those who are asked; to You I complain of the weakness of my strength and the scarcity of my means, O Most Merciful of those who show mercy, by Your power over me; and do not entrust me to myself for the blink of an eye, O Ever Living, O Sustainer, by Your mercy I seek relief. (said three times)”', 1, '', '', 'Further Supplications', 241),
  ('bocp_242', 'book_of_prayer', '', 'اللَّهُمَّ أَسْأَلُكَ بِعِزِّكَ وَذُلِّي إِلَّا رَحِمْتَنِي، وَأَسْأَلُكَ بِقُوَّتِكَ وَضَعْفِي، وَبِغِنَائِكَ عَنِّي وَفَقْرِي إِلَيْكَ، هَذِهِ نَاصِيَتِي الْكَاذِبَةُ الْخَاطِئَةُ بَيْنَ يَدَيْكَ، عَبِيدُكَ سِوَايَ كَثِيرٌ وَلَيْسَ لِي سَيِّدٌ سِوَاكَ، لَا مَلْجَأَ وَلَا مَنْجَى مِنْكَ إِلَّا إِلَيْكَ، أَسْأَلُكَ مَسْأَلَةَ الْمِسْكِينِ، وَأَبْتَهِلُ إِلَيْكَ ابْتِهَالَ الْخَاضِعِ الذَّلِيلِ، وَأَدْعُوكَ دُعَاءَ الْخَائِفِ الضَّرِيرِ، سُؤَالَ مَنْ خَضَعَتْ لَكَ رَقَبَتُهُ، وَرَغِمَ لَكَ أَنْفُهُ، وَفَاضَتْ لَكَ عَيْنَاهُ، وَذَلَّ لَكَ قَلْبُهُ', 'Allāhumma asʾaluka bi-ʿizzika wa dhullī illā raḥimtanī, wa asʾaluka bi-quwwatika wa ḍaʿfī, wa bi-ghināʾika ʿannī wa faqrī ilayk, hādhihi nāṣiyatiya''l-kādhibatu''l-khāṭiʾatu bayna yadayk, ʿabīduka siwāya kathīrun wa laysa lī sayyidun siwāk, lā maljaʾa wa lā manjā minka illā ilayk, asʾaluka masʾalata''l-miskīn, wa abtahilu ilayka''btihāla''l-khāḍiʿi''dh-dhalīl, wa adʿūka duʿāʾa''l-khāʾifi''ḍ-ḍarīr, suʾāla man khaḍaʿat laka raqabatuh, wa raghima laka anfuh, wa fāḍat laka ʿaynāh, wa dhalla laka qalbuh', '“O Allah! I ask You by Your might and my lowliness, that You have mercy on me; I ask You by Your strength and my weakness, by Your independence from me and my need of You; this is my lying, sinful forelock before You; You have many servants besides me, but I have no master besides You; there is no refuge or escape from You except to You; I ask You with the asking of the destitute, I implore You with the imploring of the humbled lowly one, and I call You with the call of the fearful afflicted one — the asking of one whose neck is humbled to You, whose nose is in the dust for You, whose eyes overflow for You, and whose heart is humbled to You.”', 1, '', '', 'Further Supplications', 242),
  ('bocp_243', 'book_of_prayer', '', 'اللَّهُمَّ أَلْبِسْنِي الْعَافِيَةَ حَتَّى تُهَنِّيَنِي بِالْمَعِيشَةِ، وَاخْتِمْ لِي بِالْمَغْفِرَةِ حَتَّى لَا تَضُرَّنِي الذُّنُوبُ، وَاكْفِنِي كُلَّ هَوْلٍ دُونَ الْجَنَّةِ حَتَّى تُبَلِّغَنِيهَا بِرَحْمَتِكَ يَا أَرْحَمَ الرَّاحِمِينَ', 'Allāhumma albisni''l-ʿāfiyata ḥattā tuhanniyanī bi''l-maʿīshah, wa''khtim lī bi''l-maghfirati ḥattā lā taḍurrani''dh-dhunūb, wa''kfinī kulla hawlin dūna''l-jannati ḥattā tuballighanīhā bi-raḥmatika yā arḥama''r-rāḥimīn', '“O Allah! Clothe me in well-being until You make life pleasant for me, seal my end with forgiveness so that sins do not harm me, and suffice me against every terror short of Paradise until You bring me to it, by Your mercy, O Most Merciful of those who show mercy.”', 1, '', '', 'Further Supplications', 243),
  ('bocp_244', 'book_of_prayer', '', 'اللَّهُمَّ أَعْطِنِي مِنَ الدُّنْيَا مَا تَقِينِي بِهِ فِتْنَتَهَا، وَتُغْنِينِي بِهِ عَنْ أَهْلِهَا، وَيَكُونُ بَلَاغًا لِي إِلَى مَا هُوَ خَيْرٌ مِنْهَا، فَإِنَّهُ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِكَ', 'Allāhumma aʿṭinī mina''d-dunyā mā taqīnī bihi fitnatahā, wa tughnīnī bihi ʿan ahlihā, wa yakūnu balāghan lī ilā mā huwa khayrun minhā, fa-innahu lā ḥawla wa lā quwwata illā bik', '“O Allah! Grant me of this world what protects me from its trial, makes me independent of its people, and serves as a passage for me to what is better than it; for there is no power and no strength except by You.”', 1, '', '', 'Further Supplications', 244),
  ('bocp_245', 'book_of_prayer', '', 'اللَّهُمَّ قَنِّعْنِي بِمَا رَزَقْتَنِي، وَبَارِكْ لِي فِيهِ، وَاخْلُفْ عَلَيَّ كُلَّ غَائِبَةٍ لِي بِخَيْرٍ', 'Allāhumma qanniʿnī bimā razaqtanī, wa bārik lī fīh, wa''khluf ʿalayya kulla ghāʾibatin lī bi-khayr', '“O Allah! Make me content with what You have provided me, bless it for me, and replace for me with good everything of mine that is absent.”', 1, '', '', 'Further Supplications', 245),
  ('bocp_246', 'book_of_prayer', '', 'سُبْحَانَ اللَّهِ وَبِحَمْدِهِ عَدَدَ خَلْقِهِ وَرِضَا نَفْسِهِ وَزِنَةَ عَرْشِهِ وَمِدَادَ كَلِمَاتِهِ', 'Subḥāna''llāhi wa bi-ḥamdihi ʿadada khalqihi wa riḍā nafsihi wa zinata ʿarshihi wa midāda kalimātih', '“Glory be to Allah, and I praise Him by the number of His creation and by what pleases Him, and by the weight of His Throne, and the ink of His Words.”', 1, '', '', 'Closing Remembrance & Salawat', 246),
  ('bocp_247', 'book_of_prayer', '', 'سُبْحَانَ اللَّهِ عَدَدَ مَا خَلَقَ فِي السَّمَاءِ وَعَدَدَ مَا خَلَقَ فِي الْأَرْضِ، وَسُبْحَانَ اللَّهِ عَدَدَ مَا بَيْنَ ذَلِكَ، وَسُبْحَانَ اللَّهِ عَدَدَ مَا هُوَ خَالِقٌ، وَاللَّهُ أَكْبَرُ مِثْلَ ذَلِكَ، وَالْحَمْدُ لِلَّهِ مِثْلَ ذَلِكَ، وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ مِثْلَ ذَلِكَ', 'Subḥāna''llāhi ʿadada mā khalaqa fi''s-samāʾi wa ʿadada mā khalaqa fi''l-arḍ, wa subḥāna''llāhi ʿadada mā bayna dhālik, wa subḥāna''llāhi ʿadada mā huwa khāliq, wa''llāhu akbaru mithla dhālik, wa''l-ḥamdu li''llāhi mithla dhālik, wa lā ḥawla wa lā quwwata illā bi''llāhi mithla dhālik', '“Glory be to Allah by the number of what He created in the heaven and by the number of what He created on the earth; and Glory be to Allah by the number of what is between them; and Glory be to Allah by the number of what He is creating; and Allah is the Most Great the like of that, and praise be to Allah the like of that, and there is no power and no strength except by Allah the like of that.”', 1, '', '', 'Closing Remembrance & Salawat', 247),
  ('bocp_248', 'book_of_prayer', '', 'سُبْحَانَ اللَّهِ عَدَدَ خَلْقِهِ، سُبْحَانَ اللَّهِ مِلْءَ مَا خَلَقَ، سُبْحَانَ اللَّهِ عَدَدَ مَا خَلَقَ، سُبْحَانَ اللَّهِ عَدَدَ مَا فِي السَّمَاءِ وَالْأَرْضِ، سُبْحَانَ اللَّهِ عَدَدَ مَا فِي الْأَرْضِ وَالسَّمَاءِ، سُبْحَانَ اللَّهِ عَدَدَ مَا أَحْصَى كِتَابُهُ، وَسُبْحَانَ اللَّهِ عَدَدَ كُلِّ شَيْءٍ، وَسُبْحَانَ اللَّهِ مِلْءَ كُلِّ شَيْءٍ وَالْحَمْدُ لِلَّهِ مِثْلَ ذَلِكَ', 'Subḥāna''llāhi ʿadada khalqih, subḥāna''llāhi milʾa mā khalaq, subḥāna''llāhi ʿadada mā khalaq, subḥāna''llāhi ʿadada mā fi''s-samāʾi wa''l-arḍ, subḥāna''llāhi ʿadada mā fi''l-arḍi wa''s-samāʾ, subḥāna''llāhi ʿadada mā aḥṣā kitābuh, wa subḥāna''llāhi ʿadada kulli shayʾ, wa subḥāna''llāhi milʾa kulli shayʾin wa''l-ḥamdu li''llāhi mithla dhālik', '“Glory be to Allah by the number of His creation, Glory be to Allah filling all that He created, Glory be to Allah by the number of what He created, Glory be to Allah by the number of what is in the heaven and the earth, Glory be to Allah by the number of what is in the earth and the heaven, Glory be to Allah by the number of what His Book has recorded, Glory be to Allah by the number of all things, Glory be to Allah filling all things, and praise be to Allah the like of that.”', 1, '', '', 'Closing Remembrance & Salawat', 248),
  ('bocp_249', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ وَنَعِيمَهَا وَاسْتَبْرَقَهَا، وَأَعُوذُ بِكَ مِنَ النَّارِ وَسَلَاسِلِهَا وَأَغْلَالِهَا', 'Allāhumma innī asʾaluka''l-jannata wa naʿīmahā wa''stabraqahā, wa aʿūdhu bika mina''n-nāri wa salāsilihā wa aghlālihā', '“O Allah! I ask You for Paradise and its bliss and its brocade, and I seek refuge with You from the Fire and its chains and its shackles.”', 1, '', '', 'Closing Remembrance & Salawat', 249),
  ('bocp_250', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّكَ تَسْمَعُ كَلَامِي، وَتَرَى مَكَانِي وَتَعْلَمُ سِرِّي وَعَلَانِيَتِي، وَلَا يَخْفَى عَلَيْكَ شَيْءٌ مِنْ أَمْرِي وَأَنَا الْبَائِسُ الْفَقِيرُ وَالْمُسْتَغِيثُ الْمُسْتَجِيرُ، وَالْوَجِلُ الْمُشْفِقُ الْمُقِرُّ الْمُعْتَرِفُ إِلَيْكَ بِذَنْبِهِ، أَسْأَلُكَ مَسْأَلَةَ الْمِسْكِينِ وَأَبْتَهِلُ إِلَيْكَ ابْتِهَالَ الْمُذْنِبِ الذَّلِيلِ، وَأَدْعُوكَ دُعَاءَ الْخَائِفِ الضَّرِيرِ، دُعَاءَ مَنْ خَضَعَتْ لَكَ رَقَبَتُهُ وَذَلَّ لَكَ جِسْمُهُ، وَرَغِمَ لَكَ أَنْفُهُ', 'Allāhumma innaka tasmaʿu kalāmī, wa tarā makānī wa taʿlamu sirrī wa ʿalāniyatī, wa lā yakhfā ʿalayka shayʾun min amrī wa ana''l-bāʾisu''l-faqīru wa''l-mustaghīthu''l-mustajīr, wa''l-wajilu''l-mushfiqu''l-muqirru''l-muʿtarifu ilayka bi-dhanbih, asʾaluka masʾalata''l-miskīni wa abtahilu ilayka''btihāla''l-mudhnibi''dh-dhalīl, wa adʿūka duʿāʾa''l-khāʾifi''ḍ-ḍarīr, duʿāʾa man khaḍaʿat laka raqabatuhu wa dhalla laka jismuh, wa raghima laka anfuh', '“O Allah! Verily You hear my words, see my place, and know my secret and my open state, and nothing of my affair is hidden from You; I am the wretched poor one, the one who cries for help and seeks refuge, the fearful and apprehensive, acknowledging and confessing his sin to You; I ask You with the asking of the destitute, I implore You with the imploring of the lowly sinner, and I call You with the call of the fearful afflicted one — the call of one whose neck is humbled to You, whose body is lowly before You, and whose nose is in the dust for You.”', 1, '', '', 'Closing Remembrance & Salawat', 250),
  ('bocp_251', 'book_of_prayer', '', 'اللَّهُمَّ إِنَّكَ قُلْتَ، وَقَوْلُكَ الْحَقُّ: ادْعُونِي أَسْتَجِبْ لَكُمْ', 'Allāhumma innaka qulta, wa qawluka''l-ḥaqq: udʿūnī astajib lakum', '“O Allah! Verily You said, and Your Word is True: ''Call upon Me, I will answer you.''”', 1, '', '', 'Closing Remembrance & Salawat', 251),
  ('bocp_252', 'book_of_prayer', '', 'اللَّهُمَّ هَذَا الدُّعَاءُ وَعَلَيْكَ الْإِجَابَةُ وَهَذَا الْجَهْدُ وَعَلَيْكَ التُّكْلَانُ، وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِكَ', 'Allāhumma hādha''d-duʿāʾu wa ʿalayka''l-ijābatu wa hādha''l-jahdu wa ʿalayka''t-tuklān, wa lā ḥawla wa lā quwwata illā bik', '“O Allah! This is the supplication and upon You is the response; and this is the effort and upon You is the reliance; and there is no power and no strength except by You.”', 1, '', '', 'Closing Remembrance & Salawat', 252),
  ('bocp_253', 'book_of_prayer', '', 'اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ، كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَعَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ، وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ، كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ وَعَلَى آلِ إِبْرَاهِيمَ، إِنَّكَ حَمِيدٌ مَجِيدٌ', 'Allāhumma ṣalli ʿalā Muḥammadin wa ʿalā āli Muḥammad, kamā ṣallayta ʿalā Ibrāhīma wa ʿalā āli Ibrāhīma innaka ḥamīdun majīd, wa bārik ʿalā Muḥammadin wa ʿalā āli Muḥammad, kamā bārakta ʿalā Ibrāhīma wa ʿalā āli Ibrāhīm, innaka ḥamīdun majīd', '“O Allah! Bless Muhammad and the members of his family as You have blessed Ibrahim (Abraham) and the members of the family of Ibrahim; verily You are Praiseworthy, Glorious. And grant favors to Muhammad and the members of his family as You have granted favors to Ibrahim and the members of the family of Ibrahim; verily You are Praiseworthy, Glorious.”', 1, '', '', 'Closing Remembrance & Salawat', 253),
  ('bocp_254', 'book_of_prayer', '', 'لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ، لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ، إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ، لَا شَرِيكَ لَكَ', 'Labbayk Allāhumma labbayk, labbayk lā sharīka laka labbayk, inna’l-ḥamda wa’n-niʿmata laka wa’l-mulk, lā sharīka lak', '“Here I am, O Allah, here I am. Here I am; You have no partner; here I am. Surely all praise, grace, and dominion belong to You; You have no partner.”', 1, '', '', 'Hajj & Umrah Supplications', 254),
  ('bocp_255', 'book_of_prayer', '', 'اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ', 'Allāhumma’ftaḥ lī abwāba raḥmatik', '“O Allah, open for me the gates of Your mercy.”', 1, '', '', 'Hajj & Umrah Supplications', 255),
  ('bocp_256', 'book_of_prayer', '', 'بِسْمِ اللَّهِ وَاللَّهُ أَكْبَرُ', 'Bismillāhi wa’llāhu akbar', '“In the name of Allah; Allah is the Greatest.”', 1, '', '', 'Hajj & Umrah Supplications', 256),
  ('bocp_257', 'book_of_prayer', '', 'رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ', 'Rabbanā ātinā fi’d-dunyā ḥasanatan wa fi’l-ākhirati ḥasanatan wa qinā ʿadhāba’n-nār', '“Our Lord! Grant us the good of this world and the Hereafter, and protect us from the torment of the Fire.”', 1, '', '', 'Hajj & Umrah Supplications', 257),
  ('bocp_258', 'book_of_prayer', '', 'وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى', 'Wa’ttakhidhū min maqāmi Ibrāhīma muṣallā', '“Take the standing-place of Abraham as a place of prayer.”', 1, '', '', 'Hajj & Umrah Supplications', 258),
  ('bocp_259', 'book_of_prayer', '', 'اللَّهُ أَكْبَرُ، اللَّهُ أَكْبَرُ، اللَّهُ أَكْبَرُ، لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ، لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ، أَنْجَزَ وَعْدَهُ، وَنَصَرَ عَبْدَهُ، وَهَزَمَ الْأَحْزَابَ وَحْدَهُ', 'Allāhu akbar (×3), lā ilāha illa’llāhu waḥdahu lā sharīka lah, lahu’l-mulku wa lahu’l-ḥamdu wa huwa ʿalā kulli shay’in qadīr, lā ilāha illa’llāhu waḥdah, anjaza waʿdah, wa naṣara ʿabdah, wa hazama’l-aḥzāba waḥdah', '“Allah is the Greatest (three times). There is no god but Allah alone, with no partner; His is the dominion and His is all praise, and He is over all things competent. There is no god but Allah alone; He fulfilled His promise, gave victory to His servant, and alone defeated the confederates.”', 1, '', '', 'Hajj & Umrah Supplications', 259),
  ('bocp_260', 'book_of_prayer', '', 'لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ، وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ', 'Lā ilāha illa’llāhu waḥdahu lā sharīka lah, lahu’l-mulku wa lahu’l-ḥamd, wa huwa ʿalā kulli shay’in qadīr', '“There is no god but Allah alone, with no partner; His is the dominion and His is all praise, and He is over all things competent.”', 1, '', '', 'Hajj & Umrah Supplications', 260),
  ('bocp_261', 'book_of_prayer', '', 'اللَّهُ أَكْبَرُ، لَا إِلَهَ إِلَّا اللَّهُ', 'Allāhu akbar, lā ilāha illa’llāh', '“Allah is the Greatest; there is no god but Allah.”', 1, '', '', 'Hajj & Umrah Supplications', 261),
  ('bocp_262', 'book_of_prayer', '', 'اللَّهُ أَكْبَرُ', 'Allāhu akbar', '“Allah is the Greatest.”', 1, '', '', 'Hajj & Umrah Supplications', 262),
  ('bocp_263', 'book_of_prayer', '', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ عِلْمًا نَافِعًا، وَرِزْقًا وَاسِعًا، وَشِفَاءً مِنْ كُلِّ دَاءٍ', 'Allāhumma innī as’aluka ʿilman nāfiʿan, wa rizqan wāsiʿan, wa shifā’an min kulli dā’', '“O Allah, I ask You for beneficial knowledge, abundant provision, and healing from every illness.”', 1, '', '', 'Hajj & Umrah Supplications', 263);

-- Verify: SELECT section, COUNT(*) FROM azkar_items WHERE category_id = 'book_of_prayer' GROUP BY section ORDER BY MIN(sort_order);